create table if not exists public.topics (
  id        text primary key,
  track     text not null,
  category  text not null,
  number    int  not null,
  title     text not null,
  summary   text,
  wiki      jsonb not null default '[]'::jsonb,
  questions jsonb not null default '[]'::jsonb
);

alter table public.topics enable row level security;

drop policy if exists topics_select_approved on public.topics;
create policy topics_select_approved on public.topics
  for select using ( public.is_approved() );

grant select on public.topics to authenticated;

insert into public.topics (id, track, category, number, title, summary, wiki, questions)
select id, track, category, number, title, summary, wiki, questions
from jsonb_to_recordset($awfjson$[{"id":"funkcje-czasu-wolnego","track":"wszyscy","category":"rekreacja","number":1,"title":"Funkcje czasu wolnego i ich potencjał wychowawczy","summary":"Siedem funkcji czasu wolnego oraz jak dobrze zorganizowany czas wolny wspiera rozwój osobisty, społeczny i moralny.","wiki":[{"body":"Czas wolny pełni szereg funkcji, które razem wspierają regenerację, rozwój i relacje człowieka. Dobrze zorganizowany czas wolny ma także silny potencjał wychowawczy."},{"heading":"Funkcje czasu wolnego","bullets":["Regeneracyjna — odpoczynek fizyczny i psychiczny po wysiłku, stresie i obowiązkach.","Rekreacyjna — rozrywka, relaks i miłe spędzanie czasu.","Rozwojowa — poszerzanie wiedzy, rozwijanie zainteresowań, nowe umiejętności (kursy, książki, warsztaty).","Kompensacyjna — wyrównuje braki z innych sfer życia (aktywność, kontakt społeczny, kreatywność).","Kreacyjna — twórcza realizacja przez sztukę, muzykę, pisanie, rękodzieło.","Katartyczna — oczyszcza emocje, rozładowuje stres i napięcie.","Społeczna — budowanie relacji, współpraca i integracja z grupą."]},{"heading":"Potencjał wychowawczy","body":"Polega na wykorzystaniu czasu wolnego do wspierania rozwoju osobistego, społecznego i moralnego dzieci i młodzieży — to nie tylko odpoczynek, ale i szansa na wychowanie.","bullets":["Rozwija zainteresowania i pasje — dziecko odkrywa, co lubi i w czym jest dobre.","Buduje relacje społeczne oraz więzi rodzinne i rówieśnicze.","Kształtuje wartości: empatię, współpracę, szacunek, zasady fair play.","Chroni przed zachowaniami ryzykownymi — zorganizowany czas wolny ogranicza nudę i negatywne wpływy."]}],"questions":[{"type":"abcd","q":"Która funkcja czasu wolnego pełni rolę oczyszczającą emocje i rozładowującą napięcie?","options":["Kompensacyjna","Regeneracyjna","Kreacyjna","Katartyczna"],"correct":3,"explain":"Funkcja katartyczna oczyszcza emocje oraz rozładowuje stres i napięcie."},{"type":"abcd","q":"Funkcja kompensacyjna czasu wolnego polega na:","options":["wyrównywaniu braków i niedostatków z innych sfer życia","twórczej realizacji przez sztukę i rękodzieło","odpoczynku po wysiłku fizycznym","budowaniu relacji w grupie"],"correct":0,"explain":"Funkcja kompensacyjna uzupełnia braki z innych stref życia (np. aktywność fizyczna, kontakt społeczny)."},{"type":"tf","q":"Dobrze zorganizowany czas wolny zmniejsza podatność na nudę i chroni przed zachowaniami ryzykownymi.","correct":true,"explain":"To jeden z elementów potencjału wychowawczego czasu wolnego."},{"type":"flash","front":"Wymień 7 funkcji czasu wolnego.","back":"Regeneracyjna, rekreacyjna, rozwojowa, kompensacyjna, kreacyjna, katartyczna, społeczna."}]},{"id":"koncepcje-motywacyjne","track":"wszyscy","category":"rekreacja","number":2,"title":"Koncepcje motywacyjne udziału w aktywności rekreacyjno-turystycznej","summary":"Motywacja jako wewnętrzny stan pobudzający do działania, piramida Maslowa, teoria autodeterminacji oraz motywacja wewnętrzna i zewnętrzna.","wiki":[{"body":"Motywacja to wewnętrzny stan pobudzający jednostkę do działania; kieruje zachowaniem oraz wpływa na to, jak długo i jak intensywnie coś wykonujemy. Powstaje z różnych potrzeb i może mieć charakter rodzinny, poznawczy, historyczny, zdrowotny, społeczny, estetyczny lub duchowy."},{"heading":"Piramida potrzeb Maslowa","bullets":["Fizjologiczne — odpoczynek, sen, jedzenie (wakacje zaspokajają te potrzeby).","Bezpieczeństwa — podróże w spokojne miejsca, oderwanie od stresu.","Przynależności — wyjazdy z rodziną i przyjaciółmi, budowanie relacji.","Uznania — zdobywanie i dzielenie się nowymi doświadczeniami.","Samorealizacji — poznawanie świata, rozwój osobisty, duchowy, edukacyjny."]},{"heading":"Teoria autodeterminacji (Ryan i Deci)","body":"Wskazuje 3 kluczowe potrzeby psychologiczne: autonomię (decydowanie o sobie), kompetencję (poczucie sprawności) oraz relacje z innymi. Rekreacja pomaga je zaspokoić, dając poczucie spełnienia."},{"heading":"Motywacja wewnętrzna i zewnętrzna","bullets":["Wewnętrzna — wynika z osobistych potrzeb i przyjemności (bieganie dla satysfakcji, podróże dla poznawania świata).","Zewnętrzna — związana z nagrodą lub uniknięciem kary (udział w zawodach dla medalu)."]}],"questions":[{"type":"abcd","q":"Motywacja o charakterze estetycznym w aktywności rekreacyjno-turystycznej to przede wszystkim:","options":["chęć spędzania czasu z bliskimi","potrzeba kontaktu z przyrodą i pięknym krajobrazem","poprawa kondycji fizycznej i odreagowanie stresu","zainteresowanie historią danego miejsca"],"correct":1,"explain":"Motyw estetyczny to potrzeba kontaktu z przyrodą i pięknym krajobrazem; pozostałe odpowiadają motywom rodzinnemu, zdrowotnemu i historycznemu."},{"type":"abcd","q":"Bieganie dla własnej satysfakcji to przykład motywacji:","options":["zewnętrznej","wewnętrznej","kontrolnej","formalnej"],"correct":1,"explain":"Motywacja wewnętrzna wynika z osobistych potrzeb i przyjemności z działania."},{"type":"tf","q":"W piramidzie Maslowa potrzeby fizjologiczne znajdują się na najwyższym poziomie.","correct":false,"explain":"Na szczycie piramidy jest samorealizacja, a potrzeby fizjologiczne stanowią jej podstawę (najniższy poziom)."},{"type":"flash","front":"Czym różni się motywacja wewnętrzna od zewnętrznej?","back":"Wewnętrzna wynika z osobistych potrzeb i przyjemności; zewnętrzna z oczekiwania nagrody lub uniknięcia kary."}]},{"id":"witaminy-antyoksydacyjne","track":"wszyscy","category":"zywienie","number":7,"title":"Witaminy antyoksydacyjne i ich funkcje w organizmie","summary":"Witaminy A, C, E oraz koenzym Q10 chronią komórki przed wolnymi rodnikami; ich źródła i funkcje.","wiki":[{"body":"Witaminy antyoksydacyjne pomagają chronić komórki przed uszkodzeniem przez wolne rodniki — cząsteczki, które mogą sprzyjać chorobom (nowotwory, choroby serca i mózgu). Organizm broni się sam, a witaminy dodatkowo go wspierają."},{"heading":"Witamina A (retinol, beta-karoten)","body":"Źródła: marchew, dynia, bataty, szpinak, jarmuż.","bullets":["Neutralizuje wolne rodniki, chroni błony komórkowe.","Wspiera zdrowie skóry i błon śluzowych.","Niezbędna do prawidłowego widzenia i odporności."]},{"heading":"Witamina C (kwas askorbinowy)","body":"Źródła: cytrusy, papryka, pietruszka, truskawki, kiwi.","bullets":["Silny antyoksydant działający w środowisku wodnym.","Wspomaga syntezę kolagenu i gojenie ran.","Zwiększa przyswajanie żelaza niehemowego, wzmacnia odporność."]},{"heading":"Witamina E (tokoferole)","body":"Źródła: oleje roślinne, orzechy, nasiona, zielone warzywa.","bullets":["Chroni błony komórkowe przed uszkodzeniami oksydacyjnymi.","Wspomaga układ krwionośny, zmniejsza ryzyko miażdżycy.","Poprawia stan skóry i wspiera układ nerwowy."]},{"heading":"Koenzym Q10","body":"Nie jest witaminą, ale ma silne działanie antyoksydacyjne. Źródła: ryby, mięso, orzechy, oleje roślinne. Bierze udział w produkcji energii w mitochondriach."}],"questions":[{"type":"abcd","q":"Która witamina antyoksydacyjna działa głównie w środowisku wodnym organizmu?","options":["Witamina A","Koenzym Q10","Witamina E","Witamina C"],"correct":3,"explain":"Witamina C jest silnym antyoksydantem neutralizującym wolne rodniki w środowisku wodnym."},{"type":"abcd","q":"Dobrym źródłem witaminy A (beta-karotenu) jest:","options":["cytryna","marchew","olej słonecznikowy","ryba"],"correct":1,"explain":"Witamina A / beta-karoten występuje m.in. w marchwi, dyni, batatach i jarmużu."},{"type":"tf","q":"Koenzym Q10 jest witaminą antyoksydacyjną.","correct":false,"explain":"Koenzym Q10 nie jest witaminą, choć ma silne działanie antyoksydacyjne i uczestniczy w produkcji energii w mitochondriach."},{"type":"flash","front":"Czym są wolne rodniki i dlaczego są groźne?","back":"To cząsteczki uszkadzające komórki; mogą sprzyjać chorobom (nowotwory, choroby serca i mózgu). Witaminy antyoksydacyjne pomagają je neutralizować."}]},{"id":"blonnik-pokarmowy","track":"wszyscy","category":"zywienie","number":8,"title":"Funkcje błonnika pokarmowego w organizmie","summary":"Błonnik rozpuszczalny i nierozpuszczalny — funkcje, źródła, zalecane spożycie i skutki nadmiaru.","wiki":[{"body":"Błonnik pokarmowy to część roślin, która nie ulega strawieniu i wchłonięciu w przewodzie pokarmowym. Choć nie dostarcza energii, usprawnia pracę jelit, wspiera odchudzanie i pomaga regulować poziom cukru we krwi."},{"heading":"Błonnik rozpuszczalny","body":"W kontakcie z wodą pęcznieje i tworzy żel. Spowalnia wchłanianie węglowodanów (stabilizuje glukozę) i obniża poziom cholesterolu.","bullets":["Źródła: płatki owsiane, rośliny strączkowe, siemię lniane, jabłka, cytrusy."]},{"heading":"Błonnik nierozpuszczalny","body":"Działa jak „szczotka” w jelitach — zwiększa objętość stolca i przyspiesza pasaż jelitowy, zapobiegając zaparciom.","bullets":["Źródła: produkty pełnoziarniste, otręby, orzechy, skórki warzyw i owoców."]},{"heading":"Zalecenia i nadmiar","bullets":["Dorośli: 25–40 g błonnika dziennie.","Nadmiar może powodować biegunkę i zaburzać wchłanianie składników mineralnych (żelaza, wapnia, cynku)."]}],"questions":[{"type":"abcd","q":"Który rodzaj błonnika w kontakcie z wodą tworzy żel i obniża poziom cholesterolu?","options":["Nierozpuszczalny","Żaden","Oba tak samo","Rozpuszczalny"],"correct":3,"explain":"Błonnik rozpuszczalny pęcznieje, tworzy żel, stabilizuje glukozę i obniża cholesterol."},{"type":"abcd","q":"Jakie jest zalecane dzienne spożycie błonnika u dorosłych?","options":["5–10 g","25–40 g","10–20 g","50–70 g"],"correct":1,"explain":"Zalecenie dla dorosłych to 25–40 g błonnika dziennie."},{"type":"tf","q":"Błonnik rozpuszczalny przyspiesza pasaż jelitowy i zapobiega zaparciom.","correct":false,"explain":"Pasaż przyspiesza błonnik nierozpuszczalny (działa jak „szczotka”); rozpuszczalny pęcznieje, spowalnia trawienie i obniża cholesterol."},{"type":"flash","front":"Jakie są skutki nadmiaru błonnika?","back":"Biegunka oraz zaburzenia wchłaniania składników mineralnych (żelaza, wapnia, cynku)."}]},{"id":"przystosowania-do-wysilku","track":"wszyscy","category":"fizjologia","number":14,"title":"Fizjologiczne przystosowania organizmu do wysiłku fizycznego","summary":"Adaptacje do treningu wytrzymałościowego, siłowego, gibkościowego, niskiej intensywności oraz interwałowego.","wiki":[{"body":"Adaptacje organizmu zależą od rodzaju, intensywności, czasu trwania i częstotliwości treningu. Regularny wysiłek prowadzi do zmian czynnościowych zwiększających wydolność i sprawność."},{"heading":"Trening wytrzymałościowy (bieganie, kolarstwo)","bullets":["Wzrost pojemności minutowej serca i objętości wyrzutowej.","Więcej i wydolniejsze mitochondria, wzrost VO₂ max.","Lepsze ukrwienie tkanek, obniżenie tętna spoczynkowego."]},{"heading":"Trening siłowy (ciężary, masa ciała)","bullets":["Hipertrofia mięśni — wzrost przekroju poprzecznego włókien.","Wzrost siły i gęstości mięśniowej oraz gęstości mineralnej kości.","Lepsza rekrutacja jednostek motorycznych i kontrola mięśni."]},{"heading":"Trening gibkości i równowagi (joga, rozciąganie)","bullets":["Większy zakres ruchu w stawach, mniejsze ryzyko kontuzji.","Relaks mięśni, lepsza koordynacja i równowaga."]},{"heading":"Niska intensywność oraz trening interwałowy","bullets":["Niska intensywność: wzrost wydolności tlenowej, obniżenie kortyzolu, kontrola masy ciała.","Interwały / sporty zespołowe: szybka adaptacja układu krążenia do zmiennego obciążenia, poprawa systemu tlenowego i beztlenowego."]}],"questions":[{"type":"abcd","q":"Hipertrofia mięśni jest charakterystyczną adaptacją dla treningu:","options":["wytrzymałościowego","gibkościowego","siłowego","o niskiej intensywności"],"correct":2,"explain":"Hipertrofia (wzrost przekroju włókien) to typowa adaptacja do treningu siłowego."},{"type":"abcd","q":"Wzrost liczby i wydolności mitochondriów oraz VO₂ max to efekt treningu:","options":["siłowego","oporowego","gibkościowego","wytrzymałościowego"],"correct":3,"explain":"Adaptacje tlenowe (mitochondria, VO₂ max) są typowe dla treningu wytrzymałościowego."},{"type":"tf","q":"Regularny trening wytrzymałościowy obniża tętno spoczynkowe.","correct":true,"explain":"Serce pracuje efektywniej, pompując więcej krwi przy każdym skurczu, więc tętno spoczynkowe spada."},{"type":"flash","front":"Wymień trzy systemy energetyczne pracującego mięśnia.","back":"System fosfagenowy (ATP), glikoliza beztlenowa (mleczan) i metabolizm tlenowy (mitochondria)."}]},{"id":"style-kierowania","track":"wszyscy","category":"zarzadzanie","number":16,"title":"Style kierowania","summary":"Trzy główne style kierowania: autokratyczny, demokratyczny i liberalny — ich zalety i wady.","wiki":[{"body":"Styl kierowania to sposób, w jaki kierownik zarządza zespołem: jak podejmuje decyzje, komunikuje się i wpływa na pracę. Wyróżnia się trzy główne style."},{"heading":"Styl autokratyczny","body":"Kierownik sam podejmuje wszystkie decyzje i ma pełną kontrolę. Sprawdza się przy dużej wiedzy kierownika i konieczności szybkich decyzji, ale z czasem obniża zaangażowanie i motywację pracowników."},{"heading":"Styl demokratyczny","body":"Kierownik konsultuje decyzje z pracownikami, którzy mogą wyrażać opinie. Działa dobrze przy kompetentnym i zaangażowanym zespole, ale podejmowanie decyzji bywa wolniejsze."},{"heading":"Styl liberalny","body":"Kierownik daje dużą swobodę — pracownicy sami decydują i wykonują zadania. Dobre przy kompetentnym, zmotywowanym zespole, ale może prowadzić do chaosu i braku kontroli. W praktyce kierownicy łączą style zależnie od sytuacji."}],"questions":[{"type":"abcd","q":"Który styl kierowania zakłada konsultowanie decyzji z pracownikami?","options":["Autokratyczny","Liberalny","Demokratyczny","Dyrektywny"],"correct":2,"explain":"W stylu demokratycznym kierownik konsultuje się z zespołem przed podjęciem decyzji."},{"type":"abcd","q":"Główną wadą stylu liberalnego może być:","options":["spadek motywacji wynikający z nadmiernej kontroli","chaos i brak kontroli","zbyt wolne podejmowanie decyzji przez konsultacje","traktowanie pracowników jak narzędzia"],"correct":1,"explain":"Duża swoboda w stylu liberalnym może z czasem prowadzić do chaosu i braku kontroli."},{"type":"tf","q":"Styl autokratyczny może być skuteczny, gdy decyzje muszą być podejmowane szybko.","correct":true,"explain":"Sprawdza się, gdy kierownik ma dużą wiedzę i potrzebne są szybkie decyzje."},{"type":"flash","front":"Wymień trzy główne style kierowania.","back":"Autokratyczny, demokratyczny i liberalny."}]},{"id":"produkt-turystyczny","track":"wszyscy","category":"turystyka","number":18,"title":"Produkt turystyczny — koncepcje, struktura i przykłady","summary":"Definicje produktu turystycznego z perspektywy firmy i turysty, elementy materialne i niematerialne oraz rodzaje produktów.","wiki":[{"body":"Produkt turystyczny to zestaw dóbr i usług zaspokajających potrzeby turysty związane z podróżą i pobytem. Z perspektywy przedsiębiorstwa to zestaw usług i dóbr do sprzedaży; z perspektywy turysty — zestaw przeżyć, doświadczeń i korzyści."},{"heading":"Elementy materialne","bullets":["Infrastruktura turystyczna.","Baza noclegowa (hotele, pensjonaty).","Gastronomia (restauracje, bary).","Transport (loty, pociągi, autobusy), sprzęt, pamiątki."]},{"heading":"Elementy niematerialne","bullets":["Usługi przewodnickie i informacyjne.","Przeżycia emocjonalne i duchowe.","Wizerunek miejsca, atmosfera, klimat i pogoda.","Nowe kontakty i relacje społeczne."]},{"heading":"Rodzaje produktów","bullets":["Produkty proste — pojedyncze dobra/usługi (bilet, nocleg, przewodnik).","Produkty złożone (pakiety) — kombinacje usług i atrakcji (imprezy turystyczne)."]}],"questions":[{"type":"abcd","q":"Z perspektywy turysty (konsumenta) produkt turystyczny to przede wszystkim:","options":["zestaw przeżyć, doświadczeń i korzyści","zestaw usług i dóbr oferowanych do sprzedaży","wyłącznie baza noclegowa","tylko transport i gastronomia"],"correct":0,"explain":"Dla turysty produkt to zestaw przeżyć, doświadczeń i korzyści; perspektywa firmy to zestaw usług/dóbr do sprzedaży."},{"type":"abcd","q":"Który z elementów jest niematerialnym składnikiem produktu turystycznego?","options":["Baza noclegowa","Transport","Atmosfera i wizerunek miejsca","Sprzęt turystyczny"],"correct":2,"explain":"Elementy niematerialne to m.in. atmosfera, wizerunek miejsca, przeżycia i relacje społeczne."},{"type":"tf","q":"Impreza turystyczna (pakiet) jest przykładem złożonego produktu turystycznego.","correct":true,"explain":"Produkty złożone to kombinacje usług i atrakcji, np. imprezy turystyczne."},{"type":"flash","front":"Podaj dwie definicje produktu turystycznego (firma vs turysta).","back":"Firma: zestaw usług i dóbr oferowanych do sprzedaży. Turysta: zestaw przeżyć, doświadczeń i korzyści."}]},{"id":"formy-ochrony-przyrody","track":"wszyscy","category":"przyroda","number":54,"title":"Formy ochrony przyrody w Polsce","summary":"Parki narodowe, parki krajobrazowe, rezerwaty, Natura 2000, pomniki przyrody i pozostałe formy ochrony.","wiki":[{"heading":"Główne formy ochrony","bullets":["Parki narodowe — najwyższa forma ochrony; duże obszary, surowe zakazy (np. Białowieski, Tatrzański).","Parki krajobrazowe — chronią krajobraz i przyrodę z mniejszymi ograniczeniami; dopuszczalna działalność gospodarcza nieszkodliwa dla środowiska.","Rezerwaty przyrody — mniejsze obszary; ścisłe (zakaz ingerencji) lub częściowe (ograniczone działania ochronne).","Natura 2000 — sieć europejskich terenów chroniących zagrożone gatunki i siedliska.","Pomnik przyrody — pojedyncze obiekty (drzewa, głazy, jaskinie), np. Dąb Bartek."]},{"heading":"Pozostałe formy","bullets":["Użytki ekologiczne — niewielkie cenne tereny (oczka wodne, bagna, torfowiska).","Zespoły przyrodniczo-krajobrazowe — obszary cenne krajobrazowo i kulturowo.","Stanowiska dokumentacyjne — miejsca ważne geologicznie.","Ochrona gatunkowa — roślin, zwierząt i grzybów.","UNESCO — lista światowego dziedzictwa (np. Wieliczka, stare miasto w Krakowie)."]}],"questions":[{"type":"abcd","q":"Która forma ochrony przyrody w Polsce jest uznawana za najwyższą?","options":["Park krajobrazowy","Pomnik przyrody","Użytek ekologiczny","Park narodowy"],"correct":3,"explain":"Park narodowy to najwyższa forma ochrony — duże obszary i surowe zakazy."},{"type":"abcd","q":"Dąb Bartek to przykład:","options":["parku narodowego","rezerwatu ścisłego","pomnika przyrody","użytku ekologicznego"],"correct":2,"explain":"Pojedyncze obiekty przyrodnicze (drzewa, głazy) to pomniki przyrody — np. Dąb Bartek."},{"type":"tf","q":"Natura 2000 to sieć europejskich terenów chroniących zagrożone gatunki i siedliska.","correct":true,"explain":"Natura 2000 to europejska sieć obszarów chroniących zagrożone gatunki i siedliska."},{"type":"flash","front":"Czym różni się rezerwat ścisły od częściowego?","back":"Ścisły — całkowity zakaz ingerencji człowieka; częściowy — możliwe ograniczone działania ochronne."}]},{"id":"check-in-check-out","track":"hotelarstwo","category":"hotelarstwo","number":37,"title":"Procedura check-in i check-out gościa hotelowego","summary":"Kroki zameldowania (check-in) i wymeldowania (check-out) gościa w hotelu.","wiki":[{"heading":"Check-in (zameldowanie)","body":"Proces rejestracji gościa w hotelu.","bullets":["Powitanie gościa — uprzejmie i profesjonalnie.","Weryfikacja rezerwacji w systemie (imię, nazwisko, data).","Prośba o dokument tożsamości (paszport / dowód).","Wypełnienie karty rejestracyjnej.","Autoryzacja płatności — depozyt lub preautoryzacja karty.","Przekazanie klucza/karty, informacja o numerze pokoju i godzinach wymeldowania.","Dodatkowe informacje (śniadanie, wifi, siłownia) i ewentualna pomoc bagażowa."]},{"heading":"Check-out (wymeldowanie)","body":"Proces zakończenia pobytu i rozliczenia gościa.","bullets":["Sprawdzenie tożsamości gościa (nazwisko / numer pokoju).","Weryfikacja opłat — czy usługi dodatkowe (minibar, restauracja) doliczono.","Rozliczenie płatności (gotówka, karta, inna metoda).","Wystawienie faktury/paragonu na życzenie gościa.","Zwrot depozytu i klucza/karty do pokoju.","Zapytanie o opinię oraz uprzejme pożegnanie i zaproszenie ponownie."]}],"questions":[{"type":"abcd","q":"Który krok należy do procedury check-in?","options":["Autoryzacja płatności / preautoryzacja karty","Zwrot depozytu","Wystawienie faktury końcowej","Zwrot klucza do pokoju"],"correct":0,"explain":"Autoryzacja płatności (depozyt lub preautoryzacja karty) to element zameldowania (check-in)."},{"type":"tf","q":"Weryfikacja, czy usługi z minibaru zostały doliczone do rachunku, należy do check-in.","correct":false,"explain":"To krok wymeldowania (check-out), a nie zameldowania — przy check-out rozlicza się opłaty za usługi dodatkowe."},{"type":"flash","front":"Wymień pierwsze trzy kroki procedury check-in.","back":"Powitanie gościa, weryfikacja rezerwacji, prośba o dokument tożsamości."}]},{"id":"obiekty-hotelarskie","track":"hotelarstwo","category":"hotelarstwo","number":48,"title":"Rodzaje obiektów hotelarskich i kategoryzacja w Polsce","summary":"Obiekty kategoryzowane i nieskategoryzowane oraz system gwiazdek (1–5) w Polsce.","wiki":[{"heading":"Obiekty kategoryzowane","bullets":["Hotel — min. 10 pokoi, szeroki zakres usług (nocleg, wyżywienie, sprzątanie).","Motel — przy trasach, parking i udogodnienia dla zmotoryzowanych, min. 10 pokoi.","Pensjonat — nocleg i pełne wyżywienie, mniejszy zakres usług, min. 7 pokoi.","Dom wycieczkowy, schronisko młodzieżowe, schronisko górskie, pola namiotowe/kempingi."]},{"heading":"Obiekty nieskategoryzowane","body":"Nie muszą mieć gwiazdek, ale muszą spełniać wymagania sanitarne i techniczne.","bullets":["Pola biwakowe, kwatery prywatne.","Ośrodki wczasowe/wypoczynkowe/szkoleniowe, agroturystyka."]},{"heading":"System gwiazdek (1–5)","bullets":["Hotele, motele, pensjonaty: gwiazdki 1–5; campingi 1–4.","1* minimalne wyposażenie; 3* własna łazienka, TV, gastronomia; 5* luksus, recepcja 24h.","Kategorię przyznaje marszałek województwa po kontroli (ustawa z 19 sierpnia 2004 r.)."]}],"questions":[{"type":"abcd","q":"Kto przyznaje kategorię (gwiazdki) obiektowi hotelarskiemu w Polsce?","options":["Minister sportu","Burmistrz gminy","Marszałek województwa","Polska Izba Hotelarstwa"],"correct":2,"explain":"Kategorię nadaje marszałek województwa na wniosek właściciela po kontroli zgodności z wymaganiami."},{"type":"abcd","q":"Ile minimum pokoi musi mieć hotel?","options":["5","10","7","15"],"correct":1,"explain":"Hotel to obiekt z minimum 10 pokojami; pensjonat — min. 7."},{"type":"tf","q":"Agroturystyka jest obiektem kategoryzowanym gwiazdkowo.","correct":false,"explain":"Agroturystyka należy do obiektów nieskategoryzowanych (bez gwiazdek, ale ze spełnieniem wymagań sanitarnych i technicznych)."},{"type":"flash","front":"Czym różni się pensjonat od hotelu?","back":"Pensjonat oferuje nocleg i pełne wyżywienie, ma mniejszy zakres usług i min. 7 pokoi; hotel min. 10 pokoi i szerszy zakres usług."}]},{"id":"obsluga-klienta-biuro-podrozy","track":"hotelarstwo","category":"hotelarstwo","number":39,"title":"Obsługa klienta w biurze podróży i rozmowa sprzedażowa","summary":"Etapy obsługi klienta: powitanie, badanie potrzeb, prezentacja oferty, obsługa obiekcji, finalizacja i pożegnanie.","wiki":[{"heading":"Etapy rozmowy sprzedażowej","bullets":["Powitanie — uśmiech, profesjonalny wygląd, aktywne słuchanie.","Badanie potrzeb — pytania otwarte o miejsce, termin, budżet, liczbę osób, standard.","Prezentacja oferty — kilka opcji, kluczowe informacje (cena, program, ubezpieczenia), korzyści.","Obsługa obiekcji — słuchanie wątpliwości, jasne odpowiedzi, alternatywy.","Finalizacja — szczegóły rezerwacji i płatności, umowa, potwierdzenie.","Pożegnanie i opieka posprzedażowa — podziękowanie, kontakt, opinia po powrocie."]}],"questions":[{"type":"abcd","q":"Na którym etapie obsługi klienta zadajemy pytania otwarte o budżet i preferencje?","options":["Badanie potrzeb","Finalizacja sprzedaży","Obsługa obiekcji","Pożegnanie"],"correct":0,"explain":"Pytania otwarte o miejsce, termin, budżet i standard zadaje się na etapie badania potrzeb."},{"type":"tf","q":"Opieka posprzedażowa obejmuje zapytanie klienta o opinię po powrocie z wyjazdu.","correct":true,"explain":"Pożegnanie i opieka posprzedażowa obejmują kontakt oraz zapytanie o opinię i sugestie po powrocie."},{"type":"flash","front":"Wymień sześć etapów obsługi klienta w biurze podróży.","back":"Powitanie, badanie potrzeb, prezentacja oferty, obsługa obiekcji, finalizacja sprzedaży, pożegnanie i opieka posprzedażowa."}]},{"id":"cechy-projektu-outdoorowego","track":"przygodowa","category":"outdoor","number":1,"title":"Cechy projektu outdoorowego","summary":"Czynniki kształtujące outdoor, jego aspekt emocjonalny i kulturowy oraz główne aspekty projektów outdoorowych.","wiki":[{"body":"Projekty outdoorowe nie muszą skupiać się na silnych emocjach ani ryzyku uszczerbku na zdrowiu. Outdoor to szerszy obszar niż turystyka — wyróżnia się outdoor recreation, education i activities. Często łączy się z turystyką miejską (np. spływ tratwami, jazda konna, narciarstwo, trekking, birdwatching)."},{"heading":"Czynniki kształtujące outdoor","bullets":["Otwarta przestrzeń — miejska lub wiejska, przystosowana i bezpieczna.","Integracja z otoczeniem — przestrzeń zagospodarowana, interakcja ze środowiskiem.","Integracja i interakcja z uczestnikami — wycieczki, warsztaty, gry, wspólne oglądanie.","Warunki atmosferyczne — pogoda jako przeszkoda lub zaleta.","Element edukacji — zamierzony lub jako efekt działania."]},{"heading":"Główne aspekty projektów outdoorowych","bullets":["Promocja dziedzictwa kulturowego i naturalnego.","Podniesienie znaczenia lokalnej ludności i jej tożsamości.","Budowanie kompetencji międzykulturowych.","Budowanie obustronnego szacunku do miejsca.","Tworzenie sztuki w przestrzeni i innych wytworów."]}],"questions":[{"type":"abcd","q":"Który czynnik NIE jest typowym wyróżnikiem projektu outdoorowego?","options":["Otwarta przestrzeń przystosowana i bezpieczna","Integracja z otoczeniem","Wysokie ryzyko uszczerbku na zdrowiu jako cel","Interakcja z uczestnikami"],"correct":2,"explain":"Outdoor nie skupia się na dużym ryzyku — kładzie nacisk na wątki kulturowe i interakcję z otoczeniem."},{"type":"tf","q":"Outdoor zawęża się wyłącznie do turystyki.","correct":false,"explain":"Outdoor to szerszy obszar; wyróżnia się outdoor recreation, education i activities."},{"type":"flash","front":"Wymień trzy rodzaje outdooru.","back":"Outdoor recreation, outdoor education i outdoor activities."}]},{"id":"edukacja-przygodowa","track":"przygodowa","category":"outdoor","number":3,"title":"Edukacja przygodowa — specyfika i charakterystyka","summary":"Outdoor education, jej trzy komponenty oraz model adventure education według Priesta i Gassa (cel, proces, wynik).","wiki":[{"body":"Edukacja przygodowa opiera się na uczeniu przez doświadczenie i relacji człowieka z naturą. Pojęcie outdoor education jest szerokie — obejmuje ekstremalne wyprawy, lekcje w terenie i percepcyjne obcowanie z przyrodą (pol. edukacja plenerowa)."},{"heading":"Trzy komponenty outdoor education","bullets":["Ekologia.","Rozwój umiejętności fizycznych.","Relacje interpersonalne."]},{"heading":"Adventure education wg Priesta i Gassa","bullets":["Cel — uświadomienie uczestnikowi możliwości zmiany na lepsze (samoocena, relacje społeczne).","Proces — aktywności grupowe/indywidualne wymagające decyzyjności, rozwiązywania problemów, komunikacji, współpracy, zaufania i ryzyka (emocjonalnego, społecznego, fizycznego).","Wynik — samodoskonalenie; zmierzenie się z ograniczeniami i rozwój potencjału, poprawa relacji z innymi i sobą."]},{"body":"Adventure education i environmental education zawierają się w szerszym ujęciu outdoor education. Na zachodzie rozwinęły się dwa nurty: pedagogika przygody (kraje anglosaskie) oraz pedagogika przeżyć (m.in. Niemcy, Czechy)."}],"questions":[{"type":"abcd","q":"Które trzy komponenty łączą działania outdoor education?","options":["Ekonomia, marketing, logistyka","Historia, kultura, sztuka","Ryzyko, rywalizacja, nagroda","Ekologia, rozwój umiejętności fizycznych, relacje interpersonalne"],"correct":3,"explain":"Outdoor education łączy ekologię, rozwój umiejętności fizycznych oraz relacje interpersonalne."},{"type":"abcd","q":"Według Priesta i Gassa wynikiem adventure education jest:","options":["samodoskonalenie","zysk finansowy","zdobycie certyfikatu","wygrana w rywalizacji"],"correct":0,"explain":"Wynik to samodoskonalenie — rozwój potencjału i poprawa relacji z innymi i sobą."},{"type":"tf","q":"Pedagogika przeżyć rozwinęła się głównie w krajach anglosaskich.","correct":false,"explain":"W krajach anglosaskich rozwinęła się pedagogika przygody; pedagogika przeżyć — m.in. w Niemczech i Czechach."},{"type":"flash","front":"Opisz model adventure education wg Priesta i Gassa.","back":"Cel (zmiana na lepsze), proces (aktywności wymagające decyzyjności, współpracy i ryzyka) oraz wynik (samodoskonalenie)."}]},{"id":"obowiazki-pracownika-pracodawcy","track":"wszyscy","category":"zarzadzanie","number":3,"title":"Omów podstawowe obowiązki pracownika i pracodawcy","summary":"Wzajemne obowiązki stron stosunku pracy wynikające z umowy i prawa pracy.","wiki":[{"heading":"Obowiązki pracownika","bullets":["Sumienne wykonywanie pracy - rzetelnie, zgodnie z zaleceniami przełożonych, instrukcją i harmonogramem","Przestrzeganie przepisów BHP oraz regulaminu pracy, utrzymywanie porządku i higieny dla bezpieczeństwa swojego i innych","Dbanie o mienie pracodawcy - szanowanie sprzętu, narzędzi i materiałów, używanie ich zgodnie z przeznaczeniem","Zachowanie tajemnicy - danych firmy, klientów i informacji chronionych","Zachowanie kultury osobistej - unikanie konfliktów, poszanowanie innych, współpraca i komunikacja"]},{"heading":"Obowiązki pracodawcy","bullets":["Zapewnienie bezpiecznych i higienicznych warunków pracy (sprawny sprzęt, szkolenia BHP)","Terminowe i uczciwe wynagrodzenie","Szacunek dla godności pracownika - zakaz dyskryminacji i mobbingu","Dbanie o rozwój zawodowy pracownika","Przestrzeganie przepisów prawa pracy (czas pracy, urlopy)"]},{"body":"Podstawą wzajemnych obowiązków są umowa o pracę oraz przepisy prawa pracy, które określają normy i regulacje związane z zatrudnieniem."}],"questions":[{"type":"abcd","q":"Który z poniższych jest obowiązkiem pracodawcy, a nie pracownika?","options":["Dbanie o mienie pracodawcy","Zachowanie tajemnicy firmy","Zapewnienie bezpiecznych i higienicznych warunków pracy","Przestrzeganie regulaminu pracy"],"correct":2,"explain":"Zapewnienie bezpiecznych i higienicznych warunków pracy spoczywa na pracodawcy; pozostałe to obowiązki pracownika."},{"type":"tf","q":"Zakaz dyskryminacji i mobbingu należy do obowiązków pracownika.","correct":false,"explain":"To obowiązek pracodawcy — musi on szanować godność pracownika oraz przeciwdziałać dyskryminacji i mobbingowi."},{"type":"flash","front":"Wymień podstawowe obowiązki pracownika.","back":"Sumienne wykonywanie pracy, przestrzeganie BHP i regulaminu, dbanie o mienie pracodawcy, zachowanie tajemnicy oraz kultury osobistej."}]},{"id":"teorie-potrzeb-rekreacja","track":"wszyscy","category":"rekreacja","number":4,"title":"Omów teorie wyjaśniające znaczenie potrzeb w życiu człowieka biorącego udział w aktywnościach rekreacyjnych","summary":"Rekreacja zaspokaja potrzeby człowieka, co tłumaczą m.in. piramida Maslowa i teoria autodeterminacji.","wiki":[{"body":"Rekreacja pełni funkcję zaspokajania potrzeb rekreacyjnych, zdrowotnych, poznawczych, kulturowych i społecznych. Uczestnik angażuje się nie tylko dla ruchu, ale też dla poprawy kondycji, poznawania nowych treści, integracji i relaksu."},{"heading":"Piramida potrzeb Maslowa","body":"Maslow uporządkował potrzeby od najbardziej podstawowych do najwyższych:","bullets":["Fizjologiczne - ruch, odpoczynek, regeneracja (gimnastyka, spacery)","Bezpieczeństwa - bezpieczne warunki zajęć, nadzór trenera, struktura treningu","Przynależności i akceptacji - zajęcia grupowe, integracja, gry zespołowe","Uznania - pochwały, osiągnięcia, testy sprawnościowe","Samorealizacji - nowe wyzwania, rozwój kompetencji, kreatywność"]},{"heading":"Teoria autodeterminacji (Ryan i Deci)","body":"Wskazuje 3 kluczowe potrzeby psychologiczne, których zaspokojenie daje poczucie spełnienia i radości:","bullets":["Autonomia - decydowanie samemu o sobie","Kompetencja - poczucie sprawności i rozwijanie umiejętności","Relacje - posiadanie dobrych więzi z innymi"]}],"questions":[{"type":"abcd","q":"Które trzy potrzeby psychologiczne wyróżnia teoria autodeterminacji Ryana i Deciego?","options":["Poznawcze, kulturowe, zdrowotne","Fizjologiczne, bezpieczeństwa, uznania","Ruch, odpoczynek, regeneracja","Autonomia, kompetencja, relacje"],"correct":3,"explain":"Teoria autodeterminacji opiera się na potrzebie autonomii, kompetencji i relacji z innymi."},{"type":"tf","q":"Według piramidy Maslowa potrzeba samorealizacji znajduje się na najwyższym poziomie.","correct":true,"explain":"Maslow uporządkował potrzeby od fizjologicznych (najniższe) do samorealizacji (najwyższe)."},{"type":"flash","front":"Jak rekreacja realizuje potrzebę przynależności wg Maslowa?","back":"Poprzez zajęcia grupowe, integrację, gry zespołowe i wspólne wyprawy."}]},{"id":"komunikowanie-w-organizacji","track":"wszyscy","category":"zarzadzanie","number":5,"title":"Omów zagadnienie - Komunikowanie się w organizacji","summary":"Komunikacja to proces wymiany informacji w organizacji, pełniący funkcje informacyjną, motywacyjną, kontrolną i społeczną.","wiki":[{"body":"Komunikacja w organizacji to proces wymiany informacji, idei, opinii i instrukcji między członkami organizacji, odgrywający kluczową rolę w jej efektywnym funkcjonowaniu."},{"heading":"Funkcje komunikacji","bullets":["Informacyjna - przekazywanie danych, instrukcji, celów","Motywacyjna - zachęcanie pracowników do działania","Kontrolna - monitorowanie zadań i przestrzeganie zasad","Emocjonalno-społeczna - budowanie zaufania, atmosfery i relacji"]},{"heading":"Rodzaje komunikacji","bullets":["Formalna - oficjalne komunikaty, maile, spotkania, dokumenty","Nieformalna - codzienne rozmowy","Pionowa - polecenia przełożonych, raporty pracowników","Pozioma - między pracownikami tego samego szczebla"]},{"heading":"Rola lidera i bariery","body":"Lider przekazuje jasne informacje, udziela informacji zwrotnej, rozwiązuje konflikty, słucha, motywuje i prowadzi dialog. Bariery komunikacyjne to m.in. różnice międzykulturowe i wiekowe, brak jasnych kanałów oraz nieefektywne przekazywanie informacji."}],"questions":[{"type":"abcd","q":"Komunikacja między pracownikami tego samego szczebla to komunikacja:","options":["Pionowa","Pozioma","Formalna","Kontrolna"],"correct":1,"explain":"Komunikacja pozioma zachodzi między pracownikami na tym samym szczeblu, w odróżnieniu od pionowej (przełożony-podwładny)."},{"type":"tf","q":"Funkcja motywacyjna komunikacji polega na monitorowaniu zadań i przestrzegania zasad.","correct":false,"explain":"Monitorowanie zadań to funkcja kontrolna; funkcja motywacyjna polega na zachęcaniu pracowników do działania."},{"type":"flash","front":"Za co odpowiada lider w komunikacji w organizacji?","back":"Za przekazywanie jasnych informacji, udzielanie informacji zwrotnej, rozwiązywanie konfliktów, słuchanie, motywowanie i prowadzenie otwartego dialogu."}]},{"id":"rodzina-jako-mala-grupa","track":"wszyscy","category":"rekreacja","number":6,"title":"Rodzina jako mała grupa społeczna uczestnicząca w turystyce i rekreacji","summary":"Rodzina to mała grupa o własnych rolach i zasadach, której uczestnictwo w turystyce ma motywy integracyjne, wychowawcze, edukacyjne i zdrowotne.","wiki":[{"body":"Rodzina to grupa społeczna składająca się z bliskich osób - najczęściej rodziców i dzieci, czasem dziadków. Jej członkowie dobrze się znają i spędzają razem dużo czasu, a grupa - choć niewielka - ma swoje zasady i role."},{"heading":"Motywy uczestnictwa rodziny w turystyce i rekreacji","bullets":["Integracyjny - wspólne spędzanie czasu, oderwanie od codzienności, wzmacnianie więzi","Wychowawczy - dzieci uczą się przez obserwację zasad społecznych, współpracy i kultury","Edukacyjny - poznawanie nowych miejsc, kultury i historii","Zdrowotny - aktywność fizyczna (spacery, rower, pływanie) wspiera zdrowie całej rodziny"]},{"heading":"Planowanie wyjazdu","body":"Wyjazd to często wspólna decyzja - rodzice wybierają miejsce, ale uwzględniają sugestie dzieci. Wybór zależy od możliwości finansowych, zainteresowań i potrzeb. Trudności mogą wynikać z różnic pokoleniowych, ograniczeń finansowych oraz zmieniających się potrzeb rodziny."}],"questions":[{"type":"abcd","q":"Który motyw uczestnictwa rodziny w turystyce wiąże się z uczeniem dzieci zasad społecznych przez obserwację?","options":["Wychowawczy","Zdrowotny","Integracyjny","Edukacyjny"],"correct":0,"explain":"Motyw wychowawczy polega na tym, że dzieci uczą się zasad społecznych, współpracy i kultury przez obserwację i uczestnictwo."},{"type":"tf","q":"Planowanie wyjazdu rodzinnego nigdy nie napotyka problemów wynikających z różnic pokoleniowych.","correct":false,"explain":"Różnice pokoleniowe (inne zainteresowania), ograniczenia finansowe i zmiany potrzeb mogą utrudniać planowanie wyjazdu."},{"type":"flash","front":"Wymień motywy uczestnictwa rodziny w turystyce i rekreacji.","back":"Integracyjny, wychowawczy, edukacyjny i zdrowotny."}]},{"id":"zabawa-rozrywka-grupy-wiekowe","track":"wszyscy","category":"rekreacja","number":9,"title":"Zabawa i rozrywka w kontekście czasu wolnego różnych grup wiekowych","summary":"Zabawa i rozrywka pełnią różne funkcje w czasie wolnym dzieci, młodzieży i dorosłych.","wiki":[{"body":"Czas wolny to czas bez obowiązków zawodowych, szkolnych czy domowych, przeznaczony na odpoczynek, regenerację i samorealizację. Zabawa to spontaniczna aktywność dająca radość i rozwijająca umiejętności, a rozrywka to szeroko pojęte formy spędzania czasu wolnego (fizyczne, kulturowe, rekreacyjne)."},{"heading":"Dzieci (wiek przedszkolny i wczesnoszkolny)","bullets":["Zabawy ruchowe - rozwijają sprawność fizyczną (bieganie, plac zabaw)","Zabawy konstrukcyjne - wspierają logiczne myślenie (klocki, układanki)","Zabawy fabularne i tematyczne - rozwijają wyobraźnię (dom, sklep)","Gry planszowe - ćwiczą pamięć i koncentrację"]},{"heading":"Młodzież","bullets":["Sport - kondycja i zdrowie (siłownia, sporty drużynowe, taniec)","Kultura - muzyka, kino, teatr","Internet i gry komputerowe, media społecznościowe","Podróże oraz wolontariat (poczucie sensu, odpowiedzialność)"]},{"heading":"Dorośli","bullets":["Relaks - redukcja stresu (książki, film)","Aktywność fizyczna (siłownia, joga, fitness)","Spotkania towarzyskie i hobby/pasje","Rozwój zawodowy i nauka"]}],"questions":[{"type":"abcd","q":"Który rodzaj zabawy dzieci szczególnie wspiera logiczne myślenie?","options":["Zabawy ruchowe","Zabawy tematyczne","Zabawy fabularne","Zabawy konstrukcyjne"],"correct":3,"explain":"Zabawy konstrukcyjne (klocki, układanki) wspierają logiczne myślenie."},{"type":"tf","q":"Czas wolny dorosłych jest zazwyczaj mocno ograniczony przez dużą ilość obowiązków.","correct":true,"explain":"Według materiału czas wolny dorosłych jest dość mocno ograniczony przez liczne obowiązki."},{"type":"flash","front":"Czym różni się zabawa od rozrywki?","back":"Zabawa to spontaniczna aktywność dająca radość i rozwijająca umiejętności; rozrywka to szeroko pojęte formy spędzania czasu wolnego - fizyczne, kulturowe i rekreacyjne."}]},{"id":"zasady-prezentacji-powerpoint","track":"wszyscy","category":"technologie","number":10,"title":"Podaj 5 zasad dobrze przygotowanej prezentacji w PowerPoint","summary":"Dobra prezentacja opiera się na logicznej strukturze, minimalizmie, spójnym stylu, wspierającej grafice i interakcji z odbiorcami.","wiki":[{"heading":"Pięć zasad","bullets":["Logiczna struktura i płynność - jasny podział na wstęp, rozwinięcie i zakończenie, start od tytułu i spisu treści, logiczna kolejność slajdów","Przejrzystość i minimalizm - jeden slajd to jedna myśl, hasła i punkty zamiast długich zdań, czytelna czcionka (Arial, Calibri)","Styl graficzny - jedna kolorystyka i czcionka, maksymalnie 2-3 kolory, unikanie nadmiaru efektów specjalnych","Grafika i wspierające treści - każdy element graficzny coś tłumaczy, obrazy dobrej jakości i czytelne","Interakcja i dopasowanie do słuchaczy - mówienie swobodne zamiast czytania slajdów, angażowanie pytaniami i przykładami, dostosowanie języka do odbiorców"]}],"questions":[{"type":"abcd","q":"Ile kolorów zaleca się stosować w spójnym stylu graficznym prezentacji?","options":["Dowolnie wiele","Co najmniej 5","Maksymalnie 2-3","Tylko czarny i biały"],"correct":2,"explain":"Zasada stylu graficznego zaleca używanie maksymalnie 2-3 kolorów dla zachowania spójności."},{"type":"tf","q":"Zgodnie z dobrymi zasadami prezentacji należy odczytywać tekst ze slajdów słowo w słowo.","correct":false,"explain":"Zasada interakcji mówi, by nie czytać slajdów, lecz mówić swobodnie i rozwijać hasła."},{"type":"flash","front":"Na czym polega zasada przejrzystości i minimalizmu?","back":"Każdy slajd to jedna myśl - krótko i konkretnie; zamiast długich zdań stosuje się hasła i punkty oraz czytelną czcionkę odpowiedniej wielkości."}]},{"id":"fizjologiczne-podstawy-treningu","track":"wszyscy","category":"fizjologia","number":11,"title":"Przedstaw fizjologiczne podstawy treningu fizycznego człowieka","summary":"Trening wywołuje adaptacje fizjologiczne w wielu układach organizmu, opierając się na trzech systemach energetycznych.","wiki":[{"body":"Trening fizyczny wpływa na organizm poprzez adaptacje fizjologiczne zwiększające wydolność, siłę i sprawność. Jego podstawą jest zdolność organizmu do adaptacji do obciążeń wysiłkowych."},{"heading":"Źródła energii podczas wysiłku","bullets":["System fosfagenowy (ATP) - dostarcza energii bardzo szybko, do krótkich intensywnych wysiłków","Glikoliza beztlenowa - rozkład glukozy bez tlenu, energia od kilkudziesięciu sekund do minut, produktem jest mleczan","Metabolizm tlenowy - zachodzi w mitochondriach, wykorzystuje węglowodany i tłuszcze, do długotrwałych wysiłków"]},{"heading":"Adaptacje układów","bullets":["Mięśniowy - hipertrofia, wzrost wytrzymałości, więcej mitochondriów, lepsza koordynacja nerwowo-mięśniowa","Krążenia - wzrost objętości wyrzutowej i minutowej serca, spadek tętna spoczynkowego, więcej naczyń włosowatych, obniżenie ciśnienia i poziomu LDL","Oddechowy - większa pojemność płuc, lepsza wymiana gazowa, silniejsze mięśnie oddechowe","Nerwowy - lepsza koordynacja i czas reakcji, więcej endorfin","Metaboliczny i hormonalny - lepsze spalanie tłuszczów, większa wrażliwość na insulinę, wzrost testosteronu"]}],"questions":[{"type":"abcd","q":"Który system energetyczny dostarcza energii najszybciej, w krótkich i intensywnych wysiłkach?","options":["Metabolizm tlenowy","System fosfagenowy (ATP)","Glikoliza beztlenowa","Lipoliza"],"correct":1,"explain":"System fosfagenowy (ATP) dostarcza energii bardzo szybko i jest wykorzystywany w krótkich intensywnych wysiłkach."},{"type":"tf","q":"Regularny trening prowadzi do spadku tętna spoczynkowego.","correct":true,"explain":"Adaptacja układu krążenia obejmuje spadek tętna spoczynkowego - serce bije wolniej i bardziej efektywnie."},{"type":"flash","front":"Jakie zmiany w układzie mięśniowym wywołuje trening?","back":"Hipertrofia (wzrost masy i siły), wzrost wytrzymałości, większa liczba mitochondriów oraz lepsza koordynacja nerwowo-mięśniowa."}]},{"id":"segmentacja-rynku-turystycznego","track":"wszyscy","category":"marketing","number":12,"title":"Przedstaw segmentację rynku turystycznego/rekreacyjnego - pojęcie, kryteria i przykłady","summary":"Segmentacja to podział klientów na grupy o podobnych cechach, co pozwala lepiej dopasować ofertę.","wiki":[{"body":"Segmentacja rynku to podział dużej grupy klientów na mniejsze segmenty o podobnych cechach, potrzebach lub zachowaniach. Dzięki temu firmy turystyczne lepiej dopasowują oferty do konkretnej grupy, zwiększając jej zadowolenie i skuteczność marketingu."},{"heading":"Kryteria segmentacji","bullets":["Demograficzne - wiek, płeć, dochód, stan cywilny, wykształcenie","Geograficzne - miejsce zamieszkania, klimat, odległość od destynacji","Psychograficzne - styl życia, wartości, osobowość, zainteresowania","Behawioralne - motywacje, lojalność, częstotliwość podróżowania"]},{"heading":"Segmentacja wg celu podróży i aktywności","bullets":["Cel podróży: wypoczynkowa, biznesowa, zdrowotna (spa, wellness), kulturowa","Rodzaj aktywności: sportowa, ekoturystyka, rozrywkowa"]},{"heading":"Przykładowe segmenty","bullets":["Rodziny z dziećmi - atrakcje dla najmłodszych","Młodzi dorośli - przygody, życie nocne, aktywny odpoczynek","Seniorzy - spokój i dostęp do opieki medycznej","Turyści biznesowi - szybki transport i dogodności do pracy","Miłośnicy przygód - ekoturystyka, natura"]}],"questions":[{"type":"abcd","q":"Styl życia, wartości i zainteresowania to kryterium segmentacji:","options":["Psychograficzne","Geograficzne","Demograficzne","Behawioralne"],"correct":0,"explain":"Kryterium psychograficzne obejmuje styl życia, wartości, osobowość i zainteresowania."},{"type":"tf","q":"Segmentacja rynku pozwala firmom turystycznym lepiej dopasować ofertę do konkretnej grupy klientów.","correct":true,"explain":"To główny cel segmentacji - dopasowanie oferty zwiększa zadowolenie klientów i skuteczność działań marketingowych."},{"type":"flash","front":"Wymień cztery kryteria segmentacji rynku turystycznego.","back":"Demograficzne, geograficzne, psychograficzne i behawioralne."}]},{"id":"czynniki-zachowania-wolnoczasowe","track":"wszyscy","category":"rekreacja","number":13,"title":"Scharakteryzuj czynniki determinujące zachowanie wolnoczasowe","summary":"Wybór form spędzania czasu wolnego zależy od czynników demograficznych, ekonomicznych, społecznych, psychologicznych, kulturowo-technologicznych i środowiskowych.","wiki":[{"body":"Zachowanie wolnoczasowe to sposoby, w jakie ludzie spędzają swój czas wolny. Wybór aktywności zależy od wielu czynników."},{"heading":"Czynniki demograficzne","bullets":["Wiek - dzieci preferują zabawy ruchowe, młodzież gry i sport, dorośli rekreację i turystykę, seniorzy spokojne formy (spacery)","Płeć - mężczyźni częściej sport i rywalizację, kobiety częściej zajęcia relaksacyjne, kulturowe i społeczne","Stan cywilny i sytuacja rodzinna - osoby samotne wybierają podróże i spotkania, rodziny z dziećmi rekreację dla najmłodszych"]},{"heading":"Pozostałe czynniki","bullets":["Ekonomiczne - dochód i dostępność urlopu wpływają na wybór (droższe vs darmowe formy)","Społeczne - wpływ rodziny i znajomych, trendy i moda na zdrowy styl życia","Psychologiczne - motywacje, osobowość (introwertyk vs ekstrawertyk), stan zdrowia","Kulturowe i technologiczne - internet, gry online, urbanizacja i infrastruktura miast","Środowiskowe - infrastruktura, walory naturalne (góry, jeziora, lasy), dostępność komunikacyjna i bezpieczeństwo"]}],"questions":[{"type":"abcd","q":"Różnica między introwertykami a ekstrawertykami w wyborze form czasu wolnego należy do czynników:","options":["Ekonomicznych","Demograficznych","Psychologicznych","Środowiskowych"],"correct":2,"explain":"Osobowość (introwertyk vs ekstrawertyk) to czynnik psychologiczny."},{"type":"tf","q":"Bliskość gór, jezior i lasów to przykład czynnika ekonomicznego determinującego zachowanie wolnoczasowe.","correct":false,"explain":"Walory naturalne to czynniki środowiskowe, a nie ekonomiczne; do ekonomicznych zalicza się np. dochód czy ceny usług."},{"type":"flash","front":"Wymień główne grupy czynników determinujących zachowanie wolnoczasowe.","back":"Demograficzne, ekonomiczne, społeczne, psychologiczne, kulturowo-technologiczne oraz środowiskowe."}]},{"id":"ladowe-ekosystemy-swiata","track":"wszyscy","category":"przyroda","number":15,"title":"Lądowe ekosystemy świata: bioróżnorodność, problemy środowiskowe","summary":"Charakterystyka głównych ekosystemów lądowych, ich bioróżnorodności oraz zagrożeń środowiskowych.","wiki":[{"heading":"Bioróżnorodność","body":"Bioróżnorodność (różnorodność biologiczna) to całe bogactwo form życia na Ziemi: gatunki zwierząt, roślin i mikroorganizmów, ich zróżnicowanie genetyczne oraz ekosystemy, w których funkcjonują.","bullets":["Genetyczna - np. rasy psów, różne odmiany jabłoni","Gatunkowa - liczba i rodzaje gatunków (ptaki, ssaki, rośliny) w danym ekosystemie","Ekosystemowa - lasy, łąki, bagna, pustynie"]},{"heading":"Główne ekosystemy lądowe","bullets":["Lasy równikowe (deszczowe, tropikalne) - najbogatszy ekosystem Ziemi, liczne gatunki endemiczne; zagrożenia: wycinka, rolnictwo (soja, palma olejowa), zmiany klimatu","Lasy liściaste strefy umiarkowanej - różnorodne drzewa liściaste, bogata fauna; zagrożenia: zanieczyszczenia powietrza, intensywna gospodarka leśna, fragmentacja siedlisk","Tajga - dominują drzewa iglaste, fauna chłodnego klimatu (łosie, wilki, niedźwiedzie); zagrożenia: wycinka przemysłowa, topnienie wiecznej zmarzliny, pożary","Pustynie - sukulenty, gady, drobne ssaki; zagrożenia: zmiany klimatu, nadużywanie wód podziemnych","Tundra - niska roślinność (mchy, porosty), lisy polarne, sowy śnieżne, renifery; zagrożenia: eksploatacja surowców, ocieplenie klimatu","Sawanna - obszary trawiaste z rozproszonymi drzewami, dużo ssaków; zagrożenia: nadmierny wypas, kłusownictwo, wypalanie traw","Stepy i prerie - trawiaste równiny (trawy, gryzonie, sokoły, dzikie konie); zagrożenia: przekształcanie w tereny rolnicze, erozja gleby"]}],"questions":[{"type":"abcd","q":"Który ekosystem lądowy jest uznawany za najbogatszy pod względem bioróżnorodności?","options":["Tundra","Lasy równikowe (deszczowe)","Pustynie","Stepy i prerie"],"correct":1,"explain":"Lasy równikowe (tropikalne) to najbogatszy ekosystem Ziemi z ogromną liczbą gatunków, w tym licznymi endemitami."},{"type":"abcd","q":"Ile rodzajów bioróżnorodności wyróżniono w materiale?","options":["3 - genetyczna, gatunkowa, ekosystemowa","2 - genetyczna i gatunkowa","4 - z dodatkiem krajobrazowej","5"],"correct":0,"explain":"Wyróżniono trzy rodzaje: genetyczną, gatunkową i ekosystemową."},{"type":"tf","q":"Topnienie wiecznej zmarzliny jest jednym z problemów środowiskowych tajgi.","correct":true,"explain":"W tajdze zagrożeniem są wycinka przemysłowa, zmiany klimatyczne (topnienie wiecznej zmarzliny) oraz pożary."},{"type":"flash","front":"Wymień przykładowe problemy środowiskowe lasów równikowych.","back":"Wycinka lasów, rolnictwo (uprawa soi, palmy olejowej) prowadzące do utraty siedlisk i spadku bioróżnorodności, oraz zmiany klimatyczne przesuszające lasy."}]},{"id":"wodne-ekosystemy-swiata","track":"wszyscy","category":"przyroda","number":17,"title":"Wodne ekosystemy świata: bioróżnorodność, problemy środowiskowe","summary":"Charakterystyka ekosystemów słodkowodnych i morskich, ich bioróżnorodności, zagrożeń oraz sposobów ochrony.","wiki":[{"heading":"Rodzaje wodnych ekosystemów","body":"Ekosystemy wodne są kluczowe dla życia na Ziemi - stanowią siedliska milionów gatunków oraz pełnią funkcję filtracyjną i klimatyczną.","bullets":["Słodkowodne - rzeki, jeziora, bagna, mokradła; ryby (pstrągi, sumy), płazy (żaby, salamandry), gady (żółwie, krokodyle), rośliny wodne, ptaki wodne","Morskie - oceany, morza, rafy koralowe; od planktonu i koralowców po drapieżniki jak rekiny","Rafy koralowe - zajmują niewielką powierzchnię, ale są siedliskiem dla około 25% wszystkich gatunków morskich"]},{"heading":"Problemy środowiskowe","bullets":["Zanieczyszczenia wód - ścieki przemysłowe i rolnicze, pestycydy; eutrofizacja (namnażanie glonów przez nadmiar azotu, deficyt tlenu); plastik w oceanach","Zmiany klimatu i globalne ocieplenie - zakwaszenie oceanu, wzrost poziomu wody, zmiany zasolenia przez topnienie lodowców","Nadmierna eksploatacja - budowa i regulacja rzek ograniczająca migrację ryb","Zanieczyszczenie siedlisk - osuszanie bagien i mokradeł, utrata siedlisk ptaków wodnych i płazów"]},{"heading":"Ochrona wodnych ekosystemów","bullets":["Zrównoważone rybołówstwo","Ochrona siedlisk i gatunków","Działania na rzecz klimatu","Redukcja zanieczyszczeń"]}],"questions":[{"type":"abcd","q":"Jaki odsetek wszystkich gatunków morskich znajduje siedlisko w rafach koralowych?","options":["Około 5%","Około 10%","Około 25%","Około 50%"],"correct":2,"explain":"Rafy koralowe zajmują niewielką powierzchnię, lecz są siedliskiem dla około 25% wszystkich gatunków morskich."},{"type":"abcd","q":"Czym jest eutrofizacja?","options":["Zakwaszeniem oceanu przez wzrost temperatury","Przyspieszonym namnażaniem glonów spowodowanym nadmiarem azotu, prowadzącym do deficytu tlenu","Topnieniem lodowców i wzrostem poziomu wód","Migracją ryb między rzekami"],"correct":1,"explain":"Eutrofizacja to przyspieszone namnażanie glonów wskutek nadmiaru azotu, co prowadzi do deficytu tlenu i śmierci organizmów wodnych."},{"type":"tf","q":"Osuszanie bagien i mokradeł przyczynia się do utraty siedlisk ptaków wodnych i płazów.","correct":true,"explain":"Osuszanie bagien i mokradeł to zanieczyszczenie/niszczenie siedlisk skutkujące utratą siedlisk ptaków wodnych i płazów."},{"type":"flash","front":"Wymień sposoby ochrony wodnych ekosystemów.","back":"Zrównoważone rybołówstwo, ochrona siedlisk i gatunków, działania na rzecz klimatu oraz redukcja zanieczyszczeń."}]},{"id":"zalety-statystyki-w-turystyce","track":"wszyscy","category":"technologie","number":19,"title":"Zalety stosowania statystyki w turystyce","summary":"Co najmniej trzy zalety wykorzystania statystyki w planowaniu, ocenie wpływu gospodarczego i decyzjach biznesowych w turystyce.","wiki":[{"heading":"Lepsze planowanie i zarządzanie turystyką","body":"Statystyka dostarcza danych o tym, ilu turystów przyjeżdża, skąd pochodzą, jak długo zostają i z jakich usług korzystają.","bullets":["Efektywne planowanie rozwoju infrastruktury (noclegi, drogi, atrakcje)","Dostosowanie oferty usługowej i zarządzanie zasobami","Np. dane o szczycie w lipcu i sierpniu pozwalają z wyprzedzeniem zwiększyć liczbę pracowników i rozbudować bazę","Zmniejszenie ryzyka przeciążenia miejsc i niezadowolenia turystów"]},{"heading":"Monitorowanie wpływu gospodarczego","body":"Statystyka pozwala ocenić, jak turystyka wpływa na gospodarkę: ile pieniędzy wydają turyści, które branże zyskują (hotele, restauracje, transport), ile miejsc pracy tworzy turystyka. Pomaga to władzom lokalnym podejmować świadome decyzje rozwojowe."},{"heading":"Trafne decyzje biznesowe i prognozowanie trendów","body":"Analiza statystyczna pomaga przewidzieć przyszłe zachowania turystów, co jest istotne przy planowaniu reklam, inwestycji i planów rozwoju. Branża może szybciej reagować na problemy, takie jak spadek liczby odwiedzających lub zmiana zainteresowań."}],"questions":[{"type":"abcd","q":"Która z poniższych jest zaletą stosowania statystyki w turystyce wymienioną w materiale?","options":["Lepsze planowanie i zarządzanie turystyką","Eliminacja sezonowości ruchu turystycznego","Likwidacja kosztów infrastruktury","Gwarancja stałej liczby turystów"],"correct":0,"explain":"Pierwszą wymienioną zaletą jest lepsze planowanie i zarządzanie turystyką dzięki danym o ruchu turystycznym."},{"type":"tf","q":"Statystyka pozwala ocenić wpływ turystyki na gospodarkę, np. ile pieniędzy wydają turyści i ile miejsc pracy tworzy turystyka.","correct":true,"explain":"Monitorowanie wpływu gospodarczego to jedna z głównych zalet - statystyka ujawnia wydatki turystów, zyski branż i liczbę miejsc pracy."},{"type":"flash","front":"Podaj trzy zalety stosowania statystyki w turystyce.","back":"Lepsze planowanie i zarządzanie turystyką, monitorowanie wpływu gospodarczego oraz podejmowanie trafnych decyzji biznesowych i prognozowanie trendów."}]},{"id":"pojecie-i-funkcje-zarzadzania","track":"wszyscy","category":"zarzadzanie","number":21,"title":"Pojęcie i funkcje zarządzania","summary":"Definicja zarządzania oraz jego podstawowe funkcje: planowanie, organizowanie, przewodzenie i kontrolowanie.","wiki":[{"heading":"Pojęcie zarządzania","body":"Zarządzanie to proces planowania, organizowania, przewodzenia i kontrolowania zasobów organizacji w celu osiągnięcia określonych celów. Jest kluczowym elementem funkcjonowania każdej organizacji, niezależnie od jej wielkości czy branży."},{"heading":"Podstawowe funkcje zarządzania","bullets":["Planowanie - określanie celów i sposobów ich realizacji; analiza sytuacji, prognozowanie i opracowanie strategii","Organizowanie - przydzielanie zadań, zasobów i odpowiedzialności; tworzenie struktur organizacyjnych","Przewodzenie - motywowanie i prowadzenie zespołu, komunikacja, rozwiązywanie problemów i podejmowanie decyzji","Kontrolowanie - monitorowanie postępów i porównywanie z celami; wprowadzanie korekt"]},{"body":"W modelu Henriego Fayola wyróżnia się 5. funkcję: koordynowanie."}],"questions":[{"type":"abcd","q":"Która funkcja zarządzania polega na monitorowaniu postępów i porównywaniu ich z założonymi celami?","options":["Planowanie","Kontrolowanie","Przewodzenie","Organizowanie"],"correct":1,"explain":"Kontrolowanie to monitorowanie postępów i porównywanie ich z celami oraz wprowadzanie korekt."},{"type":"abcd","q":"Jaką piątą funkcję zarządzania dodał Henri Fayol?","options":["Koordynowanie","Delegowanie","Negocjowanie","Raportowanie"],"correct":0,"explain":"W modelu Henriego Fayola piątą funkcją jest koordynowanie."},{"type":"tf","q":"Motywowanie zespołu, komunikacja i podejmowanie decyzji należą do funkcji planowania.","correct":false,"explain":"To elementy przewodzenia, a nie planowania; planowanie dotyczy wyznaczania celów i sposobów ich osiągnięcia."},{"type":"flash","front":"Wymień cztery podstawowe funkcje zarządzania.","back":"Planowanie, organizowanie, przewodzenie i kontrolowanie (w modelu Fayola dodatkowo koordynowanie)."}]},{"id":"determinizm-i-wolna-wola","track":"wszyscy","category":"historia","number":22,"title":"Problem determinizmu i wolnej woli. Czy człowiek jest wolny?","summary":"Pojęcia determinizmu i wolnej woli oraz trzy główne stanowiska filozoficzne wobec pytania o wolność człowieka.","wiki":[{"heading":"Pojęcia","bullets":["Determinizm - pogląd, że wszystko, co się dzieje, ma swoją przyczynę; znając prawa natury i warunki początkowe można przewidzieć każde zdarzenie, także ludzkie decyzje","Wolna wola - przekonanie, że człowiek może samodzielnie wybierać, co oznacza odpowiedzialność za swoje decyzje"]},{"heading":"Problem","body":"Jeśli wszystko jest z góry zdeterminowane, to być może nasze decyzje są jedynie skutkiem genów, wychowania i innych wpływów. Powstaje pytanie, czy mamy wtedy wolną wolę i czy jesteśmy za coś odpowiedzialni."},{"heading":"Trzy główne podejścia filozoficzne","bullets":["Twardy determinizm - nie ma wolnej woli; wolność to tylko nasze wrażenie, a nie prawda","Libertarianizm - wolna wola istnieje, świat nie jest całkowicie zdeterminowany; człowiek może działać inaczej i ponosi odpowiedzialność","Kompatybilizm - wolna wola i determinizm mogą współistnieć; człowiek jest wolny, jeśli działa zgodnie ze swoimi przekonaniami, a nie pod przymusem"]}],"questions":[{"type":"abcd","q":"Które stanowisko głosi, że wolna wola i determinizm mogą działać razem?","options":["Twardy determinizm","Kompatybilizm","Libertarianizm","Indeterminizm"],"correct":1,"explain":"Kompatybilizm zakłada, że wolna wola i determinizm mogą współistnieć - człowiek jest wolny, jeśli działa zgodnie ze swoimi przekonaniami, a nie pod przymusem."},{"type":"abcd","q":"Co głosi twardy determinizm w kwestii wolności człowieka?","options":["Wolność to iluzja, wolnej woli nie ma","Człowiek jest w pełni wolny","Wolność zależy od wychowania","Wolna wola istnieje obok determinizmu"],"correct":0,"explain":"Według twardego determinizmu wolności nie ma - jest ona tylko iluzją, a wszystko dzieje się, bo musiało się tak stać."},{"type":"tf","q":"Determinizm to pogląd, że wszystko, co się dzieje, ma swoją przyczynę.","correct":true,"explain":"Tak brzmi definicja determinizmu - każde zdarzenie ma swoją przyczynę, a znając prawa natury i warunki początkowe można je przewidzieć."},{"type":"flash","front":"Wymień trzy główne podejścia filozoficzne do problemu determinizmu i wolnej woli.","back":"Twardy determinizm (brak wolnej woli), libertarianizm (wolna wola istnieje) oraz kompatybilizm (wolna wola i determinizm współistnieją)."}]},{"id":"e-marketing-w-turystyce-i-rekreacji","track":"wszyscy","category":"marketing","number":23,"title":"E-marketing w turystyce i rekreacji: pojęcie, narzędzia, znaczenie","summary":"Definicja e-marketingu, jego najważniejsze narzędzia cyfrowe oraz znaczenie dla promocji oferty turystycznej i rekreacyjnej.","wiki":[{"heading":"Pojęcie","body":"E-marketing to wykorzystywanie cyfrowych kanałów komunikacji do prezentowania oferty turystycznej, interakcji z klientami oraz monitorowania skuteczności działań. Kluczowym celem jest dotarcie do potencjalnych turystów i rekreantów w sposób atrakcyjny, spersonalizowany i mierzalny."},{"heading":"Narzędzia e-marketingu","bullets":["Strony internetowe i blogi - atrakcyjne strony ze zdjęciami i opisami, blogi budujące zaufanie","SEO - optymalizacja treści pod wyszukiwarki, by strona pojawiała się wyżej w wynikach","SEM - płatne reklamy (np. Google Ads) docierające do osób szukających konkretnych usług","Media społecznościowe - Instagram, Facebook itp. do prezentacji oferty i interakcji","E-mail marketing - newslettery i oferty specjalne utrzymujące kontakt z klientami","Content marketing - wartościowe treści: artykuły, filmy, infografiki","Mobile marketing - dostosowanie treści i reklam do urządzeń mobilnych","Reklamy graficzne i wideo - atrakcyjny wizualny sposób prezentacji oferty"]},{"heading":"Znaczenie","bullets":["Globalny zasięg - prezentacja ofert na całym świecie 24/7","Niższe koszty - reklama tańsza i bardziej efektywna","Dostosowanie do klienta - dzięki analizie danych oferta dopasowana indywidualnie","Szybka analiza wyników - bieżące śledzenie skuteczności kampanii"]}],"questions":[{"type":"abcd","q":"Które narzędzie e-marketingu polega na płatnych reklamach docierających do osób szukających konkretnych usług turystycznych?","options":["SEO","SEM (np. Google Ads)","Newsletter","Blog"],"correct":1,"explain":"SEM (marketing w wyszukiwarkach) to płatne reklamy, np. Google Ads, docierające do osób szukających konkretnych usług turystycznych."},{"type":"abcd","q":"Co jest kluczowym celem e-marketingu w turystyce?","options":["Dotarcie do turystów w sposób atrakcyjny, spersonalizowany i mierzalny","Wyłącznie obniżenie kosztów drukowania ulotek","Zastąpienie pracowników biur podróży","Rezygnacja z analizy danych o klientach"],"correct":0,"explain":"Celem e-marketingu jest dotarcie do potencjalnych turystów i rekreantów w sposób atrakcyjny, spersonalizowany oraz mierzalny."},{"type":"tf","q":"Ograniczony, lokalny zasięg oferty to jedna z głównych zalet e-marketingu w turystyce.","correct":false,"explain":"Przeciwnie — atutem e-marketingu jest globalny zasięg i dostępność oferty 24/7, a nie ograniczenie do rynku lokalnego."},{"type":"flash","front":"Wymień co najmniej cztery narzędzia e-marketingu w turystyce.","back":"Strony internetowe i blogi, SEO, SEM (Google Ads), media społecznościowe, e-mail marketing, content marketing, mobile marketing oraz reklamy graficzne i wideo."}]},{"id":"rola-managera-w-turystyce","track":"wszyscy","category":"zarzadzanie","number":24,"title":"Rola managera w turystyce","summary":"Kluczowa rola i główne obowiązki managera zarządzającego firmami turystycznymi.","wiki":[{"heading":"Rola managera","body":"Manager w turystyce odgrywa kluczową rolę w zarządzaniu działalnością firm turystycznych, takich jak biura podróży, hotele i organizatorzy wycieczek. Jego główne zadania obejmują planowanie, organizowanie, kierowanie i kontrolowanie działań związanych z oferowaniem usług turystycznych."},{"heading":"Kluczowe obowiązki","bullets":["Zarządzanie zespołem - rekrutacja, motywowanie, przydzielanie zadań, monitorowanie","Planowanie i rozwój oferty turystycznej - tworzenie atrakcyjnych pakietów, analiza trendów rynkowych, wprowadzanie nowych produktów","Relacje z klientami - wysoka jakość obsługi, rozwiązywanie problemów, reagowanie na opinie","Marketing i promocja - opracowywanie strategii, wykorzystywanie narzędzi e-marketingu","Zarządzanie finansami - budżetowanie, kontrola kosztów, analiza wyników i działania korygujące","Współpraca z partnerami - kontakt z dostawcami usług (hotele, przewodnicy), budowanie relacji biznesowych","Zapewnienie zgodności z przepisami - przestrzeganie regulacji prawnych i monitorowanie ich zmian"]},{"body":"W dynamicznie zmieniającej się branży manager musi być elastyczny i otwarty na innowacje, aby spełniać oczekiwania klientów i sprostać wyzwaniom rynkowym."}],"questions":[{"type":"abcd","q":"Które zadanie należy do kluczowych obowiązków managera w turystyce?","options":["Osobiste oprowadzanie wszystkich wycieczek","Ignorowanie opinii klientów","Zakaz korzystania z e-marketingu","Zarządzanie zespołem: rekrutacja, motywowanie, przydzielanie zadań"],"correct":3,"explain":"Zarządzanie zespołem - rekrutacja, motywowanie, przydzielanie zadań i monitorowanie - to jeden z kluczowych obowiązków managera."},{"type":"tf","q":"W dynamicznie zmieniającej się branży turystycznej manager powinien być elastyczny i otwarty na innowacje.","correct":true,"explain":"Materiał wskazuje, że manager musi być elastyczny i otwarty na innowacje, aby sprostać oczekiwaniom klientów i wyzwaniom rynku."},{"type":"flash","front":"Wymień przykładowe obowiązki managera w turystyce.","back":"Zarządzanie zespołem, planowanie i rozwój oferty, relacje z klientami, marketing i promocja, zarządzanie finansami, współpraca z partnerami oraz zapewnienie zgodności z przepisami."}]},{"id":"badania-pierwotne-a-wtorne-rynku-turystycznego","track":"wszyscy","category":"marketing","number":25,"title":"Różnice między badaniami pierwotnymi a wtórnymi rynku turystycznego","summary":"Porównanie badań pierwotnych i wtórnych rynku turystycznego pod kątem źródeł danych, metod oraz zalet i wad.","wiki":[{"heading":"Badania pierwotne","body":"Polegają na zbieraniu nowych, niepublikowanych wcześniej danych bezpośrednio od źródła.","bullets":["Metody: wywiady indywidualne, ankiety i kwestionariusze, grupy fokusowe, obserwacje","Zalety: aktualność danych, dostosowanie do potrzeb badania, kontrola jakości","Wady: kosztowność, czasochłonność, wymagana infrastruktura i zasoby"]},{"heading":"Badania wtórne","body":"Polegają na analizie już istniejących danych, zebranych i opublikowanych wcześniej przez inne podmioty.","bullets":["Źródła: raporty branżowe, dane statystyczne urzędów, artykuły naukowe i publikacje, bazy danych","Zalety: oszczędność czasu i kosztów, szeroki zakres informacji, łatwość porównania danych historycznych","Wady: brak aktualności, ograniczona elastyczność (dane zebrane w innym celu), niepewna jakość"]},{"heading":"Najważniejsze różnice","body":"Oba podejścia różnią się metodologią zbierania danych, źródłami informacji oraz zastosowaniem. Pierwotne dają świeże, dopasowane dane kosztem czasu i pieniędzy; wtórne są tańsze i szybsze, lecz mniej aktualne i mniej elastyczne."}],"questions":[{"type":"abcd","q":"Co jest cechą badań pierwotnych rynku turystycznego?","options":["Zbieranie nowych, niepublikowanych danych bezpośrednio od źródła","Analiza danych opublikowanych wcześniej przez inne podmioty","Korzystanie wyłącznie z raportów branżowych","Brak możliwości dostosowania do potrzeb badania"],"correct":0,"explain":"Badania pierwotne polegają na zbieraniu nowych, niepublikowanych wcześniej danych bezpośrednio od źródła (np. ankiety, wywiady)."},{"type":"abcd","q":"Która z poniższych jest zaletą badań wtórnych?","options":["Pełna aktualność danych","Oszczędność czasu i kosztów","Możliwość bezpośredniej kontroli jakości zbierania danych","Pełne dostosowanie do potrzeb konkretnego badania"],"correct":1,"explain":"Zaletą badań wtórnych jest oszczędność czasu i kosztów, bo dane są już dostępne i nie trzeba zbierać ich od podstaw."},{"type":"tf","q":"Zaletą badań wtórnych jest zawsze pełna aktualność i pewna jakość danych.","correct":false,"explain":"To wada, nie zaleta — dane wtórne bywają nieaktualne i zebrane w innym celu, więc ich jakość jest niepewna."},{"type":"flash","front":"Czym różnią się badania pierwotne od wtórnych rynku turystycznego?","back":"Pierwotne to zbieranie nowych danych bezpośrednio od źródła (aktualne, dopasowane, ale drogie i czasochłonne); wtórne to analiza istniejących, opublikowanych danych (tańsze i szybsze, ale mniej aktualne i elastyczne)."}]},{"id":"znaczenie-kultury-w-turystyce","track":"wszyscy","category":"historia","number":26,"title":"Znaczenie kultury w turystyce","summary":"Rola kultury jako atrakcji i elementu doświadczenia turystycznego oraz wzajemny wpływ turystyki i kultury lokalnej.","wiki":[{"body":"Kultura odgrywa kluczową rolę w turystyce - wpływa na motywację podróżnych i rozwój destynacji. Jest jednym z głównych czynników przyciągających turystów oraz kształtującym dla nich doświadczeniem."},{"heading":"Kultura jako atrakcja i doświadczenie","bullets":["Kultura jako atrakcja - wiele osób podróżuje, by poznać dziedzictwo kulturowe; popularne są zabytki, muzea, festiwale, sztuka, muzyka, tradycje","Kultura jako element doświadczenia - turystyka kulturowa pozwala poznawać nowe języki, zwyczaje i style życia; lokalne potrawy, rękodzieło i obyczaje czynią podróż bardziej autentyczną"]},{"heading":"Wpływ turystyki na kulturę lokalną","bullets":["Pozytywny - wspieranie zachowania i promocji dziedzictwa; dochody finansują renowację zabytków i wydarzenia kulturowe","Negatywny - konflikty społeczne, zanikanie autentyczności (kultura na pokaz), komercjalizacja pod turystów"]},{"heading":"Kultura a zrównoważona turystyka","bullets":["Ochrona lokalnych tradycji i dziedzictwa jest kluczowa dla zrównoważonego rozwoju","Edukacja turystów w zakresie poszanowania miejscowej kultury pomaga zachować jej unikalny charakter"]}],"questions":[{"type":"abcd","q":"Który przykład ilustruje kulturę jako atrakcję turystyczną?","options":["Darmowe wi-fi w hotelu","Transfer z lotniska","Zabytki, muzea, festiwale, sztuka i tradycje","Ubezpieczenie podróży"],"correct":2,"explain":"Popularne atrakcje kulturowe to zabytki, muzea, festiwale, sztuka, muzyka i tradycje - to one przyciągają turystów."},{"type":"tf","q":"Rozwój turystyki zawsze wzmacnia autentyczność kultury lokalnej i nie niesie żadnych zagrożeń.","correct":false,"explain":"Turystyka może też komercjalizować kulturę i osłabiać jej autentyczność (kultura „robi się na pokaz”) oraz wywoływać konflikty społeczne."},{"type":"flash","front":"Jakie znaczenie odgrywa kultura w turystyce?","back":"Jest atrakcją przyciągającą turystów (zabytki, festiwale, tradycje) i elementem doświadczenia (języki, potrawy, zwyczaje); turystyka wzajemnie wpływa na kulturę lokalną - wspiera dziedzictwo, ale może je komercjalizować. Ochrona tradycji i edukacja turystów wspierają zrównoważony rozwój."}]},{"id":"ocena-wydolnosci-fizycznej","track":"wszyscy","category":"fizjologia","number":28,"title":"Sposoby oceny wydolności fizycznej","summary":"Wydolność fizyczną ocenia się metodami laboratoryjnymi i terenowymi, mierząc m.in. VO2max, tętno i parametry beztlenowe.","wiki":[{"heading":"Czym jest wydolność fizyczna","body":"Wydolność fizyczna to zdolność organizmu do wykonywania wysiłku o określonej intensywności i czasie trwania bez nadmiernego zmęczenia oraz z możliwością szybkiej regeneracji. Ocenia się ją metodami laboratoryjnymi i terenowymi."},{"heading":"Metody laboratoryjne (bezpośrednie)","body":"Najdokładniejsze, prowadzone w warunkach kontrolowanych przy użyciu specjalistycznego sprzętu (bieżnia, cykloergometr).","bullets":["Pomiar VO2max - maksymalna ilość tlenu, jaką organizm może pobrać, przetransportować i zużyć; najlepszy wskaźnik wydolności tlenowej","Test progowy (próg mleczanowy) - ocena stężenia mleczanu we krwi przy rosnącej intensywności","Ergometria wysiłkowa - bieżnia, cykloergometr, ergometr wioślarski; ocena tętna, ciśnienia, EKG, poboru tlenu","CPET (sercowo-płucny test wysiłkowy), spirometria, EKG wysiłkowe"]},{"heading":"Testy terenowe i metody pośrednie","body":"Łatwiejsze i tańsze do przeprowadzenia; metody pośrednie szacują VO2max na podstawie reakcji tętna.","bullets":["Test Coopera - bieg przez 12 min, mierzony dystans; im większy, tym lepsza wydolność","Test Ruffiera - tętno przed wysiłkiem, po 30 przysiadach i po minucie odpoczynku","Test Astranda - cykloergometr, obciążenie submaksymalne, ocena na podstawie tętna","Test Harwardzki - wchodzenie i schodzenie ze stopnia, analiza szybkości powrotu tętna"]},{"heading":"Wydolność beztlenowa i ocena subiektywna","bullets":["Test Wingate - 30 s maksymalnego wysiłku na cykloergometrze; ocenia moc maksymalną, pojemność beztlenową i odporność na zmęczenie","Próg przemian beztlenowych - inwazyjnie (pomiar mleczanu), nieinwazyjnie (test Conconiego, próg wentylacji)","Skala Borga - subiektywna ocena odczuwanego zmęczenia podczas wysiłku"]}],"questions":[{"type":"abcd","q":"Który test polega na przebiegnięciu jak najdłuższego dystansu w ciągu 12 minut?","options":["Test Ruffiera","Test Astranda","Test Wingate","Test Coopera"],"correct":3,"explain":"Test Coopera to bieg przez 12 minut, w którym mierzy się pokonany dystans pozwalający oszacować VO2max."},{"type":"tf","q":"VO2max jest uznawany za najlepszy wskaźnik wydolności tlenowej.","correct":true,"explain":"VO2max określa największą ilość tlenu, jaką organizm może pobrać i zużyć, i jest najlepszym wskaźnikiem wydolności aerobowej."},{"type":"tf","q":"Test Wingate służy do oceny wydolności tlenowej (aerobowej).","correct":false,"explain":"Test Wingate (30 s maksymalnego wysiłku) ocenia wydolność beztlenową: moc maksymalną, pojemność beztlenową i odporność na zmęczenie."},{"type":"flash","front":"Wymień i scharakteryzuj sposoby oceny wydolności fizycznej.","back":"Metody laboratoryjne (VO2max, próg mleczanowy, ergometria, CPET); testy terenowe (Cooper, Ruffier, Astrand, Harwardzki); ocena parametrów fizjologicznych (tętno, ciśnienie, czas regeneracji); wydolność beztlenowa (test Wingate); ocena subiektywna (skala Borga)."}]},{"id":"typy-wykresow-dochod-firmy","track":"wszyscy","category":"technologie","number":29,"title":"Trzy typy wykresów do prezentacji dochodu firmy w 5 kolejnych latach","summary":"Dochód firmy w czasie najlepiej prezentują wykres kolumnowy, liniowy oraz kołowy (do proporcji).","wiki":[{"heading":"Typy wykresów","bullets":["Wykres kolumnowy (słupkowy) - przedstawia dochód jako pionowe lub poziome słupki, których wysokość odpowiada wartości w danym roku; czytelny, ułatwia porównanie danych","Wykres liniowy - prezentuje zmiany dochodu w czasie linią łączącą punkty z kolejnych lat; przydatny do analizy trendów, wzrostu lub spadku","Wykres kołowy (pierścieniowy) - pokazuje procentowy udział dochodu z każdego roku w dochodzie całkowitym; sprawdza się gdy chcemy zobrazować proporcje zamiast zmian w czasie"]}],"questions":[{"type":"abcd","q":"Który wykres jest najlepszy do analizy trendu wzrostu lub spadku dochodu w czasie?","options":["Wykres kołowy","Wykres liniowy","Wykres pierścieniowy","Wykres bąbelkowy"],"correct":1,"explain":"Wykres liniowy łączy punkty z kolejnych lat, dzięki czemu dobrze obrazuje trendy oraz wzrost i spadek dochodu."},{"type":"tf","q":"Wykres liniowy najlepiej nadaje się do pokazania procentowego udziału dochodów poszczególnych lat w dochodzie całkowitym.","correct":false,"explain":"Do proporcji (udziału w całości) służy wykres kołowy; wykres liniowy obrazuje zmiany wartości w czasie, a nie udziały procentowe."},{"type":"flash","front":"Wymień 3 typy wykresów do prezentacji dochodu firmy w 5 kolejnych latach.","back":"Wykres kolumnowy (słupkowy), wykres liniowy oraz wykres kołowy (pierścieniowy)."}]},{"id":"redukcja-stresu-rekreacja-turystyka","track":"wszyscy","category":"rekreacja","number":30,"title":"Radzenie sobie ze stresem przez działalność rekreacyjno-turystyczną","summary":"Aktywność rekreacyjno-turystyczna obniża poziom stresu poprzez ruch, kontakt z naturą, zmianę otoczenia i relacje społeczne.","wiki":[{"heading":"Rekreacja i turystyka jako forma redukcji stresu","body":"Stres jest naturalną reakcją organizmu, ale jego nadmiar prowadzi do problemów zdrowotnych i psychicznych. Aktywność rekreacyjno-turystyczna umożliwia odpoczynek, regenerację i oderwanie od codziennych obowiązków.","bullets":["Aktywność fizyczna (spacery, pływanie, jazda na rowerze) obniża poziom kortyzolu i poprawia samopoczucie","Kontakt z naturą (góry, las, morze) działa uspokajająco i zmniejsza napięcie psychiczne","Zmiana otoczenia pozwala oderwać się od stresujących sytuacji","Społeczny aspekt turystyki (wyjazdy z rodziną, znajomymi) wzmacnia relacje międzyludzkie"]},{"heading":"Formy pomagające w redukcji stresu","bullets":["Rekreacja ruchowa - bieganie, joga, fitness, siłownia pobudzają wydzielanie endorfin","Turystyka wypoczynkowa - morze, uzdrowiska, spa - relaks i regeneracja","Turystyka aktywna - wędrówki górskie, kajakarstwo, nurkowanie wymagają skupienia","Turystyka kulturowa - muzea, koncerty, festiwale jako źródło przyjemności"]},{"heading":"Korzyści psychofizyczne","bullets":["Lepsza odporność na stres dzięki regularnej aktywności","Poprawa jakości snu - ruch na świeżym powietrzu wspomaga regenerację","Wzrost poziomu energii i motywacji"]}],"questions":[{"type":"abcd","q":"Jaki efekt fizjologiczny daje aktywność fizyczna w kontekście redukcji stresu?","options":["Podnosi poziom kortyzolu","Pogarsza jakość snu","Zwiększa napięcie psychiczne","Obniża poziom kortyzolu"],"correct":3,"explain":"Aktywność fizyczna obniża poziom kortyzolu (hormonu stresu) i poprawia samopoczucie."},{"type":"tf","q":"Kontakt z naturą podczas turystyki działa uspokajająco i zmniejsza napięcie psychiczne.","correct":true,"explain":"Przebywanie w górach, lesie czy nad morzem działa uspokajająco i redukuje napięcie psychiczne."},{"type":"flash","front":"Jakie korzyści psychofizyczne daje aktywność rekreacyjno-turystyczna?","back":"Lepsza odporność na stres, poprawa jakości snu (ruch na świeżym powietrzu wspomaga regenerację) oraz wzrost poziomu energii i motywacji."}]},{"id":"podzial-pozycji-wyjsciowych","track":"wszyscy","category":"fizjologia","number":31,"title":"Podział pozycji wyjściowych do ćwiczeń kształtujących","summary":"Pozycje wyjściowe dzieli się na wysokie, półwysokie, niskie, izolowane i równoważne.","wiki":[{"heading":"Podział podstawowy","bullets":["Pozycje wysokie - pozycje w staniu oraz we wspięciu (np. postawa, wykrok, rozkrok, wypady, pozycje wspięte)","Pozycje półwysokie - półprzysiady, przysiady, klęki (np. przysiad obunóż, klęk prosty, klęk podparty)","Pozycje niskie - siady, podpory, leżenia (np. siad prosty, siad skrzyżny, podpór leżąc, leżenie tyłem)"]},{"heading":"Pozycje specjalne","bullets":["Pozycje izolowane - ruch odbywa się w jednym stawie i angażuje jedną grupę mięśniową przy minimalnym udziale innych mięśni (np. pozycja w siadzie skrzyżnym)","Pozycje równoważne - wymagają współdziałania całego ciała i układu ruchowego w celu zachowania równowagi"]}],"questions":[{"type":"abcd","q":"Do której grupy pozycji wyjściowych zaliczamy siady, podpory i leżenia?","options":["Pozycje wysokie","Pozycje niskie","Pozycje półwysokie","Pozycje równoważne"],"correct":1,"explain":"Pozycje niskie obejmują siady, podpory i leżenia."},{"type":"tf","q":"Pozycje izolowane to takie, w których ruch odbywa się w wielu stawach jednocześnie i angażuje wiele grup mięśniowych.","correct":false,"explain":"Odwrotnie — w pozycjach izolowanych ruch odbywa się w jednym stawie i angażuje jedną grupę mięśniową; praca wielu stawów cechuje ćwiczenia złożone (wielostawowe)."},{"type":"flash","front":"Dokonaj podziału pozycji wyjściowych do ćwiczeń kształtujących.","back":"Pozycje wysokie (stanie, wspięcie), półwysokie (półprzysiady, przysiady, klęki), niskie (siady, podpory, leżenia), izolowane (ruch w jednym stawie) oraz równoważne (współdziałanie całego ciała dla zachowania równowagi)."}]},{"id":"funkcje-dysfunkcje-turystyki","track":"wszyscy","category":"turystyka","number":32,"title":"Funkcje i dysfunkcje współczesnej turystyki","summary":"Turystyka pełni m.in. funkcje wypoczynkową, zdrowotną, edukacyjną i ekonomiczną, ale powoduje też dysfunkcje, jak przeludnienie i wzrost cen.","wiki":[{"heading":"Funkcje turystyki","body":"Turystyka jako zjawisko społeczne i gospodarcze przyczynia się do rozwoju społecznego, kulturalnego i ekonomicznego.","bullets":["Wypoczynkowa - odpoczynek od obowiązków i regeneracja","Zdrowotna - poprawa stanu zdrowia turystów","Edukacyjna i kulturowa - poszerzanie wiedzy o kulturach, tradycjach, zwyczajach","Wychowawcza - rozwija odpowiedzialność i umiejętność współpracy w grupie","Ekonomiczna - generuje dochody, tworzy miejsca pracy, stymuluje lokalne gospodarki","Urbanistyczna/miastotwórcza, polityczna, etniczna oraz ekologiczna"]},{"heading":"Dysfunkcje turystyki","body":"Rozwój turystyki niesie również negatywne skutki dla środowiska i społeczeństwa.","bullets":["Przeludnienie popularnych miejsc - tłok, hałas, problemy z infrastrukturą","Wzrost cen towarów, usług i mieszkań uciążliwy dla mieszkańców","Uzależnienie lokalnej gospodarki od turystyki (wrażliwość na kryzysy)","Degradacja kultury - tradycje stają się pokazami dla turystów i tracą autentyczność","Zjawiska patologiczne (alkoholizm, prostytucja) oraz konflikty społeczne"]}],"questions":[{"type":"abcd","q":"Która z poniższych jest dysfunkcją, a nie funkcją turystyki?","options":["Funkcja zdrowotna","Funkcja edukacyjna","Degradacja kultury","Funkcja ekonomiczna"],"correct":2,"explain":"Degradacja kultury (utrata autentyczności tradycji) to dysfunkcja; pozostałe to funkcje turystyki."},{"type":"tf","q":"Uzależnienie lokalnej gospodarki wyłącznie od turystyki czyni ją wrażliwą na kryzysy.","correct":true,"explain":"Gdy gospodarka opiera się głównie na turystyce, kryzys może bardzo negatywnie wpłynąć na region - to dysfunkcja turystyki."},{"type":"flash","front":"Wymień funkcje współczesnej turystyki.","back":"Wypoczynkowa, zdrowotna, edukacyjna i kulturowa, wychowawcza, ekonomiczna, urbanistyczna/miastotwórcza, polityczna, etniczna i ekologiczna."}]},{"id":"trendy-tworzenia-stron-www","track":"wszyscy","category":"technologie","number":33,"title":"Obecne trendy przy tworzeniu stron internetowych","summary":"Współczesne strony stawiają na dostępność, szybkość, minimalizm, podejście mobile-first, AI i intuicyjną nawigację.","wiki":[{"heading":"Najważniejsze trendy","body":"Strony internetowe coraz bardziej skupiają się na wygodzie użytkownika, aby były łatwe, szybkie i przyjemne w obsłudze.","bullets":["Projektowanie z myślą o dostępności - zrozumiałe dla wszystkich, w tym osób z niepełnosprawnościami","Szybkość działania - użytkownicy oczekują szybkiego ładowania strony","Minimalistyczny wygląd z trybem ciemnym - większa czytelność, lepszy dla oczu, oszczędza baterię","Personalizacja i AI - chatboty, spersonalizowane rekomendacje, dynamiczne treści"]},{"heading":"Pozostałe trendy","bullets":["Efekty 3D i animacja - ruchome elementy przyciągające uwagę","Projektowanie mobile-first - najpierw smartfony, potem komputery","Prosta nawigacja i menu rozwijane (np. hamburger, menu pełnoekranowe)","Wysokiej jakości, autorskie materiały graficzne zamiast standardowych zdjęć","Powiadomienia push - z możliwością ich wyłączenia"]}],"questions":[{"type":"abcd","q":"Co oznacza podejście mobile-first przy tworzeniu stron internetowych?","options":["Tworzenie osobnej aplikacji zamiast strony","Strona dostępna tylko na komputerach","Rezygnacja z wersji mobilnej","Strona tworzona najpierw z myślą o smartfonach, a potem dopasowana do komputerów"],"correct":3,"explain":"Mobile-first oznacza projektowanie najpierw pod smartfony, a następnie dopasowanie do komputerów, bo coraz więcej osób przegląda internet przez telefon."},{"type":"tf","q":"Tryb ciemny jest obecnie popularnym trendem, ponieważ jest lepszy dla oczu i oszczędza baterię.","correct":true,"explain":"Minimalistyczny wygląd z trybem ciemnym poprawia czytelność, jest łagodniejszy dla oczu i oszczędza baterię."},{"type":"flash","front":"Wymień obecne trendy przy tworzeniu stron internetowych.","back":"Dostępność, szybkość działania, minimalizm z trybem ciemnym, personalizacja i AI, efekty 3D i animacje, mobile-first, prosta nawigacja (menu rozwijane), autorskie materiały graficzne, powiadomienia push."}]},{"id":"metody-badania-rynku-turystycznego","track":"wszyscy","category":"marketing","number":35,"title":"Metody i techniki badania rynku turystycznego","summary":"Rynek turystyczny bada się metodami ilościowymi i jakościowymi, w oparciu o dane pierwotne i wtórne.","wiki":[{"heading":"Istota badań","body":"Badanie rynku turystycznego to proces zbierania informacji o konkurencji i turystach, ich potrzebach, zachowaniach i oczekiwaniach."},{"heading":"Badania ilościowe","body":"Celem jest uzyskanie konkretnych, liczbowych danych, które można analizować statystycznie.","bullets":["Ankiety i kwestionariusze (pytania zamknięte, skale ocen; online, telefonicznie, osobiście)","Badania opinii turystów (formularze oceny usług)","Badania popytu turystycznego (liczba turystów, cel podróży, długość pobytu, wydatki)","Zalety: duża próba, możliwość wnioskowania statystycznego. Wady: nie pokazują motywów i emocji turystów"]},{"heading":"Badania jakościowe","body":"Celem jest zrozumienie motywacji, potrzeb, opinii i zachowań turystów; dane opisowe, mniejsza liczba osób.","bullets":["Wywiady pogłębione - indywidualne rozmowy z uczestnikami rynku","Grupy fokusowe - dyskusje w małych grupach o usługach i preferencjach","Obserwacja uczestnicząca - badacz angażuje się w działanie grupy","Zalety: głębokie zrozumienie zachowań. Wady: trudne do uogólnienia, wymagają czasu i zasobów"]},{"heading":"Źródła danych","bullets":["Badania pierwotne - dane zbierane samodzielnie od respondentów (ankieta, wywiad, obserwacja)","Badania wtórne - wykorzystanie istniejących danych, raportów, statystyk i publikacji"]}],"questions":[{"type":"abcd","q":"Która metoda należy do badań jakościowych rynku turystycznego?","options":["Grupa fokusowa","Ankieta zamknięta","Analiza danych liczbowych ze statystyk","Badanie popytu turystycznego"],"correct":0,"explain":"Grupa fokusowa to badanie jakościowe; pozostałe wymienione to metody ilościowe."},{"type":"tf","q":"Badania wtórne polegają na samodzielnym zbieraniu nowych danych w terenie, np. przez ankiety.","correct":false,"explain":"To opis badań pierwotnych; badania wtórne opierają się na już istniejących danych, raportach i statystykach."},{"type":"flash","front":"Omów podstawowe metody i techniki badania rynku turystycznego.","back":"Badania ilościowe (ankiety, badania opinii i popytu - dane liczbowe) oraz jakościowe (wywiady pogłębione, grupy fokusowe, obserwacja uczestnicząca - zrozumienie motywacji). Obie grupy prowadzi się jako badania pierwotne (zbierane samodzielnie) lub wtórne (istniejące dane)."}]},{"id":"zalozenia-metodyczne-rekreacja","track":"wszyscy","category":"rekreacja","number":36,"title":"Założenia metodyczne w rekreacji fizycznej - formy, metody i środki","summary":"Instruktor rekreacji wykorzystuje różne formy, metody nauczania i treningowe, środki oraz zasady metodyczne, by osiągnąć cele zajęć.","wiki":[{"heading":"Formy rekreacji fizycznej","body":"Założenie metodyczne to pomysł na to, jak poprowadzić zajęcia, by osiągnąć cel. Formy to rodzaje zajęć ruchowych poprawiających kondycję, zdrowie, samopoczucie i integrację.","bullets":["Formy organizacyjne: indywidualna (jogging), zespołowe (siatkówka), grupowe (fitness, taniec), masowe (biegi uliczne)","Formy dydaktyczne: zabawowa, naśladowcza, zadaniowa, improwizacyjna, ścisła, programowa, współzawodnictwo"]},{"heading":"Metody działania instruktora","bullets":["Metody nauczania czynności ruchowych: poglądowa (pokaz), słowa (objaśnienia), praktyczna (wykonywanie ćwiczeń)","Metody treningowe ciągłe: jednostajna (stała intensywność), zmienna (zmiana tempa)","Metody treningowe przerywane: interwałowa, powtórzeniowa, ekstensywna, intensywna","Metody socjotechniczne: informacyjna, poradnictwo, animacja, programowanie","Metody wychowawcze: wpływu osobistego, sytuacyjnego, społecznego, kierowania samowychowaniem"]},{"heading":"Środki w rekreacji fizycznej","body":"Narzędzia uatrakcyjniające i ułatwiające zajęcia.","bullets":["Sprzęt sportowy, muzyka, przestrzeń","Przyrządy intensyfikujące - hantle, stepy","Metody intensyfikacji - praca w parach, zmiany tempa, dodatkowe powtórzenia"]},{"heading":"Zasady metodyczne (dydaktyczne)","bullets":["Świadomość i aktywność - uczestnik wie po co ćwiczy i chce to robić","Systematyczność","Dostępność - dostosowanie do wieku i możliwości","Utrwalenie - powtarzanie dla lepszego zapamiętania","Wszechstronność - rozwój siły, wytrzymałości i zręczności"]}],"questions":[{"type":"abcd","q":"Do której grupy zalicza się metoda jednostajna i zmienna?","options":["Metody nauczania czynności ruchowych","Metody wychowawcze","Metody socjotechniczne","Metody treningowe ciągłe"],"correct":3,"explain":"Metoda jednostajna (stała intensywność) i zmienna (zmiana tempa) to metody treningowe ciągłe."},{"type":"tf","q":"Zasada dostępności oznacza dostosowanie zajęć do wieku i możliwości uczestników.","correct":true,"explain":"Zasada dostępności wymaga, by zajęcia były dostosowane do wieku i możliwości ćwiczących."},{"type":"flash","front":"Wymień metody działania instruktora rekreacji.","back":"Metody nauczania czynności ruchowych (poglądowa, słowa, praktyczna), metody treningowe (ciągłe: jednostajna, zmienna; przerywane: interwałowa, powtórzeniowa, ekstensywna, intensywna), metody socjotechniczne (informacyjna, poradnictwo, animacja, programowanie) oraz metody wychowawcze (wpływu osobistego, sytuacyjnego, społecznego, kierowania samowychowaniem)."}]},{"id":"uniwersalne-zasady-sporzadzania-listu","track":"wszyscy","category":"zarzadzanie","number":38,"title":"Uniwersalne zasady sporzadzania listu","summary":"Omowienie ukladu, stylu i jezyka oraz rodzajow listow.","wiki":[{"heading":"Uklad listu","body":"Poprawnie sporzadzony list ma stala, logiczna strukture, ktora porzadkuje przekaz.","bullets":["Naglowek - dane nadawcy oraz data","Adresat - imie, nazwisko lub nazwa firmy i adres","Zwrot grzecznosciowy - formalny (Szanowna Pani) lub nieformalny (Droga Anno, czesc)","Tresc - logiczna, podzielona na akapity, jasna i poprawna","Zakonczenie - podsumowanie, prosba o odpowiedz lub podziekowanie","Zwrot koncowy i podpis - formalny (Z wyrazami szacunku) lub nieformalny (pozdrawiam serdecznie)"]},{"heading":"Styl i jezyk","bullets":["Dostosowanie do odbiorcy - styl formalny lub nieformalny","Jasnosc i zwiezlosc - unikamy dygresji, mowimy konkretnie","Poprawnosc jezykowa - brak bledow ortograficznych i stylistycznych","Uprzejmosc - nawet w skargach zachowujemy uprzejmy i rzeczowy ton"]},{"heading":"Rodzaje listow","bullets":["Formalny - do urzedow i firm, oficjalny styl (list motywacyjny, reklamacje)","Nieformalny - do znajomych i rodziny, swobodny styl","Biznesowy - elementy formalne, ale bardziej elastyczny ton (oferta, podziekowania dla klienta)"]}],"questions":[{"type":"abcd","q":"Ktory element listu zawiera dane nadawcy oraz date?","options":["Adresat","Naglowek","Zwrot koncowy","Tresc"],"correct":1,"explain":"Naglowek listu zawiera dane nadawcy plus date."},{"type":"tf","q":"Nawet w listach ze skarga nalezy zachowac uprzejmy i rzeczowy ton.","correct":true,"explain":"Uprzejmosc to jedna z zasad stylu - obowiazuje takze w skargach."},{"type":"flash","front":"Wymien rodzaje listow.","back":"Formalny (urzedy, firmy), nieformalny (znajomi, rodzina) oraz biznesowy (elementy formalne, lecz bardziej elastyczny ton)."}]},{"id":"bariery-komunikacji-miedzykulturowej","track":"wszyscy","category":"zarzadzanie","number":41,"title":"Cechy charakteru i bariery wewnetrzne utrudniajace komunikacje miedzykulturowa","summary":"Cechy charakteru oraz bariery wewnetrzne uniemozliwiajace dobra komunikacje miedzykulturowa.","wiki":[{"heading":"Cechy charakteru utrudniajace komunikacje","bullets":["Egocentryzm - skupienie na sobie utrudnia dostrzeganie odmiennych sposobow wyrazania mysli, emocji i wartosci","Brak empatii - niezdolnosc do postawienia sie w sytuacji drugiej osoby ogranicza rozumienie jej perspektywy kulturowej","Niskie umiejetnosci spoleczne - trudnosci w nawiazywaniu relacji i adaptacji do nowych sytuacji kulturowych","Zamkniecie na zmiany - przywiazanie do jedynie slusznych norm utrudnia adaptacje do nowych kontekstow kulturowych"]},{"heading":"Bariery wewnetrzne","bullets":["Lek i niepewnosc - obawa przed niezrozumieniem lub byciem ocenianym prowadzi do wycofania z komunikacji","Stereotypy i uprzedzenia - automatyczne przypisywanie cech osobom z danej kultury prowadzi do bledow i konfliktow","Szok kulturowy - intensywne przezycia w nowej kulturze moga wywolac frustracje, lek i odrzucenie odmiennych norm","Brak samoswiadomosci i tozsamosci kulturowej - nieznajomosc wlasnych uwarunkowan utrudnia zrozumienie roznic","Etnocentryzm - przekonanie, ze wlasna kultura jest lepsza","Nietolerancja oraz brak kompetencji kulturowych"]}],"questions":[{"type":"abcd","q":"Jak nazywa sie przekonanie, ze wlasna kultura jest lepsza od innych?","options":["Etnocentryzm","Egocentryzm","Empatia","Sensualizm"],"correct":0,"explain":"Etnocentryzm to przekonanie o wyzszosci wlasnej kultury - bariera komunikacji miedzykulturowej."},{"type":"tf","q":"Brak empatii ulatwia zrozumienie perspektywy kulturowej drugiej osoby.","correct":false,"explain":"Przeciwnie - brak empatii ogranicza zrozumienie perspektywy kulturowej innej osoby."},{"type":"flash","front":"Czym jest szok kulturowy jako bariera komunikacji?","back":"Intensywne przezycia zwiazane z wejsciem w nowa kulture, ktore moga wywolac frustracje, lek i odrzucenie odmiennych norm."}]},{"id":"pozytywne-skutki-wielkich-odkryc-geograficznych","track":"wszyscy","category":"historia","number":42,"title":"Pozytywne skutki Epoki Wielkich Odkryc Geograficznych","summary":"Korzysci, jakie Epoka Wielkich Odkryc Geograficznych przyniosla swiatu i ludzkosci.","wiki":[{"heading":"Czym byly Wielkie Odkrycia Geograficzne","body":"Epoka Wielkich Odkryc Geograficznych (XV-XVII wiek) to okres dalekich wypraw morskich Europejczykow w celu poznania nowych ladow i znalezienia nowych szlakow handlowych. Najwazniejsi odkrywcy to m.in. Krzysztof Kolumb, Vasco da Gama oraz Ferdynand Magellan."},{"heading":"Wiedza, nauka i nawigacja","bullets":["Poznanie nowych kontynentow i oceanow oraz dokladniejsze mapowanie swiata","Udowodnienie mozliwosci oplyniecia Ziemi","Rozwoj kartografii, geografii i astronomii","Doskonalenie instrumentow nawigacyjnych (kompas, astrolabium) i budowy statkow"]},{"heading":"Gospodarka i wymiana","bullets":["Powstanie nowych szlakow handlowych laczacych Europe, Afryke, Azje i Ameryke","Rozwoj portow, miast handlowych i transportu morskiego","Wymiana kolumbijska - do Europy trafily ziemniaki, kukurydza, pomidory, kakao i tyton; do Ameryki konie, bydlo, pszenica i trzcina cukrowa","Wzrost produkcji zywnosci, ograniczenie glodu i wzrost liczby ludnosci","Pobudzenie kapitalizmu handlowego, bankowosci i podstaw gospodarki globalnej"]},{"heading":"Kontakty miedzykulturowe","body":"Mimo licznych konfliktow doszlo do poznawania nowych kultur i tradycji, wymiany wiedzy i doswiadczen oraz wzrostu zainteresowania roznorodnoscia swiata. Dzieki odkryciom swiat stal sie bardziej polaczony gospodarczo, kulturowo i komunikacyjnie, co stworzylo podstawy wspolczesnej globalizacji."}],"questions":[{"type":"abcd","q":"Ktore rosliny w ramach tzw. wymiany kolumbijskiej trafily do Europy?","options":["Pszenica i trzcina cukrowa","Len i konopie","Ryz i jeczmien","Ziemniaki i kukurydza"],"correct":3,"explain":"Do Europy trafily m.in. ziemniaki, kukurydza, pomidory, kakao i tyton; pszenice i trzcine cukrowa przywieziono do Ameryki."},{"type":"tf","q":"Wielkie odkrycia geograficzne przyczynily sie do rozwoju kapitalizmu handlowego i podstaw gospodarki globalnej.","correct":true,"explain":"Odkrycia pobudzily kapitalizm handlowy, bankowosc i stworzyly podstawy gospodarki globalnej."},{"type":"flash","front":"Wymien trzech najwazniejszych odkrywcow Epoki Wielkich Odkryc Geograficznych.","back":"Krzysztof Kolumb, Vasco da Gama oraz Ferdynand Magellan."}]},{"id":"zasady-zachowania-zdrowia","track":"wszyscy","category":"zywienie","number":43,"title":"Glowne zasady zachowania zdrowia","summary":"Najwazniejsze zasady sluzace zachowaniu zdrowia fizycznego i psychicznego.","wiki":[{"heading":"Czym jest zdrowie","body":"Zdrowie to pelny dobrostan fizyczny, psychiczny i spoleczny, a nie tylko brak choroby lub niepelnosprawnosci. Czlowiek zdrowy nie tylko nie choruje, ale tez dobrze sie czuje, ma energie, sprawnie funkcjonuje w spoleczenstwie i radzi sobie z codziennymi wyzwaniami."},{"heading":"Glowne zasady","bullets":["Zdrowe odzywianie - warzywa i owoce, unikanie fast foodow, slodyczy i nadmiaru soli, picie 1,5-2 l wody dziennie, regularne posilki (3-5 razy dziennie)","Sen i odpoczynek - 7-9 h snu dla doroslych, 8-10 h dla mlodziezy; sen wspomaga regeneracje i zdrowie psychiczne","Aktywnosc fizyczna - co najmniej 30 min dziennie; poprawia krazenie, odpornosc, nastroj i kondycje","Unikanie uzywek - alkohol, papierosy i inne srodki szkodza zdrowiu fizycznemu i psychicznemu","Higiena osobista - mycie rak, codzienna kapiel, czyste ubrania, dbanie o otoczenie","Zdrowie psychiczne - radzenie sobie ze stresem, wspierajace relacje, rozwijanie pasji","Profilaktyka zdrowotna - regularne wizyty u lekarza i stomatologa, badania okresowe, szczepienia ochronne"]}],"questions":[{"type":"abcd","q":"Ile wody dziennie zaleca sie wypijac w ramach zdrowego odzywiania?","options":["okolo 1,5-2 l","okolo 0,5 l","okolo 3-4 l","okolo 5 l"],"correct":0,"explain":"Zaleca sie picie okolo 1,5-2 l wody dziennie."},{"type":"tf","q":"Doroslym zaleca sie 4-5 godzin snu na dobe.","correct":false,"explain":"Zalecane jest 7-9 h snu dla doroslych (a dla mlodziezy 8-10 h); 4-5 h to zbyt malo dla zdrowia."},{"type":"flash","front":"Podaj minimalna dzienna dawke aktywnosci fizycznej wedlug zasad zachowania zdrowia.","back":"Co najmniej 30 minut dziennie (np. spacer, jazda na rowerze, plywanie, taniec)."}]},{"id":"zrodla-informacji-geograficzno-turystycznej-mapy","track":"wszyscy","category":"turystyka","number":44,"title":"Zrodla informacji geograficzno-turystycznej i znaczenie map","summary":"Rodzaje zrodel informacji turystycznej oraz znaczenie map w badaniach srodowiska i dzialalnosci turystyczno-rekreacyjnej.","wiki":[{"heading":"Zrodla informacji geograficzno-turystycznej","bullets":["Mapy i atlasy turystyczne - ukształtowanie terenu, szlaki, obiekty przyrodnicze i kulturowe","Przewodniki turystyczne - opisy atrakcji, szlakow, propozycje tras, informacje praktyczne","Informatory i foldery - krotkie broszury promujace region, wydarzenia i miejsca","Internet - strony, blogi podroznicze, aplikacje (Google Maps, Booking, TripAdvisor)","Lokalne centra informacji turystycznej - aktualne dane i materialy promocyjne","Filmy dokumentalne i programy podroznicze - krajobraz, kultura i przyroda","Dane statystyczne i raporty - ruch turystyczny, liczba turystow, wplyw na srodowisko"]},{"heading":"Znaczenie map w badaniach srodowiska geograficznego","bullets":["Orientacja w terenie - planowanie trasy, polozenie atrakcji, wyznaczenie kierunku","Analiza srodowiska - mapy topograficzne, klimatyczne i hydrograficzne pozwalaja badac cechy srodowiska","Bezpieczenstwo - unikanie trudnych lub niebezpiecznych terenow, szczegolnie w gorach i lasach","Planowanie infrastruktury - projektowanie szlakow pieszych, rowerowych, miejsc wypoczynkowych","Lokalizacja atrakcji i infrastruktury - rozmieszczenie hoteli, restauracji, zabytkow"]},{"heading":"Znaczenie map w dzialalnosci turystyczno-rekreacyjnej","bullets":["Ulatwiaja nawigacje, szczegolnie w gorach, lasach i terenach nieznanych","Pomagaja odkryc nowe, mniej znane atrakcje","Wspieraja rozwoj ekoturystyki - tworzenie tras zgodnych z ochrona przyrody","Pomagaja w promocji regionow - sa uzywane w kampaniach informacyjnych i marketingowych"]}],"questions":[{"type":"abcd","q":"Ktory rodzaj map sluzy do badania cech srodowiska przyrodniczego?","options":["Mapy polityczne","Mapy topograficzne, klimatyczne i hydrograficzne","Mapy administracyjne","Mapy drogowe miast"],"correct":1,"explain":"Mapy tematyczne - topograficzne, klimatyczne i hydrograficzne - pozwalaja badac cechy srodowiska przyrodniczego."},{"type":"tf","q":"Lokalne centra informacji turystycznej sa jednym ze zrodel informacji geograficzno-turystycznej.","correct":true,"explain":"Lokalne centra informacji turystycznej dostarczaja aktualne dane i materialy promocyjne."},{"type":"flash","front":"Wymien co najmniej trzy zrodla informacji geograficzno-turystycznej.","back":"M.in. mapy i atlasy, przewodniki turystyczne, informatory i foldery, Internet, lokalne centra informacji turystycznej, filmy dokumentalne, dane statystyczne i raporty."}]},{"id":"wartosci-zdrowotne-gier-terenowych-bieg-na-orientacje","track":"wszyscy","category":"fizjologia","number":45,"title":"Wartosci zdrowotne i edukacyjne gier terenowych na przykladzie biegu na orientacje","summary":"Wartosci zdrowotne, edukacyjne oraz wielostronne oddzialywanie biegu na orientacje na organizm rekreanta i turysty.","wiki":[{"heading":"Przyklad: bieg na orientacje","body":"Bieg na orientacje to popularna na calym swiecie gra sportowo-rekreacyjna, polegajaca na odnalezieniu wyznaczonych punktow kontrolnych w terenie przy pomocy mapy i kompasu. Moze byc rozgrywana indywidualnie lub w zespolach - w lesie, parku, gorach czy terenie miejskim."},{"heading":"Wartosci zdrowotne","bullets":["Rozwijanie kondycji fizycznej - bieganie lub szybki marsz w zroznicowanym terenie","Poprawa wydolnosci oddechowo-krazeniowej, sily i koordynacji","Dotlenienie organizmu - aktywnosc na swiezym powietrzu","Zmniejszenie stresu i napiecia psychicznego - kontakt z natura dziala uspokajajaco"]},{"heading":"Wartosci edukacyjne","bullets":["Nauka orientacji w terenie","Myslenie przestrzenne i szybkie podejmowanie decyzji","Poznawanie srodowiska geograficznego i przyrodniczego","Samodzielnosc i odpowiedzialnosc - uczestnik sam planuje trase i tempo"]},{"heading":"Wielostronne oddzialywanie na organizm","bullets":["Fizyczne - poprawa sprawnosci ogolnej, rownowagi i refleksu","Psychiczne - rozwoj koncentracji, logicznego myslenia i odpornosci na stres","Spoleczne - integracja w grupie i zdrowa rywalizacja (w wersjach druzynowych)","Emocjonalne - poczucie przygody, adrenalina, satysfakcja z ukonczenia trasy"]}],"questions":[{"type":"abcd","q":"Za pomoca jakich narzedzi rekreant odnajduje punkty kontrolne w biegu na orientacje?","options":["Telefonu i zegarka","Lornetki i busoli satelitarnej","Mapy i kompasu","Wylacznie znakow szlaku"],"correct":2,"explain":"Bieg na orientacje polega na odnalezieniu punktow kontrolnych przy pomocy mapy i kompasu."},{"type":"tf","q":"Bieg na orientacje moze byc rozgrywany wylacznie indywidualnie.","correct":false,"explain":"Moze byc rozgrywany indywidualnie lub w zespolach, w roznych typach terenu."},{"type":"flash","front":"Wymien obszary wielostronnego oddzialywania biegu na orientacje na organizm.","back":"Fizyczne, psychiczne, spoleczne oraz emocjonalne."}]},{"id":"epoki-historyczne-chronologicznie","track":"wszyscy","category":"historia","number":46,"title":"Epoki historyczne w ukladzie chronologicznym - kultura i sztuka","summary":"Chronologiczny przeglad epok historycznych wraz z osiagnieciami i przemianami w kulturze i sztuce.","wiki":[{"heading":"Od prehistorii do starozytnosci","bullets":["Prehistoria (do ok. 4000-3500 p.n.e.) - rewolucja neolityczna, malarstwo jaskiniowe (Lascaux, Altamira), wenus paleolityczne, architektura megalityczna (Stonehenge)","Starozytnosc (do 476 n.e.) - wynalezienie pisma, demokracja i filozofia w Grecji, prawo rzymskie; piramidy w Gizie, greckie porzadki architektoniczne, rzymski beton (Panteon, Koloseum)"]},{"heading":"Sredniowiecze, renesans, barok","bullets":["Sredniowiecze (476-1453/1492) - teocentryzm, scholastyka, pierwsze uniwersytety; styl romanski i gotycki (sklepienie krzyzowo-zebrowe, witraze)","Renesans (XV-XVI w.) - humanizm i antropocentryzm, druk Gutenberga, heliocentryzm Kopernika; perspektywa linearna, Leonardo da Vinci, Michal Aniol, Rafael","Barok (koniec XVI - polowa XVIII w.) - kontrreformacja, dynamizm i swiatlocien (Caravaggio), opera Monteverdiego, Bernini, Rembrandt, Rubens"]},{"heading":"Oswiecenie, romantyzm, pozytywizm","bullets":["Oswiecenie (XVIII w.) - \"wiek rozumu\", racjonalizm, Wielka Rewolucja Francuska (1789); rokoko i klasycyzm, Mozart, Haydn, bajki Krasickiego","Romantyzm (koniec XVIII - polowa XIX w.) - bunt przeciw racjonalizmowi, kult jednostki, mesjanizm; Mickiewicz, Slowacki, Chopin, neogotyk","Pozytywizm i realizm (2. polowa XIX w.) - scjentyzm, ewolucjonizm, praca u podstaw; powiesc realistyczna (Prus, Sienkiewicz), narodziny impresjonizmu (Monet)"]},{"heading":"Modernizm i wspolczesnosc","bullets":["Przelom wiekow / Mloda Polska (ok. 1890-1918) - dekadentyzm, Nietzsche, psychoanaliza Freuda; symbolizm, secesja (Klimt, Mucha)","Dwudziestolecie miedzywojenne (1918-1939) - awangarda: kubizm, futuryzm, dadaizm, surrealizm, abstrakcjonizm; funkcjonalizm (Bauhaus)","Wspolczesnosc (od 1939) - kryzys humanizmu, rewolucja cyfrowa, postmodernizm; pop-art (Warhol), konceptualizm, happening i performance"]}],"questions":[{"type":"abcd","q":"Ktora epoka nazywana jest \"wiekiem rozumu\" i wiaze sie z Wielka Rewolucja Francuska?","options":["Oswiecenie","Barok","Renesans","Romantyzm"],"correct":0,"explain":"Oswiecenie (XVIII w.) nazywano \"wiekiem rozumu\"; doprowadzilo m.in. do Wielkiej Rewolucji Francuskiej (1789)."},{"type":"tf","q":"Cecha charakterystyczna sredniowiecza byl antropocentryzm.","correct":false,"explain":"Sredniowiecze cechowal teocentryzm (Bog osrodkiem wszystkiego); antropocentryzm — czlowiek w centrum — to cecha renesansu."},{"type":"flash","front":"Wymien chronologicznie epoki od renesansu do dwudziestolecia miedzywojennego.","back":"Renesans, barok, oswiecenie, romantyzm, pozytywizm i realizm, Mloda Polska (modernizm), dwudziestolecie miedzywojenne."}]},{"id":"rekreacyjne-rodzaje-koszykowki","track":"wszyscy","category":"fizjologia","number":47,"title":"Rekreacyjne rodzaje koszykowki","summary":"Charakterystyka podstawowych rekreacyjnych odmian koszykowki wraz z ich zasadami.","wiki":[{"heading":"Wprowadzenie","body":"Koszykowka to dynamiczna gra zespolowa, ktora doczekala sie wielu rekreacyjnych odmian. Ich celem jest uproszczenie zasad, zwiekszenie dostepnosci oraz umozliwienie gry w mniejszych grupach i na ograniczonej przestrzeni."},{"heading":"Streetball (koszykowka uliczna 3x3)","bullets":["Najbardziej znana rekreacyjna odmiana koszykowki","Gra najczesciej na polowie boiska","Zespoly po 3 zawodnikow na boisku (moga byc rezerwowi)","Gra do 21 punktow lub przez okreslony czas","Rzut z dystansu (zza luku 6,75 m) za 2 punkty, inne rzuty 1 punkt","Po zdobyciu punktu druzyna przeciwna wyprowadza pilke z linii za lukiem","Gra jest bardziej dynamiczna i mniej formalna niz tradycyjna koszykowka"]},{"heading":"Koszykowka 1x1","bullets":["Gra indywidualna - jeden zawodnik przeciwko drugiemu","Skupienie na technice i umiejetnosciach indywidualnych","Gra do okreslonej liczby punktow","Mozliwe zasady: \"kto zdobywa punkt, ten zostaje z pilka\" lub zamiana","Rzuty punktowane wedlug ustalen graczy (1 lub 2 pkt)"]},{"heading":"Horse (gra w konia)","bullets":["Gra polega na nasladowaniu ruchow przeciwnika","Idealna dla dwoch lub wiecej graczy","Pierwszy gracz wykonuje dowolny rzut","Kto nie trafi, dostaje kolejna litere ze slowa HORSE","Przegrywa gracz, ktory pierwszy uzbiera cale slowo"]}],"questions":[{"type":"abcd","q":"Ilu zawodnikow gra na boisku w jednej druzynie w streetballu?","options":["2","4","3","5"],"correct":2,"explain":"Streetball to koszykowka 3x3 - po 3 zawodnikow na boisku w kazdej druzynie."},{"type":"tf","q":"W grze Horse przegrywa gracz, ktory jako pierwszy uzbiera cale slowo HORSE.","correct":true,"explain":"Za kazdy nietrafiony rzut gracz dostaje litere; przegrywa ten, kto pierwszy uzbiera cale slowo HORSE."},{"type":"flash","front":"Wymien trzy podstawowe rekreacyjne rodzaje koszykowki.","back":"Streetball (3x3), koszykowka 1x1 oraz Horse (gra w konia)."}]},{"id":"globalizacja-turystyka","track":"wszyscy","category":"turystyka","number":49,"title":"Proces globalizacji w turystyce, hotelarstwie i rekreacji","summary":"Globalizacja zbliża gospodarki i społeczeństwa, zwiększając dostępność i standaryzację usług turystycznych, hotelarskich i rekreacyjnych.","wiki":[{"heading":"Czym jest globalizacja","body":"Globalizacja to proces postępującego zbliżania się społeczeństw i gospodarek świata w wyniku rozwoju technologii, transportu, komunikacji i międzynarodowej współpracy. Obejmuje m.in. swobodny przepływ ludzi, towarów, informacji, kapitału i usług."},{"heading":"Globalizacja w turystyce","bullets":["Zwiększenie dostępności podróży (tanie loty, internetowe biura podróży)","Rozszerzenie oferty turystycznej na cały świat (egzotyka, nowe kierunki)","Wzrost liczby podróży międzynarodowych (turystyka masowa i indywidualna)","Standaryzacja stylów życia i oczekiwań turystów (np. all inclusive)","Rozwój globalnych marek (TUI, Booking) i rezerwacji online"]},{"heading":"Globalizacja w hotelarstwie","bullets":["Powstawanie sieci hotelowych działających globalnie (Marriott, Hilton)","Standaryzacja usług i wyposażenia hoteli na całym świecie","Wzrost konkurencji i dostępu do informacji (portale z recenzjami)","Automatyzacja usług (check-in online)"]},{"heading":"Globalizacja w rekreacji","bullets":["Wymiana form rekreacyjnych między krajami (joga, fitness, sporty ekstremalne)","Rozwój globalnych wydarzeń sportowo-rekreacyjnych (maratony, festiwale)","Nowe technologie rekreacyjne dostępne globalnie (aplikacje terenowe, fitness)","Wzrost znaczenia zdrowego stylu życia"]}],"questions":[{"type":"abcd","q":"Który przykład najlepiej ilustruje globalizację w hotelarstwie?","options":["Lokalna gospoda serwująca tylko dania regionalne","Powstawanie globalnych sieci hotelowych jak Marriott czy Hilton","Spadek liczby podróży międzynarodowych","Zanik standaryzacji usług hotelowych"],"correct":1,"explain":"Globalizacja w hotelarstwie objawia się m.in. powstawaniem sieci hotelowych działających w wielu krajach (Marriott, Hilton)."},{"type":"tf","q":"Globalizacja w turystyce zwiększa dostępność podróży dzięki tanim lotom i internetowym biurom podróży.","correct":true,"explain":"To jeden z głównych przejawów globalizacji w turystyce wymienionych w materiale."},{"type":"flash","front":"Wymień przejawy globalizacji w rekreacji.","back":"Wymiana form rekreacyjnych między krajami (joga, fitness), rozwój globalnych wydarzeń sportowo-rekreacyjnych, globalnie dostępne technologie rekreacyjne oraz wzrost znaczenia zdrowego stylu życia."}]},{"id":"rynek-turystyczny-elementy","track":"wszyscy","category":"turystyka","number":50,"title":"Rynek turystyczny i jego elementy (popyt, podaż, cena)","summary":"Rynek turystyczny to system wymiany usług między dostawcami a turystami, którego elementami są popyt, podaż i cena.","wiki":[{"heading":"Pojęcie rynku turystycznego","body":"Rynek turystyczny to system, w którym współpracują ze sobą firmy oferujące usługi turystyczne (biura podróży, hotele, linie lotnicze) z turystami będącymi ich konsumentami. Jego celem jest wymiana dóbr i usług związanych z podróżowaniem, wypoczynkiem i rekreacją."},{"heading":"Popyt turystyczny","body":"Popyt turystyczny to chęć i możliwość ludzi do zakupu usług turystycznych.","bullets":["Dochody ludności (im wyższe, tym większy popyt)","Czas wolny (urlopy, ferie, wakacje)","Moda i trendy (podróże egzotyczne, city break)","Czynniki psychologiczne i społeczne (potrzeba odpoczynku, prestiż)","Sytuacja polityczna i bezpieczeństwo"]},{"heading":"Podaż turystyczna","body":"Podaż turystyczna to wszystkie dobra i usługi oferowane turystom: miejsca noclegowe, transport, usługi gastronomiczne, atrakcje turystyczne, usługi organizacyjne.","bullets":["Sezonowość (większa podaż w sezonie letnim)","Zróżnicowanie jakościowe i cenowe","Ograniczona elastyczność (trudno szybko zwiększyć liczbę miejsc w hotelu czy samolocie)"]},{"heading":"Cena usług turystycznych","body":"Cena to wartość, jaką turysta płaci za usługę. Wpływ na nią mają: relacja popytu i podaży, sezon turystyczny (szczyt sezonu = drożej), standard i jakość usług, lokalizacja oraz polityka cenowa organizatora (last minute, first minute, promocje)."}],"questions":[{"type":"abcd","q":"Który czynnik NIE należy do czynników wpływających na popyt turystyczny?","options":["Dochody ludności","Czas wolny","Sezonowość podaży miejsc noclegowych","Moda i trendy"],"correct":2,"explain":"Sezonowość jest cechą podaży turystycznej, a nie czynnikiem popytu. Popyt zależy m.in. od dochodów, czasu wolnego oraz mody i trendów."},{"type":"tf","q":"Podaż turystyczna charakteryzuje się bardzo dużą elastycznością, bo usługi można natychmiast dostosować do popytu.","correct":false,"explain":"Przeciwnie — podaż turystyczna jest mało elastyczna w krótkim czasie; liczby miejsc w hotelu czy samolocie nie da się szybko zwiększyć."},{"type":"flash","front":"Wymień trzy podstawowe elementy rynku turystycznego.","back":"Popyt turystyczny, podaż turystyczna oraz cena usług turystycznych."}]},{"id":"ekonomiczne-znaczenie-turystyki","track":"wszyscy","category":"turystyka","number":51,"title":"Ekonomiczne znaczenie turystyki i rekreacji","summary":"Turystyka i rekreacja generują dochody, miejsca pracy, inwestycje i wspierają lokalne społeczności oraz bilans płatniczy państwa.","wiki":[{"heading":"Rola w gospodarce","body":"Turystyka i rekreacja odgrywają ważną rolę w gospodarce, wpływając na różne sektory i poziomy życia społeczno-gospodarczego."},{"heading":"Główne funkcje ekonomiczne","bullets":["Źródło dochodów dla gospodarki (usługi, podatki) - np. Hiszpania, Tajlandia","Tworzenie miejsc pracy, w tym sezonowych i okazjonalnych","Wspieranie lokalnych społeczności (rzemiosło, rolnictwo, agroturystyka)","Pobudzanie inwestycji i modernizacja infrastruktury (drogi, lotniska, dworce)","Zróżnicowanie gospodarki - alternatywa dla przemysłu lub rolnictwa","Poprawa bilansu płatniczego dzięki wpływom z turystyki zagranicznej","Rozwój rekreacji jako sektora usług (siłownie, spa, aquaparki)"]},{"heading":"Wpływ na bilans płatniczy","body":"Wpływy z turystyki zagranicznej poprawiają saldo eksportu usług - turyści zostawiają pieniądze w odwiedzanym kraju, a turyści krajowi wspierają rodzimy rynek usług."}],"questions":[{"type":"abcd","q":"W jaki sposób turystyka zagraniczna wpływa na bilans płatniczy państwa?","options":["Poprawia saldo eksportu usług, bo turyści zostawiają pieniądze w kraju","Pogarsza saldo, bo turyści wywożą pieniądze za granicę","Nie ma żadnego wpływu na bilans płatniczy","Zwiększa wyłącznie import towarów"],"correct":0,"explain":"Wpływy z turystyki zagranicznej poprawiają saldo eksportu usług, ponieważ turyści wydają pieniądze w odwiedzanym kraju."},{"type":"tf","q":"Turystyka może być alternatywą dla przemysłu lub rolnictwa, zwłaszcza w regionach górskich i nadmorskich.","correct":true,"explain":"Turystyka różnicuje gospodarkę i pomaga regionom uniezależnić się od jednego sektora."},{"type":"flash","front":"Podaj główne funkcje ekonomiczne turystyki i rekreacji.","back":"Źródło dochodów, tworzenie miejsc pracy, wspieranie lokalnych społeczności, pobudzanie inwestycji, zróżnicowanie gospodarki, poprawa bilansu płatniczego oraz rozwój rekreacji jako sektora usług."}]},{"id":"wirtualna-rzeczywistosc-turystyka","track":"wszyscy","category":"technologie","number":52,"title":"Wirtualna rzeczywistość (VR) i jej wykorzystanie w turystyce","summary":"VR pozwala przenieść użytkownika do wygenerowanego świata i znajduje zastosowanie w wirtualnym zwiedzaniu, prezentacji hoteli, marketingu oraz treningu rekreacyjnym.","wiki":[{"heading":"Czym jest VR","body":"Wirtualna rzeczywistość (VR) to technologia, która pozwala użytkownikowi przenieść się do wygenerowanego świata - odwzorowującego rzeczywistość lub całkowicie fikcyjnego. Dzięki goglom VR, kontrolerom ruchu i sensorom użytkownik może oglądać, poruszać się i wchodzić w interakcje z tym światem w sposób realistyczny."},{"heading":"VR w turystyce","bullets":["Wirtualne wycieczki po atrakcjach (muzea, miasta, zabytki)","Wirtualna prezentacja hoteli i kurortów przed rezerwacją (spacery po pokojach)","Reklama i marketing turystyczny regionów i państw (np. Visit Dubai VR)"]},{"heading":"VR w rekreacji","bullets":["Wirtualny trening i ćwiczenia (FitXR, Supernatural - boks, taniec, joga)","Symulatory sportowe (narty, wspinaczka, golf, pływanie)","Gry i zabawy rekreacyjne w centrach VR (strzelnica, escape room, wyścigi)"]}],"questions":[{"type":"abcd","q":"Który z poniższych to przykład wykorzystania VR w turystyce?","options":["Drukowanie papierowych folderów reklamowych","Wirtualny spacer po pokojach hotelu przed rezerwacją","Tradycyjna wycieczka autokarowa","Telefoniczna rezerwacja noclegu"],"correct":1,"explain":"Hotele i biura podróży udostępniają wirtualne spacery po pokojach i kurortach przed rezerwacją - to typowe zastosowanie VR w turystyce."},{"type":"tf","q":"VR umożliwia użytkownikowi interakcję z wygenerowanym światem dzięki goglom, kontrolerom ruchu i sensorom.","correct":true,"explain":"To podstawowa charakterystyka technologii VR opisana w materiale."},{"type":"flash","front":"Podaj trzy zastosowania VR w turystyce.","back":"Wirtualne wycieczki po atrakcjach (muzea, zabytki), wirtualna prezentacja hoteli i kurortów przed rezerwacją oraz reklama i marketing turystyczny regionów (np. Visit Dubai VR)."}]},{"id":"szlaki-turystyczne","track":"wszyscy","category":"turystyka","number":53,"title":"Szlaki turystyczne jako specyficzny produkt krajoznawczy","summary":"Szlaki turystyczne to oznakowane trasy prowadzące przez ciekawe miejsca; są produktem otwartym, łączącym walory przyrodnicze, kulturowe i edukacyjne.","wiki":[{"heading":"Pojęcie i rodzaje","body":"Szlaki turystyczne to wyznaczone w terenie trasy prowadzące przez ciekawe miejsca przyrodnicze, historyczne lub kulturowe. Są oznaczone specjalnymi symbolami (kolorami, znakami) i służą bezpiecznemu oraz atrakcyjnemu poruszaniu się po danym obszarze.","bullets":["Piesze (górskie, nizinne)","Rowerowe","Konne","Kajakowe","Narciarskie","Tematyczne (szlak zamków gotyckich, szlak papieski)"]},{"heading":"Dlaczego są specyficznym produktem krajoznawczym","bullets":["Łączą walory przyrodnicze, kulturowe i edukacyjne, pozwalając aktywnie poznawać region","Są produktem otwartym - nie wymagają zakupu, często bezpłatne i samodzielne","Tworzą spójną, zorganizowaną ofertę turystyczną (aplikacje, przewodniki)","Pobudzają rozwój lokalnych usług (noclegi, gastronomia, informacja turystyczna)","Mają znaczenie edukacyjne i proekologiczne, często prowadzą przez obszary chronione"]}],"questions":[{"type":"abcd","q":"Dlaczego szlak turystyczny uznaje się za \"produkt otwarty\"?","options":["Bo zawsze wymaga wykupienia biletu wstępu","Bo można z niego korzystać tylko z przewodnikiem","Bo jest dostępny wyłącznie sezonowo","Bo nie wymaga zakupu i często można korzystać z niego samodzielnie i bezpłatnie"],"correct":3,"explain":"Szlak jest produktem otwartym, ponieważ nie wymaga zakupu - turyści korzystają z niego samodzielnie, bez przewodnika i często bezpłatnie."},{"type":"tf","q":"Szlaki turystyczne mogą mieć charakter tematyczny, np. szlak zamków gotyckich czy szlak papieski.","correct":true,"explain":"Szlaki tematyczne to jeden z rodzajów szlaków wymienionych w materiale."},{"type":"flash","front":"Wymień rodzaje szlaków turystycznych.","back":"Piesze (górskie, nizinne), rowerowe, konne, kajakowe, narciarskie oraz tematyczne (np. szlak zamków gotyckich, szlak papieski)."}]},{"id":"walory-krajobrazowe-unesco","track":"wszyscy","category":"przyroda","number":56,"title":"Klasyfikacja walorów krajobrazowych Polski (z uwzględnieniem UNESCO)","summary":"Walory krajobrazowe dzielą się na przyrodnicze i kulturowe; Polska ma 17 obiektów na Liście Światowego Dziedzictwa UNESCO i 11 rezerwatów biosfery.","wiki":[{"heading":"Pojęcie i podział walorów","body":"Walory krajobrazowe (krajoznawcze) to cechy środowiska przyrodniczego i kulturowego decydujące o atrakcyjności obszaru. Dzieli się je na walory przyrodnicze (ukształtowanie terenu, szata roślinna, świat zwierząt, wody, zjawiska geologiczne) oraz walory kulturowe/antropogeniczne (zabytki architektury, układy urbanistyczne, obiekty przemysłowe, miejsca historyczne, krajobrazy kulturowe)."},{"heading":"Walory przyrodnicze Polski","bullets":["Krajobrazy nadmorskie - wybrzeże Bałtyku, ruchome wydmy, klify, mierzeje","Krajobrazy pojezierne - Pojezierze Mazurskie i Pomorskie, jeziora polodowcowe, moreny","Krajobrazy nizinne - równiny, doliny rzeczne (Wisła, Biebrza), bagna i torfowiska","Krajobrazy wyżynne - lessowe wąwozy, ostańce wapienne, jaskinie (Wyżyna Krakowsko-Częstochowska)","Krajobrazy górskie - Tatry, Bieszczady, Karkonosze, duże deniwelacje i piętrowość"]},{"heading":"Obiekty UNESCO w Polsce","body":"Polska posiada 17 obiektów na Liście Światowego Dziedzictwa UNESCO: 15 kulturowych i 2 przyrodnicze.","bullets":["Kulturowe m.in.: Historyczne Centrum Krakowa, kopalnie soli w Wieliczce i Bochni, Auschwitz-Birkenau, Stare Miasto w Warszawie i Zamościu, Zamek w Malborku, Toruń, Kalwaria Zebrzydowska, Kościoły Pokoju, Hala Stulecia, Tarnowskie Góry, Krzemionki","Przyrodnicze: Puszcza Białowieska (ostoja żubra) oraz pierwotne i stare lasy bukowe Karpat"]},{"heading":"Rezerwaty biosfery UNESCO","body":"W ramach programu \"Czlowiek i Biosfera\" (MAB) Polska posiada 11 rezerwatów biosfery łączących ochronę przyrody ze zrównoważonym rozwojem, m.in. Białowieża, Babia Góra, Tatry, Karkonosze, Słowiński, Bory Tucholskie, Roztocze, Karpaty Wschodnie, Kampinos."}],"questions":[{"type":"abcd","q":"Ile obiektów przyrodniczych z Polski znajduje się na Liście Światowego Dziedzictwa UNESCO?","options":["15 obiektów","11 obiektów","2 obiekty (Puszcza Białowieska oraz lasy bukowe Karpat)","17 obiektów"],"correct":2,"explain":"Z 17 polskich obiektów UNESCO 15 jest kulturowych, a tylko 2 przyrodnicze: Puszcza Białowieska oraz pierwotne i stare lasy bukowe Karpat."},{"type":"tf","q":"Rezerwaty biosfery UNESCO funkcjonują w ramach konwencji ramsarskiej i służą wyłącznie ochronie obszarów wodno-błotnych.","correct":false,"explain":"Rezerwaty biosfery działają w ramach programu „Człowiek i Biosfera” (MAB) i łączą ochronę przyrody ze zrównoważonym rozwojem; konwencja ramsarska dotyczy odrębnie obszarów wodno-błotnych."},{"type":"flash","front":"Na jakie dwie główne grupy dzielimy walory krajobrazowe Polski?","back":"Na walory przyrodnicze (ukształtowanie terenu, szata roślinna, świat zwierząt, wody, zjawiska geologiczne) oraz walory kulturowe/antropogeniczne (zabytki, układy urbanistyczne, obiekty przemysłowe, miejsca historyczne, krajobrazy kulturowe)."}]},{"id":"przyrodnicze-walory-polski","track":"wszyscy","category":"przyroda","number":57,"title":"Przyrodnicze walory Polski","summary":"Polska ma zróżnicowane walory przyrodnicze: 23 parki narodowe, góry, pojezierza, wybrzeże Bałtyku, rzeki, puszcze oraz bogatą bioróżnorodność.","wiki":[{"heading":"Pojęcie walorów przyrodniczych","body":"Walory przyrodnicze to naturalne elementy środowiska będące przedmiotem zainteresowania turysty, powstałe niezależnie od działań człowieka. Obejmują klimat, ukształtowanie terenu, wody, bogactwa naturalne, rośliny i świat zwierząt."},{"heading":"Parki narodowe i góry","bullets":["W Polsce są 23 parki narodowe","Białowieski PN - ostatni naturalny las nizinny w UE, UNESCO, chroni żubra","Tatrzański PN - najwyższe góry, doliny i jeziora polodowcowe (Morskie Oko)","Biebrzański PN - największy PN, rzeka Biebrza, bagna i torfowiska","Karpaty (Tatry z Rysami, Bieszczady) i Sudety (Śnieżka, Góry Stołowe)"]},{"heading":"Wody i pojezierza","bullets":["Pojezierze Mazurskie (Śniardwy, Mamry) i Pomorskie","Wybrzeże Bałtyku ok. 510 km - Słowiński PN (ruchome wydmy), Mierzeja Helska","Rzeki: Wisła (najdłuższa, korytarz ekologiczny), Dunajec (przełom w Pieninach)"]},{"heading":"Lasy, formacje skalne i bioróżnorodność","bullets":["Puszcze: Białowieska, Kampinoska, Augustowska","Formacje skalne i jaskinie: Wyżyna Krakowsko-Częstochowska, Jaskinia Niedźwiedzia","Bagna i mokradła: Bagna Biebrzańskie, Poleski PN","Bioróżnorodność: żubry, wilki, rysie, niedźwiedzie brunatne, ponad 400 gatunków ptaków"]}],"questions":[{"type":"abcd","q":"Ile parków narodowych znajduje się w Polsce?","options":["11","23","17","40"],"correct":1,"explain":"W Polsce znajdują się 23 parki narodowe chroniące unikalne ekosystemy i krajobrazy."},{"type":"tf","q":"Tatrzański Park Narodowy jest największym parkiem narodowym w Polsce.","correct":false,"explain":"Największy jest Biebrzański Park Narodowy (rozległe bagna i torfowiska będące siedliskiem wielu ptaków), a nie Tatrzański."},{"type":"flash","front":"Z czego znany jest Słowiński Park Narodowy?","back":"Z ruchomych wydm, które przemieszczają się pod wpływem wiatru; leży na wybrzeżu Bałtyku."}]},{"id":"style-historyczne-zabytki","track":"wszyscy","category":"historia","number":59,"title":"Rozwój stylów historycznych na zabytkach Poznania (Trakt Królewsko-Cesarski)","summary":"Trakt Królewsko-Cesarski w Poznaniu to przestrzenny zapis ewolucji stylów: od architektury przedromańskiej i gotyku po renesans, barok, klasycyzm, historyzm i modernizm.","wiki":[{"heading":"Architektura przedromańska, romańska i gotyk","body":"Najstarsze zabytki na Ostrowie Tumskim wiążą się z chrystianizacją i Piastami: Palatium Mieszka I i kaplica Dobrawy (styl przedromański, surowość, łupany kamień - opus emplectum) oraz przedromańska i romańska bazylika w podziemiach katedry (masywność, monumentalizm). Gotyk (XIII-XVI w.) reprezentuje ceglana katedra na Ostrowie Tumskim - łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste, wąskie okna - oraz Psałteria (schodkowy szczyt z blendami) i Zamek Królewski na Wzgórzu Przemysła."},{"heading":"Renesans i barok","bullets":["Renesans (XVI w.) - Ratusz Jana Baptysty Quadro z loggią arkadową i attyką, Akademia Lubrańskiego, Pałac Górków","Cechy renesansu: harmonia, symetria, horyzontalizm, proporcje antyczne","Barok (XVII-XVIII w.) - Fara Poznańska (Jezuici, pseudokorynckie kolumny, freski Dankwarta), kościół św. Antoniego","Cechy baroku: dynamizm, teatralność, iluzjonizm, theatrum sacrum"]},{"heading":"Klasycyzm, rokoko i historyzm","bullets":["Klasycyzm (XVIII w.) - Odwach (portyk toskański) i Pałac Działyńskich (tympanon)","Rokoko - detale rzeźbiarskie, motyw muszli (rocaille), lekkość, złocenia","Historyzm (XIX-XX w.) w Dzielnicy Cesarskiej - Zamek Cesarski (neoromanizm), Teatr Wielki (neoklasycyzm), Collegium Minus (neorenesans), Złota Kaplica (neobizantynizm)"]},{"heading":"Modernizm i postmodernizm","body":"Modernizm reprezentuje Okrąglak (Marek Leykam, 1948-1954) - walec z betonowych prefabrykatów, zasada \"forma wynika z funkcji\". Postmodernizm/dekonstruktywizm to Brama Poznania ICHB (2014) - betonowy sześcian \"przecięty\" przeszkloną szczeliną kadrującą widok na gotycką katedrę, dialog współczesności z historią."}],"questions":[{"type":"abcd","q":"W jakim stylu architekt Jan Baptysta Quadro przebudował poznański Ratusz?","options":["Gotyk","Barok","Renesans","Klasycyzm"],"correct":2,"explain":"Ratusz uchodzi za jedno z najwspanialszych dzieł renesansu na północ od Alp; Quadro dodał trójkondygnacyjną loggię arkadową i attykę."},{"type":"tf","q":"Zamek Cesarski w Poznaniu zbudowano w stylu gotyckim, wzorując się na średniowiecznych katedrach.","correct":false,"explain":"Zamek Cesarski (proj. Franz Schwechten, 1910) powstał w stylu neoromańskim, by nawiązać do tradycji cesarskiej i legitymizować pruskie panowanie — nie w gotyku."},{"type":"flash","front":"Jakie cechy stylu gotyckiego widać w katedrze na Ostrowie Tumskim?","back":"Czerwona cegła (gotyk ceglany), strzeliste łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste oraz wysokie, wąskie okna z witrażami."}]},{"id":"planowanie-przestrzenne","track":"wszyscy","category":"historia","number":58,"title":"System planowania przestrzennego w Polsce","summary":"To trójstopniowy, hierarchiczny system kształtowania przestrzeni dla ochrony ładu przestrzennego i zrównoważonego rozwoju; kluczowy jest poziom gminny i władztwo planistyczne.","wiki":[{"heading":"Istota i cele","body":"System planowania przestrzennego to zespół narzędzi prawnych, instytucjonalnych i organizacyjnych służących zrównoważonemu kształtowaniu przestrzeni. Głównym celem jest ochrona ładu przestrzennego i zrównoważonego rozwoju. Podstawą prawną jest ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym."},{"heading":"Struktura hierarchiczna (trójstopniowa)","bullets":["Poziom krajowy - dokument strategiczny (osie rozwoju, sieć osadnicza, korytarze transportowe), nie jest aktem prawa miejscowego","Poziom regionalny - Plan zagospodarowania przestrzennego województwa (PZPW), uchwala sejmik, nie wiąże właścicieli nieruchomości","Poziom lokalny (gminny) - kluczowy, tu zapadają decyzje wiążące dla obywatela","Zasada hierarchicznej zgodności - dokumenty niższego szczebla nie mogą być sprzeczne z wyższymi"]},{"heading":"Akty na poziomie gminy (po reformie 2023)","bullets":["Plan Ogólny Gminy - akt prawa miejscowego, obowiązkowy, dzieli gminę na strefy planistyczne (zastąpił dawne Studium)","Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) - akt prawa miejscowego, fakultatywny, podstawa pozwoleń na budowę","Zintegrowany Plan Inwestycyjny (ZPI) - szczególna forma MPZP w ramach partnerstwa publiczno-prywatnego","Gmina ma władztwo planistyczne - autonomiczne prawo kształtowania polityki przestrzennej"]},{"heading":"Dualizm systemu i problemy","body":"Gdy nie ma MPZP, inwestor występuje o decyzję o Warunkach Zabudowy (WZ) opartą na zasadzie dobrego sąsiedztwa. Nadużywanie decyzji WZ prowadziło do rozlewania się miast (urban sprawl) i chaosu przestrzennego. Główne problemy: niski stopień pokrycia kraju planami (ok. 30-35%), koszty finansowe gmin, chaos przestrzenny i konflikty funkcji."}],"questions":[{"type":"abcd","q":"Na jakiej podstawie inwestor może budować, gdy na danym terenie nie ma uchwalonego MPZP?","options":["Na podstawie Planu zagospodarowania przestrzennego województwa","Na podstawie decyzji o Warunkach Zabudowy (WZ) i zasady dobrego sąsiedztwa","Na podstawie koncepcji rozwoju kraju","Bez żadnego dokumentu administracyjnego"],"correct":1,"explain":"W braku MPZP stosuje się ścieżkę decyzyjną - decyzję o Warunkach Zabudowy opartą na zasadzie dobrego sąsiedztwa (analiza urbanistyczna)."},{"type":"tf","q":"Władztwo planistyczne oznacza, że to wojewoda (administracja rządowa) decyduje o przeznaczeniu gruntów w gminie.","correct":false,"explain":"Władztwo planistyczne przysługuje samorządowi gminnemu — to gmina, nie wojewoda, autonomicznie decyduje o polityce przestrzennej na swoim obszarze."},{"type":"flash","front":"Jakie trzy akty planistyczne funkcjonują na poziomie gminy po reformie z 2023 r.?","back":"Plan Ogólny Gminy (zastąpił Studium), Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) oraz Zintegrowany Plan Inwestycyjny (ZPI)."}]},{"id":"zagospodarowanie-turystyczne-formy","track":"wszyscy","category":"turystyka","number":60,"title":"Zagospodarowanie turystyczne ze względu na formy turystyki","summary":"Zagospodarowanie turystyczne to ogół obiektów i urządzeń obsługi ruchu turystycznego, dostosowany do potrzeb różnych form turystyki.","wiki":[{"heading":"Pojęcie","body":"Zagospodarowanie turystyczne to ogół obiektów i urządzeń służących obsłudze ruchu turystycznego, dostosowany do potrzeb różnych form turystyki. Infrastruktura i usługi różnią się zakresem, funkcją oraz lokalizacją."},{"heading":"Formy turystyki i ich zaplecze","bullets":["Turystyka kulturowa - muzea, galerie, zabytki, trasy tematyczne, przewodnicy miejscy","Turystyka miejska - baza noclegowa, restauracje, kluby, komunikacja miejska, obiekty rozrywki","Turystyka biznesowa - centra kongresowe, sale konferencyjne, hotele średniej i wysokiej klasy","Turystyka religijna - obiekty sakralne, domy pielgrzyma, punkty obsługi, parkingi","Agroturystyka - pokoje gościnne, domy wiejskie, warsztaty, produkty regionalne","Turystyka przyrodnicza - ścieżki edukacyjne, wieże widokowe, tablice, ograniczona baza (kempingi, schroniska)","Turystyka aktywna i przygodowa - oznakowanie szlaków, punkty ratunkowe, wypożyczalnie sprzętu, specjalistyczni przewodnicy"]},{"heading":"Infrastruktura wspólna","body":"Zagospodarowanie obejmuje również infrastrukturę wspólną: bazę noclegową, gastronomiczną, sanitarną, transportową oraz punkty informacyjne. Dobrze rozwinięte zaplecze zwiększa atrakcyjność regionu i sprzyja zrównoważonemu rozwojowi turystyki."}],"questions":[{"type":"abcd","q":"Jakie zaplecze jest charakterystyczne dla turystyki biznesowej?","options":["Ścieżki edukacyjne i wieże widokowe","Domy pielgrzyma i obiekty sakralne","Centra kongresowe, sale konferencyjne i hotele średniej oraz wysokiej klasy","Pokoje gościnne w gospodarstwach rolnych"],"correct":2,"explain":"Turystyka biznesowa wymaga infrastruktury konferencyjnej (hale, sale, centra kongresowe) oraz hoteli średniej i wysokiej klasy."},{"type":"tf","q":"Turystyka przyrodnicza wymaga m.in. tworzenia ścieżek edukacyjnych, punktów obserwacyjnych i ograniczonej bazy noclegowej jak kempingi czy schroniska.","correct":true,"explain":"Turystyka przyrodnicza odbywa się na obszarach chronionych i wymaga infrastruktury ochrony przyrody oraz ograniczonej bazy noclegowej."},{"type":"flash","front":"Co obejmuje infrastruktura wspólna w zagospodarowaniu turystycznym?","back":"Bazę noclegową, gastronomiczną, sanitarną, transportową oraz punkty informacyjne - wspólne dla różnych form turystyki."}]},{"id":"pilot-wycieczek","track":"hotelarstwo","category":"hotelarstwo","number":34,"title":"Obowiązki i prawa pilota wycieczek","summary":"Pilot wycieczek w imieniu organizatora nadzoruje program imprezy i sprawuje opiekę nad uczestnikami — jego obowiązki i prawa.","wiki":[{"body":"Pilot wycieczek to osoba, która w imieniu organizatora nadzoruje realizację programu imprezy turystycznej i sprawuje opiekę nad uczestnikami. Marszałek województwa ma prawo kontrolować pilotów wycieczek."},{"heading":"Obowiązki pilota","bullets":["Działa na podstawie pisemnego zlecenia organizatora; musi znać język kraju docelowego.","Czuwa nad realizacją świadczeń — sprawdza jakość usług (nocleg, wyżywienie, transport) i ich zgodność z umową.","Sprawuje opiekę nad turystami, zapewnia pomoc medyczną i reaguje na problemy (zgubione dokumenty, konflikty z prawem).","Przekazuje informacje o trasie, krajach i atrakcjach oraz tłumaczy rozmowy z obsługą.","Pełni obowiązki handlowe (interesy organizatora, faktury) i obywatelskie (szacunek dla lokalnych przepisów i zwyczajów)."]},{"heading":"Prawa pilota","bullets":["Reprezentuje organizatora — kontaktuje się z kontrahentami i koordynuje program.","Podejmuje decyzje organizacyjne związane z przebiegiem imprezy.","Wydaje uczestnikom polecenia organizacyjne."]},{"body":"Uwaga: w niektórych krajach (np. Francja, Włochy) pilot nie może oprowadzać po obiektach bez lokalnej licencji przewodnika. Częsty jest też dylemat pilota: opieka nad uczestnikami czy realizacja programu (stan wyższej konieczności)."}],"questions":[{"type":"abcd","q":"Kto ma prawo kontrolować pilotów wycieczek?","options":["Minister sportu","Izba Turystyki","Prezydent miasta","Marszałek województwa"],"correct":3,"explain":"Zgodnie z materiałem, prawo kontroli pilotów wycieczek ma marszałek województwa."},{"type":"tf","q":"W niektórych krajach (np. Francja, Włochy) pilot nie może oprowadzać turystów bez lokalnej licencji.","correct":true,"explain":"W części krajów oprowadzanie po obiektach wymaga lokalnej licencji przewodnika — pilot nie może jej zastąpić."},{"type":"flash","front":"Na czym polega dylemat pilota „opieka czy program\"?","back":"W sytuacji wyższej konieczności pilot musi zdecydować, czy realizować zaplanowany program, czy zająć się opieką nad uczestnikiem — opieka i bezpieczeństwo mają pierwszeństwo."}]},{"id":"programowanie-imprez-turystycznych","track":"hotelarstwo","category":"hotelarstwo","number":40,"title":"Programowanie imprez turystycznych dla różnych grup docelowych","summary":"Etapy tworzenia imprezy turystycznej (analiza destynacji, współpraca z usługodawcami, kreowanie programu i kalkulacja ceny) z dopasowaniem do grupy docelowej.","wiki":[{"body":"Programowanie imprezy turystycznej to proces planowania kompleksowej oferty odpowiadającej potrzebom rynku i konkretnej grupy docelowej. Kluczowe jest dopasowanie oferty do specyfiki klientów (rodziny z dziećmi, seniorzy, młodzież, VIP)."},{"heading":"1. Analiza destynacji","bullets":["Rozpoznanie atrakcji (przyrodniczych, kulturowych, rozrywkowych).","Ocena infrastruktury (baza noclegowa, gastronomiczna, transportowa) i lokalnych usługodawców.","Sprawdzenie, czy miejsce spełnia wymagania grupy docelowej."]},{"heading":"2. Współpraca z usługodawcami","body":"Touroperator ustala ceny, terminy i standardy. Dwie formy zakupu usług:","bullets":["Allotment — rezerwacja usług z możliwością zwrotu do wyznaczonego terminu (lepszy dla indywidualnych i seniorów).","Czarter — wynajęcie całej usługi na własne ryzyko (sprawdza się przy młodzieży i grupach szkolnych)."]},{"heading":"3. Program i kalkulacja ceny","bullets":["Ustala się trasę/miejsce, terminy, standard usług, atrakcje, transport i cenę.","Program dopasowany do grupy: seniorzy — krótsze trasy; młodzież — intensywny program; VIP — usługi premium.","Kalkulacja: koszty stałe + koszty zmienne + marża + prowizje; w turystyce obowiązuje VAT od marży."]}],"questions":[{"type":"abcd","q":"Która forma zakupu usług pozwala zwrócić niewykorzystane miejsca do określonego terminu?","options":["Czarter","Allotment","Leasing","Franczyza"],"correct":1,"explain":"Allotment to rezerwacja z możliwością zwrotu do wyznaczonego terminu; czarter to wynajem na własne ryzyko."},{"type":"abcd","q":"Które koszty imprezy są niezależne od liczby uczestników?","options":["Koszty stałe","Koszty zmienne","Prowizje agentów","Bilety wstępu"],"correct":0,"explain":"Koszty stałe (np. wynagrodzenie pilota, rezerwacje) nie zależą od liczby uczestników; nocleg czy bilety to koszty zmienne."},{"type":"tf","q":"Czarter sprawdza się szczególnie przy małych, niepewnych grupach indywidualnych.","correct":false,"explain":"Czarter (całość usługi na własne ryzyko) opłaca się przy dużych, pewnych grupach, np. szkolnych — a nie przy małych grupach indywidualnych."},{"type":"flash","front":"Jaki system VAT obowiązuje w turystyce przy imprezach?","back":"System VAT od marży — podatek nalicza się od marży touroperatora, a nie od całej wartości imprezy."}]},{"id":"uczestnicy-turystyki-przygodowej","track":"przygodowa","category":"outdoor","number":2,"title":"Charakterystyka uczestników turystyki przygodowej","summary":"Uczestników turystyki przygodowej napędzają emocje z przekraczania strefy komfortu, a sama przygoda ma dla nich charakter subiektywny.","wiki":[{"heading":"Poziomy przygody i oczekiwania","body":"Wyróżnia się cztery poziomy przygody: nieszczęście, przygodę ekstremalną, przygodę i zabawę. Modelowo poziom wyzwania musi być dostosowany do poziomu uczestników, a uczestnicy powinni mieć wyrobione oczekiwania, które w efekcie aktywności mogą zostać spełnione lub osiągnięte. Uczestnik musi widzieć szansę na osiągnięcie sukcesu, dzięki czemu towarzyszy mu optymizm."},{"heading":"Motywacja i subiektywność","body":"Ludzi do uprawiania turystyki przygodowej skłaniają emocje wynikające z przekraczania strefy komfortu. Mogą one wynikać z szoku kulturowego lub z wykonywania czynności wymagających znacznego wysiłku fizycznego, wywołujących poczucie ryzyka (rzeczywistego lub domniemanego) lub zagrożenia fizycznego. Zaawansowanych specjalistów od masowych uczestników odróżnia poziom umiejętności oraz odległość i dostępność miejsca uprawiania turystyki, dlatego turystyka przygodowa ma charakter subiektywny."},{"heading":"Wyróżniki uczestników","bullets":["postawa akceptacji elementu ryzyka w doznaniach turystycznych","zdolność do ponoszenia zwiększonego poziomu wysiłku fizycznego podczas wypraw","potrzeba posiadania określonych umiejętności i nastawienia psychicznego dla powodzenia wyprawy"]}],"questions":[{"type":"abcd","q":"Ile poziomów przygody wyróżnia się w charakterystyce uczestników turystyki przygodowej?","options":["Dwa","Cztery","Trzy","Pięć"],"correct":1,"explain":"Wyróżnia się cztery poziomy: nieszczęście, przygodę ekstremalną, przygodę i zabawę."},{"type":"tf","q":"Turystyka przygodowa ma dla jej uczestników charakter subiektywny.","correct":true,"explain":"O subiektywności decyduje m.in. indywidualny poziom umiejętności oraz odległość i dostępność miejsca uprawiania turystyki."},{"type":"flash","front":"Wymień wyróżniki uczestników turystyki przygodowej.","back":"Akceptacja elementu ryzyka, zdolność do zwiększonego wysiłku fizycznego oraz potrzeba posiadania określonych umiejętności i nastawienia psychicznego dla powodzenia wyprawy."}]},{"id":"etapy-zarzadzania-projektami-turystycznymi","track":"przygodowa","category":"outdoor","number":4,"title":"Etapy zarządzania projektami turystycznymi","summary":"Zarządzanie projektami turystycznymi obejmuje pięć etapów: inicjację, planowanie, realizację, monitorowanie i kontrolę oraz zamknięcie.","wiki":[{"heading":"Pięć etapów projektu","body":"Zarządzanie projektami turystycznymi składa się z pięciu głównych etapów. Każdy ma własne wyzwania i wymagania, które należy uwzględnić dla skutecznego ukończenia projektu.","bullets":["Inicjacja: określenie celu i zakresu projektu, zdefiniowanie zespołu i głównych zadań, wstępna analiza możliwości oraz ustalenie ram wyjazdu","Planowanie: szczegółowy plan z harmonogramem, budżetem, zasobami i procesami, określenie ryzyka i strategii jego zarządzania oraz przygotowanie informacji dla interesariuszy","Realizacja: wykonanie zaplanowanych zadań, monitorowanie postępów, reagowanie na zmiany i problemy, zapewnienie świadczeń i sprzętu","Monitorowanie: porównywanie postępów z planem, kontrola ryzyka, budżetu, harmonogramu i jakości oraz poziomu zadowolenia klienta","Zamknięcie: podsumowanie wyników, ocena projektu, dokumentacja, rozliczenie finansowe, raport końcowy i wdrożenie wniosków na przyszłość"]},{"heading":"Specyfika turystyki","body":"Ważnym elementem jest zrozumienie specyfiki turystyki i dostosowanie procesu zarządzania do konkretnego typu projektu. Może to obejmować analizę rynku, określenie grupy docelowej, marketing i promocję oraz współpracę z lokalnymi dostawcami i partnerami."}],"questions":[{"type":"abcd","q":"Który etap zarządzania projektem turystycznym obejmuje opracowanie harmonogramu, budżetu i strategii zarządzania ryzykiem?","options":["Inicjacja","Zamknięcie","Realizacja","Planowanie"],"correct":3,"explain":"Na etapie planowania opracowuje się szczegółowy plan z harmonogramem, budżetem, zasobami oraz strategią zarządzania ryzykiem."},{"type":"abcd","q":"Na którym etapie projektu sporządza się raport końcowy i przeprowadza rozliczenie finansowe?","options":["Zamknięcie","Realizacja","Monitorowanie","Inicjacja"],"correct":0,"explain":"Zamknięcie obejmuje podsumowanie wyników, ocenę, dokumentację, rozliczenie finansowe i raport końcowy."},{"type":"tf","q":"Zarządzanie projektami turystycznymi składa się z trzech głównych etapów.","correct":false,"explain":"Etapów jest pięć: inicjacja, planowanie, realizacja, monitorowanie i kontrola oraz zamknięcie."},{"type":"flash","front":"Wymień pięć etapów zarządzania projektami turystycznymi.","back":"Inicjacja, planowanie, realizacja, monitorowanie i kontrola oraz zamknięcie."}]},{"id":"fotografia-dokumentalna","track":"przygodowa","category":"outdoor","number":5,"title":"Fotografia dokumentalna - motywy i specyfika","summary":"Fotografia dokumentalna uchwytuje prawdziwe i naturalne momenty bez pozowania, wiernie przedstawiając świat.","wiki":[{"heading":"Czym jest fotografia dokumentalna","body":"To rodzaj fotografii, którego głównym celem jest uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania. Często jest używana do dokumentowania wydarzeń, miejsc, kultur lub sytuacji społecznych, politycznych i ludzkich. Obejmuje wszystkie zdjęcia próbujące wiernie przedstawić świat."},{"heading":"Rola i odróżnienie od fotoreportażu","body":"Zdjęcia dokumentalne, od wojennych panoram po zbliżenia ludzi na ulicy, mogą informować odbiorców o ukrytych zakamarkach współczesnego życia, a nawet stać się częścią danych historycznych. W przeciwieństwie do fotoreportażu, który ogranicza się do pojedynczej wiadomości lub wydarzenia, obrazy dokumentalne wykorzystywane są zbiorowo, aby naświetlić głębszy problem."}],"questions":[{"type":"abcd","q":"Co najlepiej odróżnia fotografię dokumentalną od fotoreportażu?","options":["Fotografia dokumentalna wymaga pozowania modeli","Fotoreportaż zawsze dotyczy danych historycznych","Obrazy dokumentalne wykorzystywane są zbiorowo, by naświetlić głębszy problem, a fotoreportaż ogranicza się do pojedynczej wiadomości lub wydarzenia","Fotografia dokumentalna dotyczy wyłącznie wydarzeń wojennych"],"correct":2,"explain":"Fotoreportaż ogranicza się do pojedynczej wiadomości lub wydarzenia, a obrazy dokumentalne wykorzystywane są zbiorowo, aby naświetlić głębszy problem."},{"type":"tf","q":"Głównym celem fotografii dokumentalnej jest uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania.","correct":true,"explain":"Fotografia dokumentalna obejmuje zdjęcia próbujące wiernie przedstawić świat."},{"type":"flash","front":"Jaki jest główny cel fotografii dokumentalnej?","back":"Uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania, w celu wiernego przedstawienia świata oraz dokumentowania wydarzeń, miejsc, kultur i sytuacji społecznych."}]},{"id":"fotografia-w-social-mediach","track":"przygodowa","category":"outdoor","number":6,"title":"Fotografia w świecie social mediów","summary":"Fotografia w mediach społecznościowych buduje wizerunek marki, zwiększa zaangażowanie i wspiera sprzedaż, będąc strategią komunikacji.","wiki":[{"heading":"Wpływ fotografii na social media","body":"Fotografia jest kluczowym elementem mediów społecznościowych. Profesjonalnie wykonane zdjęcia przyciągają uwagę, zwiększają zaangażowanie i wspierają sprzedaż. To nie tylko estetyka, ale także strategia komunikacji pozwalająca wyróżnić się na tle konkurencji.","bullets":["budowanie wizerunku marki i zaufania","zwiększanie zaangażowania (polubienia, komentarze, udostępnienia)","wspomaganie sprzedaży poprzez fotografię produktową","wyróżnianie się na tle konkurencji"]},{"heading":"Jak wykorzystać fotografię","bullets":["dostosowanie do platformy (np. Instagram - format kwadratowy, Facebook - pionowy lub poziomy)","regularność i spójność stylu oraz estetyki","kreowanie historii marki i produktu","wykorzystanie różnych formatów: zdjęcia, krótkie filmy, reelsy, story"]},{"heading":"Dodatkowe wskazówki","bullets":["dbanie o wyraźne i ostre zdjęcia (czyszczenie obiektywu, dobre oświetlenie)","pilnowanie praw autorskich do publikowanych zdjęć","eksperymentowanie z różnymi stylami i formatami"]}],"questions":[{"type":"abcd","q":"Który format zdjęć jest wskazany dla Instagrama według zasady dostosowania do platformy?","options":["Panoramiczny 21:9","Wyłącznie pionowy","Wyłącznie poziomy","Kwadratowy"],"correct":3,"explain":"Instagram wymaga zdjęć w kwadratowym formacie, a Facebook w pionowym lub poziomym."},{"type":"tf","q":"Fotografia w social media to wyłącznie kwestia estetyki, bez znaczenia strategicznego.","correct":false,"explain":"To nie tylko estetyka, ale także strategia komunikacji pozwalająca wyróżnić się na tle konkurencji."},{"type":"flash","front":"Jak fotografia wpływa na social media?","back":"Buduje wizerunek marki i zaufanie, zwiększa zaangażowanie, wspomaga sprzedaż oraz pomaga wyróżnić się na tle konkurencji."}]},{"id":"kompetencje-miedzykulturowe-outdoor","track":"przygodowa","category":"outdoor","number":7,"title":"Kompetencje międzykulturowe w projektach outdoorowych","summary":"Trzon kompetencji międzykulturowych stanowią umiejętności (skills), postawa (attitude) i wiedza (knowledge), kluczowe dla współpracy w projektach outdoorowych.","wiki":[{"heading":"Trzon kompetencji kulturowych","bullets":["Skills (umiejętności) - komunikowanie się, współpraca, elastyczność, radzenie sobie w sytuacjach stresowych, aktywne słuchanie i krytyczne myślenie","Attitude (postawa) - świadomość różnic, odwaga, pozytywne nastawienie i otwartość","Knowledge (wiedza) - wiedza kulturowa, przygotowanie na szok kulturowy oraz wiedza z turystyki, survivalu i planowania"]},{"heading":"Znaczenie w projektach outdoorowych","body":"Kompetencje obejmują rozumienie różnic kulturowych, akceptację i szacunek dla innych kultur oraz umiejętność komunikowania się i współpracy z osobami z różnych środowisk. Pozwalają na skuteczną współpracę przez budowanie zaufania, podnoszą bezpieczeństwo i komfort dzięki lepszej adaptacji, rozwijają kompetencje uczestników i kształtują właściwą relację z innym."},{"heading":"Odpowiedzialne podróżowanie","body":"Kompetencje prowadzą do odpowiedzialnego podróżowania z otwartymi oczami: ludzie pamiętają, że ich obecność odciska piętno na odwiedzanych miejscach, wydają pieniądze wspierając lokalne walory, cenią dziedzictwo przyrodnicze i kulturowe, szanują lokalne zwyczaje i tradycje oraz wspierają tych, którzy dbają o dane miejsca."}],"questions":[{"type":"abcd","q":"Który element NIE należy do trzonu kompetencji kulturowych (skills, attitude, knowledge)?","options":["Skills - umiejętności","Attitude - postawa","Budget - budżet","Knowledge - wiedza"],"correct":2,"explain":"Trzon kompetencji kulturowych stanowią skills (umiejętności), attitude (postawa) i knowledge (wiedza); budżet nie wchodzi w jego skład."},{"type":"tf","q":"Komponent \"knowledge\" obejmuje m.in. przygotowanie na szok kulturowy oraz wiedzę z survivalu i planowania.","correct":true,"explain":"Knowledge to wiedza kulturowa, przygotowanie na szok kulturowy oraz wiedza z dziedzin potrzebnych w podróży: turystyki, survivalu i planowania."},{"type":"flash","front":"Co stanowi trzon kompetencji międzykulturowych?","back":"Skills (umiejętności), attitude (postawa) i knowledge (wiedza)."}]},{"id":"kwalifikacje-pilotow-przewodnikow-trampingowych","track":"przygodowa","category":"outdoor","number":8,"title":"Kwalifikacje i kompetencje pilotów i przewodników turystyki trampingowej","summary":"Piloci i przewodnicy turystyki trampingowej muszą spełniać podstawowe wymogi prawne oraz dysponować wieloma grupami kompetencji i znajomością specyfiki trampingu.","wiki":[{"heading":"Podstawowe wymogi","body":"Podstawowe wymogi to ukończenie 18 lat, niekaralność oraz wykształcenie średnie. Przewodnik powinien posiadać wiedzę o regionie i atrakcjach, a pilot doświadczenie w organizacji i zarządzaniu wycieczkami. Obowiązki i kompetencje określa ustawa o usługach hotelarskich oraz usługach pilotów wycieczek i przewodników turystycznych z 2023 roku."},{"heading":"Grupy kompetencji","bullets":["kompetencje społeczne - elokwentność, cierpliwość, komunikatywność, empatia i elastyczność","kompetencje osobiste - cierpliwość, punktualność, dokładność, znajomość dobrych manier, optymizm","kompetencje menedżerskie i przywódcze - charyzma, pewność siebie, delegowanie uprawnień, umiejętność pracy w grupie","kompetencje zawodowe - językowe, fachowa wiedza, sporządzanie pism, pierwsza pomoc","kompetencje formalno-prawne pilota - zakres uprawnień i pełnomocnictwo do podejmowania decyzji"]},{"heading":"Specyfika trampingu","body":"W turystyce trampingowej przewodnik i pilot muszą znać teren, trasę, zagrożenia i zasady bezpieczeństwa oraz posiadać umiejętności praktyczne (obsługa sprzętu, pierwsza pomoc, planowanie). Tramping odbywa się jak najmniejszym kosztem i wymaga adaptacji pilota do otoczenia i grupy, odporności na zmienne warunki pogodowe oraz nastawienia na kontakt z lokalną ludnością i autentyczność. Treść przekazuje się przez poznawanie i doświadczanie."}],"questions":[{"type":"abcd","q":"Który z poniższych jest podstawowym wymogiem dla pilotów i przewodników turystyki trampingowej?","options":["Ukończenie 16 lat","Co najmniej 10 lat doświadczenia w terenie","Wykształcenie wyższe kierunkowe","Ukończenie 18 lat, niekaralność oraz wykształcenie średnie"],"correct":3,"explain":"Podstawowe wymogi to ukończenie 18 lat, niekaralność oraz wykształcenie średnie."},{"type":"tf","q":"Obowiązki i kompetencje pilotów oraz przewodników określa ustawa o usługach hotelarskich oraz usługach pilotów wycieczek i przewodników turystycznych z 2023 roku.","correct":true,"explain":"To właśnie ta ustawa pozostaje podstawą określającą obowiązki i kompetencje pilotów i przewodników."},{"type":"flash","front":"Wymień grupy kompetencji pilotów i przewodników turystyki trampingowej.","back":"Kompetencje społeczne, osobiste, menedżerskie i przywódcze, zawodowe oraz formalno-prawne pilota."}]},{"id":"ocena-tras-grupy-odbiorcow","track":"przygodowa","category":"outdoor","number":9,"title":"Metody oceny atrakcyjności i trudności tras dla różnych grup odbiorców","summary":"Do oceny atrakcyjności tras dla różnych grup odbiorców stosuje się m.in. szkocki formularz oceny atrakcji, testy zróżnicowania semantycznego, analizę ASEB/SWOT i kwestionariusz SERVQUAL.","wiki":[{"heading":"Metody jakościowe i kwestionariuszowe","bullets":["Szkocki formularz oceny atrakcji (Scottish Tourist Board) - obserwacja uczestnicząca, ocena sześciu części atrakcji (wstęp, wejście, prezentacja tematyki, gastronomia, sklep, toalety) na skali 0-10","Testy zróżnicowania semantycznego - budowanie profili semantycznych przez wybór par skrajnych cech (np. ładny - brzydki, bezpieczny - niebezpieczny)","Analiza ASEB/SWOT - rozwinięcie analizy SWOT o poziomy hierarchii wymagań, skupione na potrzebach, motywach, wrażeniach i satysfakcji zwiedzających","Kwestionariusz SERVQUAL - pomiar różnicy między oczekiwaniami klienta a percepcją usługi; do atrakcji przystosował go M. Nowacki"]},{"heading":"Metody analityczne","bullets":["Metoda bonitacji punktowej - przypisanie cechom wartości liczbowych według skali, których suma jest oceną","Metoda modelowa - badanie złożonych systemów przez tworzenie ich modeli, symulacja i przewidywanie zachowań","Metoda wielowymiarowej analizy porównawczej - porządkowanie jednorodnego zbioru obiektów lub cech według ustalonego kryterium, do badania zjawisk niemierzalnych bezpośrednio"]}],"questions":[{"type":"abcd","q":"Na czym opiera się założenie kwestionariusza SERVQUAL?","options":["Na liczbie odwiedzin atrakcji w sezonie","Na pomiarze długości i przewyższeń trasy","Na różnicy między oczekiwaniami klienta wobec usługi a jej percepcją","Na obserwacji uczestniczącej na skali 0-10"],"correct":2,"explain":"SERVQUAL zakłada, że satysfakcja z jakości usługi jest różnicą między oczekiwaniami klienta wobec niej a jej percepcją."},{"type":"tf","q":"Szkocki formularz oceny atrakcji ocenia sześć głównych części atrakcji na skali od 1 do 5.","correct":false,"explain":"Formularz Scottish Tourist Board stosuje jedenastostopniową skalę od 0 do 10, a nie skalę 1-5."},{"type":"flash","front":"Czym jest analiza ASEB/SWOT?","back":"Rozwinięcie tradycyjnej analizy SWOT o dodatkowy wymiar poziomów hierarchii wymagań, skupione na potrzebach, motywach, wrażeniach i satysfakcji zwiedzających."}]},{"id":"ocena-tras-formy-przygodowe","track":"przygodowa","category":"outdoor","number":10,"title":"Metody oceny atrakcyjności i trudności tras dla różnych form turystyki przygodowej","summary":"Atrakcyjność tras ocenia się m.in. listami rankingowymi i narzędziami badawczymi, a trudność za pomocą wystandaryzowanych skal właściwych dla danej formy aktywności.","wiki":[{"heading":"Ocena atrakcyjności tras","body":"Najbardziej rozpowszechnione są próby wartościowania przez listy rankingowe. W naukach geograficznych stosuje się analizy rozmieszczenia tras, a w marketingu i badaniach behawioralnych ocenia się jakość i odbiór szlaku. Wykorzystuje się skalę Likerta, Szkocki Kwestionariusz Atrakcji, Kwestionariusz Australijski, testy wiedzy, quizy, ankiety i schematy obserwacji, a coraz częściej kioski multimedialne oraz rejestrację zachowań za pomocą fotografii i nagrań."},{"heading":"Ocena trudności tras","body":"Należy korzystać z map, sprawdzać opis trasy, przebieg, długość i przewyższenia (np. w aplikacjach takich jak viaferrata.org), a także ustalić warunki pogodowe i możliwe trudności."},{"heading":"Wystandaryzowane skale trudności","bullets":["Skala UIAA (rzymska III-IX) oraz skala ferrat A-F dla tras wspinaczkowych","Skala singletrail (S0-S5) dla tras rowerowych","Skala SAC Szwajcarskiego Klubu Alpinistycznego (T1-T6) dla szlaków górskich","Oznaczenia kolorystyczne tras narciarskich (niebieski - łatwe, czarny - ekstremalne)","Skala szlaków kajakowych: nizinne (ZW: ZWA, ZWB, ZWC) i górskie (WW I do WW VI)"]}],"questions":[{"type":"abcd","q":"Która skala służy do oceny trudności tras rowerowych?","options":["Skala UIAA","Skala WW I do WW VI","Skala SAC (T1-T6)","Skala singletrail (S0-S5)"],"correct":3,"explain":"Skala singletrail to system klasyfikacji trudności tras rowerowych obejmujący 6 poziomów od S0 do S5."},{"type":"abcd","q":"Jakim kolorem oznacza się ekstremalne trasy narciarskie?","options":["Czarnym","Zielonym","Czerwonym","Niebieskim"],"correct":0,"explain":"Trasy łatwe oznacza się kolorem niebieskim, a trasy ekstremalne kolorem czarnym."},{"type":"tf","q":"Skala SAC Szwajcarskiego Klubu Alpinistycznego wykorzystuje oznaczenia od T1 do T10.","correct":false,"explain":"Skala SAC obejmuje sześć stopni — od T1 (bardzo łatwe) do T6 (najtrudniejsze szlaki alpejskie), nie sięga T10."},{"type":"flash","front":"Jak klasyfikuje się trudność szlaków kajakowych?","back":"Szlaki nizinne ocenia się w skali ZW (ZWA, ZWB, ZWC), a górskie w skali WW (od WW I do WW VI)."}]},{"id":"miekkie-formy-aktywnosci-terenowej","track":"przygodowa","category":"outdoor","number":11,"title":"Miękkie formy aktywności terenowej","summary":"Miękkie formy turystyki przygodowej charakteryzują się niskim ryzykiem i dostępnością bez specjalnego przygotowania; należą do nich m.in. bieg na orientację, safari, nurkowanie, narciarstwo, snowboard i surfing.","wiki":[{"heading":"Definicja miękkich form","body":"Miękkie formy aktywności turystyki przygodowej charakteryzują się niskim stopniem ryzyka i są dostępne dla osób bez specjalnych umiejętności czy przygotowania. W przeciwieństwie do twardej turystyki przygodowej, wymagającej zaawansowanych umiejętności i wiążącej się z większym ryzykiem, koncentrują się na przeżyciu przygody w bezpieczny i relatywnie łatwy sposób."},{"heading":"Przykłady miękkich form","bullets":["Bieg na orientację (BnO) - bieg wyznaczoną trasą z mapą i kompasem do punktów kontrolnych w określonej kolejności, łączący wysiłek fizyczny i intelektualny","Safari - podróż do dzikich obszarów w celu obserwacji zwierząt w naturalnym środowisku, np. Wielkiej Piątki: lwów, słoni, nosorożców, lampartów i bawołów","Nurkowanie - przebywanie pod wodą ze sprzętem lub na zatrzymanym oddechu (freediving); odmiany: snorkeling, freediving, płetwonurkowanie, wrakowe, jaskiniowe","Narciarstwo - przemieszczanie się na nartach; formy: klasyczne, biegi, skitouring, freeskiing, alpejskie","Snowboard - jazda na desce po stoku, rozwijająca równowagę, siłę mięśni i koordynację","Surfing - jazda na desce po fali morskiej; rodzaje: longboarding, shortboarding, na dużych falach, w rurkach"]}],"questions":[{"type":"abcd","q":"Co charakteryzuje miękkie formy aktywności turystyki przygodowej?","options":["Wysoki stopień ryzyka i konieczność zaawansowanych umiejętności","Obowiązkowy udział instruktora z licencją","Wyłącznie aktywności wysokogórskie","Niski stopień ryzyka i dostępność dla osób bez specjalnego przygotowania"],"correct":3,"explain":"Miękkie formy charakteryzują się niskim stopniem ryzyka i są dostępne dla osób bez specjalnych umiejętności czy przygotowania."},{"type":"abcd","q":"Które zwierzęta tworzą tzw. Wielką Piątkę, będącą pożądanym celem safari?","options":["Słonie, nosorożce, krokodyle, lwy i goryle","Lwy, żyrafy, zebry, hieny i gepardy","Lwy, słonie, nosorożce, lamparty i bawoły","Lamparty, tygrysy, lwy, niedźwiedzie i wilki"],"correct":2,"explain":"Wielką Piątkę tworzą lwy, słonie, nosorożce, lamparty i bawoły."},{"type":"tf","q":"Bieg na orientację wymaga zarówno sprawności fizycznej, jak i zdolności intelektualnych.","correct":true,"explain":"BnO łączy wysiłek fizyczny (bieganie, pokonywanie przeszkód) ze zdolnościami intelektualnymi (czytanie mapy, decyzje nawigacyjne)."},{"type":"flash","front":"Wymień przykłady miękkich form aktywności terenowej.","back":"Bieg na orientację, safari, nurkowanie, narciarstwo, snowboard i surfing."}]},{"id":"obszary-turystyki-przygodowej-azja","track":"przygodowa","category":"outdoor","number":12,"title":"Obszary turystyki przygodowej w Azji","summary":"Azja oferuje liczne obszary turystyki przygodowej, od Himalajów i Karakorum po Zatokę Halong, pustynię Gobi czy Raja Ampat.","wiki":[{"heading":"Obszary górskie i pustynne","bullets":["Himalaje (Nepal i Tybet) - najwyższe pasmo świata, trekking, wspinaczka wysokogórska i narciarstwo ekstremalne","Masyw Karakorum (Pakistan i Chiny) - trekking, wspinaczka i narciarstwo ekstremalne w regionie K2, przebiega tędy najwyżej położona autostrada świata","Pustynia Gobi (Chiny i Mongolia) - turystyka offroadowa i rajdy quadowe, bezpieczeństwo zapewniają wieże sygnałowe GPS","Jordania i jej pustynie (Petra) - imprezy sportowe, jazda tradycyjnym jeepem dzięki formacjom skalnym i antycznym zabudowaniom","Wulkany archipelagu Malajskiego - wyprawy trekkingowe i wspinaczkowe na styku płyt tektonicznych"]},{"heading":"Obszary wodne i przyrodnicze","bullets":["Zatoka Halong (Wietnam) - setki wysepek, kajakarstwo, żeglarstwo i fotografia przygodowa","Taman Negara (Malezja) - jeden z najstarszych lasów deszczowych, kładki 45 m nad ziemią, ekoturystyka","Tajlandia, zatoki Phuket i Phang Nga - kajakarstwo i żeglarstwo","Indonezja, Raja Ampat - nurkowanie i żeglarstwo","Wietnam, delta Mekongu i Mai Chau - trasy rowerowe przez pola ryżowe","Japonia - trekking, backpacking, narciarstwo (Furano, Hokkaido) i formy wodne na południu"]}],"questions":[{"type":"abcd","q":"Która forma turystyki przygodowej jest najbardziej charakterystyczna dla pustyni Gobi?","options":["Turystyka offroadowa i rajdy quadowe","Nurkowanie i żeglarstwo","Wspinaczka wysokogórska","Kajakarstwo"],"correct":0,"explain":"Na pustyni Gobi uprawia się przede wszystkim formy turystyki offroadowej i rajdy quadowe, a bezpieczeństwo zapewniają wieże sygnałowe GPS."},{"type":"tf","q":"Raja Ampat w Indonezji to obszar pustynny, sprzyjający przede wszystkim wspinaczce i trekkingowi wysokogórskiemu.","correct":false,"explain":"Raja Ampat to morski archipelag sprzyjający wodnym formom turystyki — głównie nurkowaniu i żeglarstwu, a nie wspinaczce na pustyni."},{"type":"flash","front":"Jakie aktywności oferują Himalaje (Nepal i Tybet)?","back":"Trekking, wspinaczkę wysokogórską i narciarstwo ekstremalne - to najwyższe pasmo górskie świata."}]},{"id":"obszary-turystyki-przygodowej-europa","track":"przygodowa","category":"outdoor","number":13,"title":"Obszary turystyki przygodowej w Europie","summary":"Europa oferuje zróżnicowane obszary turystyki przygodowej, od Tatr i Alp po Wielkie Jeziora Mazurskie, fiordy Norwegii i Islandię.","wiki":[{"heading":"Obszary górskie","bullets":["Tatry (Polska i Słowacja) - wspinaczka turystyczna, wyprawy wysokogórskie, via ferraty, trekking i narciarstwo, ratownictwo TOPR","Alpy (Francja, Szwajcaria, Włochy) - trekking, wspinaczka i narciarstwo, kolej zębatkowa z Zermatt na Gornergrat, ratownicy Air Zermatt, schroniska w Chamonix","Fiordy Norwegii - wyprawy trekkingowe i żeglarskie wśród stromych skarp oraz trasy narciarskie","Północna Szkocja - trekking, tramping, backpacking, bieg na orientację, wyprawy rowerowe, obserwacja wielorybów i wspinaczka na klifach","Islandia - trekking, tramping, backpacking, biegi i wyprawy quadowe przez pola lawowe"]},{"heading":"Obszary wodne i wybrzeża","bullets":["Francja, rzeka Dordogne - kajakarstwo łączone z turystyką kulturową","Szwecja, region Dalarna - kajakarstwo po jeziorach, wędkarstwo sportowe, bieg na orientację","Polska, Wielkie Jeziora Mazurskie - żeglarstwo z rozbudowaną infrastrukturą, windsurfing, kitesurfing, obserwacja fauny i flory","Grecja, Cyklady - żeglarstwo uwarunkowane kulturowo oraz formy związane z plażami i wyspami","Hiszpania, Wyspy Kanaryjskie - trekking, tramping, backpacking i nurkowanie w ciepłej, przejrzystej wodzie","Chorwacja, wybrzeże Dalmacji - nurkowanie, żeglarstwo i trekking"]}],"questions":[{"type":"abcd","q":"Która grupa ratownicza działa w polskich Tatrach jako udogodnienie dla turystów?","options":["Air Zermatt","WOPR","GOPR Beskidy","TOPR"],"correct":3,"explain":"W Tatrach działa TOPR, a Air Zermatt to ratownicy z regionu Matterhornu w Alpach."},{"type":"tf","q":"Polskie Wielkie Jeziora Mazurskie oferują dobre warunki do żeglarstwa wraz z rozbudowaną infrastrukturą.","correct":true,"explain":"Mazury to obszar żeglarski z rozbudowaną infrastrukturą, gdzie uprawia się także windsurfing i kitesurfing."},{"type":"flash","front":"Jakie aktywności umożliwia francuska rzeka Dordogne?","back":"Kajakarstwo łączone z turystyką kulturową - można płynąć rzeką, zatrzymując się, by spróbować lokalnej kuchni i zobaczyć sielskie miasteczka."}]},{"id":"kreatywne-myslenie-definicja-branze","track":"przygodowa","category":"outdoor","number":14,"title":"Kreatywne myslenie - definicja i branze","summary":"Kreatywne myslenie to zdolnosc generowania nowych, oryginalnych i uzytecznych idei, ceniona w wielu branzach kreatywnych i turystycznych.","wiki":[{"heading":"Definicja","body":"Kreatywne myslenie to trwala postawa czlowieka powodujaca podejmowanie dzialan przynoszacych wartosciowe nowosci. To dzialanie, ktorego celem jest zmiana stanu koniecznosci w stan wyboru. Jest to proces umyslowy prowadzacy do generowania nowych i oryginalnych idei, rozwiazan lub koncepcji, ktore sa uzyteczne i przydatne."},{"heading":"Istota","body":"Innymi slowy, jest to zdolnosc do myslenia nieszablonowego, wykraczajacego poza tradycyjne schematy myslenia."},{"heading":"Branze, w ktorych jest atutem","bullets":["filmografia","teatr","marketing","grafika komputerowa","edukacja","przewodnictwo i pilotaz","animatorka","projektowanie gier","fotografia"]}],"questions":[{"type":"abcd","q":"Czym jest kreatywne myslenie wedlug definicji?","options":["Zdolnoscia do szybkiego liczenia w pamieci","Umiejetnoscia wiernego odtwarzania znanych schematow","Procesem umyslowym prowadzacym do generowania nowych i oryginalnych idei, ktore sa uzyteczne i przydatne","Postawa unikania jakichkolwiek zmian"],"correct":2,"explain":"To proces umyslowy prowadzacy do generowania nowych i oryginalnych idei, rozwiazan lub koncepcji, ktore sa uzyteczne i przydatne."},{"type":"tf","q":"Kreatywne myslenie zmienia stan koniecznosci w stan wyboru.","correct":true,"explain":"Wprost wynika z definicji: celem dzialania kreatywnego jest zmiana stanu koniecznosci w stan wyboru."},{"type":"flash","front":"Wymien przynajmniej piec branz, w ktorych kreatywne myslenie jest duzym atutem.","back":"M.in.: filmografia, teatr, marketing, grafika komputerowa, edukacja, przewodnictwo i pilotaz, animatorka, projektowanie gier, fotografia."}]},{"id":"techniki-kreatywnego-myslenia","track":"przygodowa","category":"outdoor","number":15,"title":"Najskuteczniejsze techniki kreatywnego myslenia","summary":"Przeglad technik wspierajacych kreatywnosc: debata oksfordzka, odwrocona burza mozgow, metoda 635, 6 kapeluszy De Bono, 3 krzesla Disneya, drzewko decyzyjne, SCAMPER, diagram Ishikawy i dyskusja piramidowa.","wiki":[{"heading":"Techniki dyskusyjne i grupowe","bullets":["Uproszczona debata oksfordzka - sformalizowana dyskusja, w ktorej dwie druzyny toczą spor wokol postawionej tezy; jedna strona udowadnia jej prawdziwosc, druga ja obala","Odwrocona burza mozgow - zasady klasycznej burzy mozgow stosowane do wyroznienia jak najwiekszej liczby wad obiektu analizy, by je nastepnie wyeliminowac","Metoda 635 - rodzaj brainwritingu: 6 uczestnikow wymysla 3 pomysly w 5 minut, zapisujac je na formularzu przekazywanym osobie po prawej","Dyskusja piramidowa - przechodzenie od pracy indywidualnej, przez pary, czworki, osemki, do wspolnego stanowiska zespolu"]},{"heading":"Metody analizy z wielu perspektyw","bullets":["Technika 6 kapeluszy De Bono - mylenie lateralne; wcielanie sie w 6 rol (bialy - dane, czerwony - emocje, czarny - zagrozenia, zolty - korzysci, zielony - nowe pomysly, niebieski - zarzadzanie procesem)","Metoda 3 krzesel Disneya - analiza z trzech perspektyw: marzyciel, realista i krytyk","Drzewko decyzyjne (mind mapping) - graficzna technika wspomagania decyzji; korzen i galezie prowadzace do kolejnych wierzcholkow, ulatwia strukturyzowanie pomyslow"]},{"heading":"Techniki modyfikacji i analizy przyczyn","bullets":["SCAMPER - akronim siedmiu dzialan: Substitute (zastapic), Combine (polaczyc), Adapt (dostosowac), Modify (zmodyfikowac), Put to another use (zastosowac inaczej), Eliminate (usunac), Reverse (odwrocic)","Diagram Ishikawy (rybia osc) - analiza przyczynowo-skutkowa; 5 skladowych: ludzie, metody, maszyny, materialy, zarzadzanie"]}],"questions":[{"type":"abcd","q":"Na czym polega metoda 635?","options":["Szesciu uczestnikow wymysla po trzy pomysly w ciagu pieciu minut, zapisujac je na przekazywanych formularzach","Trzy osoby debatuja przez szesc rund po piec minut","Szesc kapeluszy zmienia sie co trzy minuty piec razy","Trzech ekspertow ocenia szesc projektow w piec dni"],"correct":0,"explain":"Nazwa wynika z zasad: 6 uczestnikow, 3 pomysly, 5 minut - to rodzaj brainwritingu, w ktorym pomysly nie sa wypowiadane na glos."},{"type":"abcd","q":"Co oznacza litera \"S\" w technice SCAMPER?","options":["Separate - rozdzielic","Simplify - uproscic","Standardize - ujednolicic","Substitute - zastapic"],"correct":3,"explain":"SCAMPER to: Substitute, Combine, Adapt, Modify, Put to another use, Eliminate, Reverse. \"S\" oznacza Substitute (zastapic)."},{"type":"tf","q":"W metodzie 3 krzesel Disneya wystepuja role: marzyciel, inwestor i sprzedawca.","correct":false,"explain":"Trzy role w metodzie Disneya to marzyciel, realista i krytyk — nie inwestor czy sprzedawca."},{"type":"flash","front":"Jakie sa kolory i role kapeluszy w technice 6 kapeluszy De Bono?","back":"Bialy - dane i informacje; czerwony - intuicja i emocje; czarny - zagrozenia; zolty - korzysci; zielony - nowe pomysly; niebieski - zarzadzanie procesem myslowym."}]},{"id":"cwiczenia-pobudzajace-kreatywnosc","track":"przygodowa","category":"outdoor","number":16,"title":"Cwiczenia pobudzajace kreatywne myslenie","summary":"Trzy przykladowe cwiczenia rozwijajace kreatywnosc: trzydziesci kolek, ciag skojarzeniowy logiczny oraz opowiesc logiczna.","wiki":[{"heading":"Trzydziesci kolek","body":"Cwiczenie mozna wykonac indywidualnie lub w grupach. Na szablonie znajduje sie trzydziesci kolek. W jak najkrotszym czasie nalezy narysowac w kazdym cos innego, trzymajac sie jednego tematu, np. \"jesien\" lub \"wakacje\"."},{"heading":"Ciag skojarzeniowy logiczny","body":"Nalezy wybrac dwa rzeczowniki i stworzyc ciag skojarzen, ktory logicznie prowadzi od jednego do drugiego, np.: kloda - drzewo - las - jezioro - wakacje - kolonie - nastolatki - pryszcz."},{"heading":"Opowiesc logiczna","body":"Polega na wymysleniu sensacyjnego naglowka (np. \"Co by bylo, gdyby czlowiek polecial na Marsa\") oraz absurdalnego zakonczenia (np. \"i wlasnie dlatego psy nie jedza czekolady\"), a nastepnie zbudowaniu sensownej opowiesci laczacej naglowek z zakonczeniem."}],"questions":[{"type":"abcd","q":"Na czym polega cwiczenie \"ciag skojarzeniowy logiczny\"?","options":["Na stworzeniu ciagu skojarzen logicznie prowadzacego od jednego wybranego rzeczownika do drugiego","Na narysowaniu rzeczy w trzydziestu kolkach na jeden temat","Na napisaniu opowiesci laczacej naglowek z zakonczeniem","Na ocenie pomyslu z trzech punktow widzenia"],"correct":0,"explain":"Wybiera sie dwa rzeczowniki i buduje ciag skojarzen logicznie prowadzacy od jednego do drugiego, np. kloda - drzewo - las."},{"type":"tf","q":"Cwiczenie \"trzydziesci kolek\" mozna wykonywac zarowno indywidualnie, jak i w grupach.","correct":true,"explain":"W opisie cwiczenia wprost zaznaczono, ze mozna je wykonac zarowno indywidualnie, jak i w grupach."},{"type":"flash","front":"Na czym polega cwiczenie \"opowiesc logiczna\"?","back":"Na wymysleniu sensacyjnego naglowka i absurdalnego zakonczenia, a nastepnie zbudowaniu sensownej opowiesci laczacej jedno z drugim."}]},{"id":"tramping-backpacking-hiking","track":"przygodowa","category":"outdoor","number":17,"title":"Tramping, backpacking, hiking - pojecia, podobienstwa i roznice","summary":"Trzy formy podrozowania: tramping (tanie wyprawy w malych grupach z planem), backpacking (indywidualne, samodzielne podroze z plecakiem) oraz hiking (krotkie, jednodniowe wedrowki).","wiki":[{"heading":"Tramping","body":"Tramping oznacza niezalezne i tanie organizowanie wypraw w bliskim kontakcie z natura, lokalnymi kulturami i mieszkancami. Slowo pochodzi od angielskiego \"to tramp\" - wedrowac, wloczyc sie; termin zaczeto uzywac w Nowej Zelandii i Australii na poczatku XX wieku.","bullets":["Podrozowanie w niewielkich grupach, zazwyczaj do 12 osob","Organizacja noclegow i przejazdow przez biuro, opcje przystepne cenowo","Rozne srodki transportu: pociagi, autobusy, taksowki, jeepy, lodzie, promy, riksze","Noclegi w hotelach 3-gwiazdkowych, motelach, czasem jurtach, namiotach lub domach mieszkancow","Trwa zazwyczaj dluzej niz tydzien; duza elastycznosc i spontanicznosc"]},{"heading":"Backpacking","body":"Forma turystyki oznaczajaca aktywnosc podroznicza na danym obszarze bez nadmiernego wydawania pieniedzy, czesto pieszo, z rzeczami w plecaku. Wymaga umiejetnosci poslugiwania sie sprzetem oraz przygotowania fizycznego i psychicznego. Backpackersi czesto okreslaja sie mianem antyturystow, podrozuja samotnie lub w malych grupach. Polska wersja backpackingu jest tramping - pojecie wprowadzone do opracowan turystycznych w 1975 roku przez Bogdana Opowicza. Roznica: tramping zazwyczaj realizowany jest w grupach i ma z gory opracowany zarys lub cel.","bullets":["Turysta sam organizuje wyjazd, nie kupuje gotowego pakietu uslug","Stoi w opozycji do turystyki masowej","Szansa na realizacje idei turystyki zrownowazonej","Zagrozenia: \"efekt gapowicza\", pobiezne poznanie kultury, pogardliwe podejscie do innych turystow"]},{"heading":"Hiking","body":"Piesza wedrowka w terenie naturalnym, zazwyczaj poza miastem, na wyznaczonych szlakach, trwajaca zazwyczaj jeden dzien. Najczesciej forma rekreacji i przyjemnego spedzania czasu na swiezym powietrzu.","bullets":["Krotkie, zazwyczaj jednodniowe wyprawy w lasach, gorach, parkach krajobrazowych, terenach wiejskich","Nie wymaga specjalnego przygotowania fizycznego ani dlugotrwalego treningu","Zazwyczaj bez noclegow w terenie; dostepny dla wszystkich bez wzgledu na wiek","Roznica wobec trekkingu: trekking ma wyzszy prog wejscia, odbywa sie na wymagajacych terenach i trwa kilka dni"]}],"questions":[{"type":"abcd","q":"Czym rozni sie tramping od backpackingu?","options":["Tramping odbywa sie wylacznie samotnie i bez planu","Tramping jest zawsze drozszy od turystyki masowej","Tramping zazwyczaj realizowany jest w grupach i ma z gory opracowany zarys lub cel","Tramping nie wymaga zadnego transportu"],"correct":2,"explain":"Tramping (polska wersja backpackingu) rozni sie tym, ze wyjazd realizowany jest w grupach oraz ma z gory opracowany zarys lub cel."},{"type":"abcd","q":"Ile osob liczy zazwyczaj grupa trampingowa?","options":["Co najmniej 30 osob","Do 50 osob","Dokladnie 6 osob","Do 12 osob"],"correct":3,"explain":"Tramping to podrozowanie w niewielkich grupach, zazwyczaj do 12 osob."},{"type":"tf","q":"Hiking to zazwyczaj wielotygodniowa, wymagajaca wyprawa, ktora wymaga dlugotrwalego treningu i specjalistycznego sprzetu.","correct":false,"explain":"To raczej opis dlugich wypraw/trekkingu; hiking to krotkie, zwykle jednodniowe wedrowki na wyznaczonych szlakach, bez specjalnego przygotowania."},{"type":"flash","front":"Skad pochodzi slowo \"tramping\" i kto wprowadzil pojecie \"tramping\" do polskich opracowan turystycznych?","back":"Slowo pochodzi od angielskiego \"to tramp\" (wedrowac, wloczyc sie); termin zaczeto uzywac w Nowej Zelandii i Australii na poczatku XX wieku. Do polskich opracowan turystycznych pojecie wprowadzil Bogdan Opowicz w 1975 roku."}]},{"id":"prawne-aspekty-projektow-outdoorowych","track":"przygodowa","category":"outdoor","number":18,"title":"Prawne aspekty projektow outdoorowych","summary":"Projekty outdoorowe wymagaja licznych prawnych obowiazkow: pozwolen administracyjnych, zgodnosci z prawem budowlanym, ochrony srodowiska, prawa wlasnosci, bezpieczenstwa oraz zgloszen wydarzen.","wiki":[{"body":"Projekty outdoorowe w turystyce i rekreacji (np. trasy rowerowe, sciezki edukacyjne, wieze widokowe, miejsca piknikowe, silownie plenerowe, wypozyczalnie sprzetu wodnego) sa popularne, ale wymagaja spelnienia wielu prawnych obowiazkow ze wzgledu na lokalizacje (czesto w srodowisku naturalnym) i funkcje publiczna. Dla otwartych obiektow zalecane jest opracowanie wewnetrznego regulaminu korzystania lub posiadanie odpowiednich atestow."},{"heading":"Kluczowe dokumenty i podstawy prawne","bullets":["Pozwolenia administracyjne i planowanie przestrzenne - zgodnosc z miejscowym planem zagospodarowania przestrzennego lub decyzja o warunkach zabudowy (Ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym)","Prawo budowlane - pozwolenie na budowe (wieze widokowe, budynki zaplecza), zgloszenie budowy (wiaty, mala architektura) lub zwolnienie (np. oznakowanie szlakow) (Ustawa z 7 lipca 1994 r. - Prawo budowlane)","Ochrona srodowiska i przyrody oraz wycinka drzew - lokalizacja w terenach chronionych lub lasach panstwowych wymaga zgod, np. Regionalnej Dyrekcji Ochrony Srodowiska (Ustawa z 16 kwietnia 2004 r. o ochronie przyrody)","Prawo wlasnosci i dostepnosc terenu - prawo do dysponowania nieruchomoscia: wlasnosc, dzierzawa, uzyczenie (Kodeks cywilny)","Bezpieczenstwo - wymogi bezpieczenstwa konstrukcyjnego, przeciwpozarowego i sanitarnego (Prawo budowlane)","Zgloszenia wydarzen outdoorowych - splywy, rajdy, pikniki masowe wymagaja zgloszenia do gminy lub organow porzadkowych (Ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r.)"]}],"questions":[{"type":"abcd","q":"Ktora ustawa stanowi podstawe prawna ochrony srodowiska i przyrody przy projektach outdoorowych?","options":["Ustawa z 16 kwietnia 2004 r. o ochronie przyrody","Ustawa z 7 lipca 1994 r. - Prawo budowlane","Ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym","Ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r."],"correct":0,"explain":"Ochrona srodowiska i przyrody oraz wycinka drzew opieraja sie na Ustawie z 16 kwietnia 2004 r. o ochronie przyrody."},{"type":"tf","q":"Organizacja masowego spływu lub rajdu moze wymagac zgloszenia do gminy lub organow porzadkowych na podstawie ustawy o bezpieczenstwie imprez masowych.","correct":true,"explain":"Zgloszenia wydarzen outdoorowych (splyw, rajd, piknik masowy) wymagaja zgloszenia do gminy lub organow porzadkowych - podstawa prawna to ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r."},{"type":"flash","front":"Jaki dokument reguluje prawo do dysponowania nieruchomoscia (wlasnosc, dzierzawa, uzyczenie) przy projekcie outdoorowym?","back":"Kodeks cywilny - reguluje prawo do dysponowania nieruchomoscia na cele budowlane (wlasnosc, dzierzawa, uzyczenie), m.in. poprzez umowy cywilnoprawne."}]},{"id":"rodzaje-turystyki-trekkingowej","track":"przygodowa","category":"outdoor","number":19,"title":"Rodzaje turystyki trekkingowej","summary":"Trekking dzieli sie wg pory roku (letni, zimowy) oraz wg miejsca wyprawy: klasyczny, pustynny, tropikalny, lodowcowy, polarny, rzeczny, bagienny i wulkaniczny.","wiki":[{"heading":"Podzial wg pory roku","bullets":["Trekking letni - mniej ubran i sprzetu z uwagi na wyzsza temperature, lzejszy ekwipunek; konieczna ochrona przed sloncem (kremy, czapki)","Trekking zimowy - wymaga wiekszych umiejetnosci, odziezy warstwowej, specjalistycznego sprzetu (raki, czekany); wiaze sie z ryzykiem lawinowym i mrozem"]},{"heading":"Podzial wg miejsca (m.in. wg P. Rozyckiego)","bullets":["Klasyczny (gorski) - forma posrednia miedzy wspinaczka a turystyka piesza, wymaga przygotowania psychofizycznego, czesto trwa kilka dni","Pustynny - skrajne temperatury, monotonia krajobrazu, burze piaskowe; dla doswiadczonych trekkerow, np. Wadi Rum w Jordanii","Tropikalny - gęste lasy i dzungle, klimat rownikowy, wilgoc; zagrozenia: burze, ulewy, owady i choroby zakazne (malaria)","Lodowcowy - niebezpieczny teren w strefach polarnych i wysokich gorach; ryzyko poslizgniecia i wpadniecia w szczeline, np. Chamonix w Alpach","Polarny - ekstremalnie niskie temperatury, arktyczne tundry; cel: biegun, zorza polarna; np. Spitsbergen, polnocna Skandynawia","Rzeczny (rafting) - na rwacych rzekach, na pontonach lub tratwach; ryzyko: prady wodne, sliski teren, duze predkosci; np. Lena na Syberii","Bagienny - krotka wyprawa przez podmokly teren z kijkami i przewodnikiem; trudnosci: brak solidnego podloza, osuwiska, komary; np. Biebrza, Amazonka","Wulkaniczny - po wygaslych (podobny do klasycznego) lub aktywnych wulkanach (czesto po zmroku); ryzyko: toksyczne gazy, erupcja, np. Teide na Teneryfie"]}],"questions":[{"type":"abcd","q":"Ktory rodzaj trekkingu znany jest rowniez jako rafting?","options":["Pustynny","Bagienny","Lodowcowy","Rzeczny"],"correct":3,"explain":"Trekking rzeczny znany jest rowniez jako rafting - uprawiany na rwacych rzekach na pontonach lub tratwach, np. na syberyjskiej Lenie."},{"type":"abcd","q":"Jakie glowne zagrozenie zdrowotne wiaze sie z trekkingiem tropikalnym?","options":["Ryzyko lawinowe i odmrozenia","Owady i przenoszone przez nie choroby zakazne, np. malaria","Burze piaskowe i odwodnienie","Toksyczne gazy wulkaniczne"],"correct":1,"explain":"W trekkingu tropikalnym niebezpieczenstwo stanowia zwierzeta, szczegolnie owady i przenoszone przez nie choroby zakazne, np. malaria."},{"type":"tf","q":"Trekking zimowy wymaga specjalistycznego sprzetu, takiego jak raki i czekany, oraz wiaze sie z ryzykiem lawinowym.","correct":true,"explain":"Trekking zimowy wymaga odziezy warstwowej i specjalistycznego sprzetu (raki, czekany), a takze wiaze sie z ryzykiem lawinowym i mrozem."},{"type":"flash","front":"Wymien rodzaje trekkingu wedlug podzialu ze wzgledu na miejsce wyprawy.","back":"Klasyczny (gorski), pustynny, tropikalny, lodowcowy, polarny, rzeczny (rafting), bagienny i wulkaniczny."}]},{"id":"roznice-konflikty-kulturowe","track":"przygodowa","category":"outdoor","number":20,"title":"Roznice i konflikty kulturowe we wspolczesnym swiecie","summary":"Roznice kulturowe sa zrodlem bogactwa i konfliktow; ich podloze stanowia m.in. etnocentryzm, stereotypy, uprzedzenia i ksenofobia, a domenami konfliktow sa terytorium, jezyk i religia.","wiki":[{"body":"Roznice kulturowe sa powszechne i stanowia zarowno zrodlo bogactwa, jak i potencjalnych konfliktow. Wzrost migracji, globalizacja i wieksza swiadomosc innych kultur prowadza do wiekszej ekspozycji na roznice, ale takze do napiec. Konflikty moga wynikac ze zderzenia kultur, np. podroze w celu zobaczenia \"dzikiego\", spotkanie kultur religijnych, zderzenie codzienne czy zderzenie stereotypowe."},{"heading":"Zjawiska prowadzace do konfliktow","bullets":["Etnocentryzm - przekonanie, ze wlasne etno zajmuje centralne, uprzywilejowane miejsce i ocenia innych przez pryzmat wlasnych przekonan","Ludzkie zoo (kanibalizm turystyczny) - traktowanie przedstawicieli innej kultury przedmiotowo, jak atrakcje","Zle pojmowana autentycznosc - turysta nie dopuszcza odstepstw od swojego obrazu tubylca","Stereotypy - uproszczony, emocjonalny i czesto falszywy obraz osoby lub grupy","Uprzedzenie - negatywne nastawienie emocjonalne oparte na stereotypie","Ksenofobia - lek przed poznawaniem nowych, nieznanych osob","Dyskryminacja - skutek uprzedzen, odrzucenie osoby lub grupy","Rasizm - odrzucenie ze wzgledu na kolor skory; Eksterminacja - likwidacja grupy narodowosciowej"]},{"heading":"Zasada DIE i domeny konfliktow","body":"Dla unikania konfliktow wazna jest zasada DIE: Description (opis - to co widze), Interpretation (interpretacja - to co mysle), Evaluation (ewaluacja - to co oceniam). W modelu blednym pomijamy opis i przechodzimy od razu do oceny.","bullets":["Trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia","Spory o terytorium: np. pakistansko-indyjski o Kaszmir, japonsko-rosyjski o Kuryle, argentynsko-brytyjski o Falklandy/Malwiny","Spory o jezyk: np. Flamandowie w Belgii, Katalonczycy w Hiszpanii","Konflikty religijne: miedzy religiami swiatowymi i w ramach odlamow (np. katolicy/protestanci w Irlandii Polnocnej)"]}],"questions":[{"type":"abcd","q":"Co opisuje zasada DIE wspierajaca komunikacje miedzykulturowa?","options":["Opis sytuacji, interpretacje i ewaluacje (description, interpretation, evaluation)","Dialog, integracje i edukacje","Decyzje, implementacje i ewaluacje","Dyskryminacje, izolacje i eksterminacje"],"correct":0,"explain":"Zasada DIE sklada sie z opisu sytuacji (description), interpretacji (interpretation) i ewaluacji (evaluation). Pominiecie opisu prowadzi do konfliktu."},{"type":"abcd","q":"Ktore sa trzy zasadnicze domeny konfliktow kulturowych?","options":["Wiek, plec i wyksztalcenie","Ekonomia, technologia i ekologia","Terytorium, jezyk i religia","Sport, sztuka i nauka"],"correct":2,"explain":"Wyrozniamy trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia."},{"type":"tf","q":"Ksenofilia to lek przed poznawaniem nowych, nieznanych osob, ktory objawia sie izolacja i niecheicia.","correct":false,"explain":"Taki lek to ksenofobia; ksenofilia oznacza przeciwnie — sympatie i upodobanie do tego, co obce i nieznane."},{"type":"flash","front":"Czym jest etnocentryzm?","back":"Postawa i przekonanie, ze wlasne etno (spoleczenstwo) zajmuje centralne, uprzywilejowane miejsce w swiecie, a innych ocenia sie przez pryzmat wlasnych przekonan."}]},{"id":"ryzyka-projektow-turystycznych","track":"przygodowa","category":"outdoor","number":21,"title":"Ryzyka projektow turystycznych","summary":"Ryzyko to mozliwosc wystapienia zdarzenia negatywnie wplywajacego na cele projektu; zarzadzanie nim obejmuje identyfikacje, profilaktyke i reakcje, a ryzyka dziela sie m.in. na ekonomiczne, srodowiskowe, geopolityczne, spoleczne i technologiczne.","wiki":[{"heading":"Definicja i zarzadzanie ryzykiem","body":"Ryzyko to mozliwosc wystapienia zdarzenia, ktore wplynie negatywnie na cele projektu. Celem zarzadzania ryzykiem jest identyfikacja zagrozen, przygotowanie sie do nich (profilaktyka, reakcja) i minimalizacja wplywu/skutkow.","bullets":["Ustanowienie polityk, procedur, systemow i standardow oraz opracowanie dokumentacji (podreczniki, instrukcje, broszury)","Wdrozenie zasad, procedur i standardow (szkolenia, cwiczenia kontrolne, audyty, przeglady)","Identyfikacja ryzyk (jakie, ocena, wplyw, skutki), profilaktyka, scenariusze postepowania i monitorowanie","Zasadnicze techniki: eliminacja, redukcja, transfer lub akceptacja"]},{"heading":"Rodzaje ryzyk","bullets":["Ekonomiczne - inflacja, spadek wartosci walut, zmiany stop procentowych, ogolna sytuacja ekonomiczna","Srodowiskowe - kleski zywiolowe, zmiany klimatu, zanieczyszczenie, ochrona przyrody","Geopolityczne - konflikty, napiecia polityczne, zmiany w polityce migracyjnej","Spoleczne - bezpieczenstwo turystow, zmiany w zachowaniach konsumenckich, zmiany demograficzne, konflikt kulturowy","Technologiczne - cyberataki, awarie systemow informacyjnych, rozwoj nowych technologii","Specyficzne dla turystyki - sezonowosc, konkurencja, zmiany przepisow, jakosc uslug, marketing, bezpieczenstwo i zdrowie turystow, skutki turystyki masowej","Zwiazane z lokalizacja - warunki naturalne, dostepnosc infrastruktury, poziom rozwoju spoleczno-gospodarczego, lokalne tradycje i kultura"]}],"questions":[{"type":"abcd","q":"Ktore z ponizszych to zasadnicze techniki zarzadzania ryzykiem?","options":["Eliminacja, redukcja, transfer lub akceptacja","Inflacja, deflacja, stagnacja i recesja","Identyfikacja, marketing, sprzedaz i serwis","Opis, interpretacja, ewaluacja i ocena"],"correct":0,"explain":"Zasadnicze techniki zarzadzania ryzykiem to eliminacja, redukcja, transfer lub akceptacja."},{"type":"abcd","q":"Do ktorej kategorii ryzyk zalicza sie cyberataki i awarie systemow informacyjnych?","options":["Ekonomicznych","Technologicznych","Srodowiskowych","Geopolitycznych"],"correct":1,"explain":"Ryzyka technologiczne sa zwiazane z cyberatakami, awariami systemow informacyjnych oraz rozwojem nowych technologii i ich wplywem na turystyke."},{"type":"tf","q":"Ryzyko definiuje sie jako zdarzenie, ktore na pewno wystapi i zawsze pozytywnie wplynie na cele projektu.","correct":false,"explain":"Ryzyko to mozliwosc (niepewnosc) wystapienia zdarzenia wplywajacego negatywnie na cele projektu, a nie zdarzenie pewne i korzystne."},{"type":"flash","front":"Wymien glowne rodzaje ryzyk w projektach turystycznych.","back":"Ekonomiczne, srodowiskowe, geopolityczne, spoleczne, technologiczne, specyficzne dla turystyki oraz zwiazane z konkretna lokalizacja."}]},{"id":"turystyka-przygodowa-niepelnosprawnosc","track":"przygodowa","category":"outdoor","number":22,"title":"Specyfika turystyki przygodowej osob z niepelnosprawnoscia","summary":"Turystyka osob z niepelnosprawnoscia to dobrana do potrzeb aktywnosc, ktora wspomaga rehabilitacje i rozwoj; wymaga uwzglednienia stopni niepelnosprawnosci, dostosowania form aktywnosci oraz odpowiedniej metodyki.","wiki":[{"heading":"Stopnie i kategorie niepelnosprawnosci","body":"W Polsce jest 3 miliony osob z prawnie potwierdzona niepelnosprawnoscia. Ustala sie trzy stopnie: znaczny (niezdolnosc do zatrudnienia lub praca w zakladzie chronionym, wymagana stala/dlugotrwala opieka), umiarkowany (praca na przystosowanym stanowisku, czesciowa/okresowa pomoc) i lekki (zdolnosc do zatrudnienia bez potrzeby pomocy).","bullets":["upoSledzeni umyslowo","glusi","niewidomi","niedostosowani spolecznie","przewlekle chorzy somatycznie, nerwowo, psychicznie","osoby z uszkodzeniem narzadu ruchu","osoby z glebszymi zaburzeniami mowy"]},{"heading":"Znaczenie i cele","body":"Turystyka osob z niepelnosprawnoscia to zamierzona, celowa, dobrana do potrzeb aktywnosc fizyczna zwiazana z aktywnoscia krajoznawcza. Glownymi celami sa zmniejszenie skutkow ograniczenia aktywnosci fizycznej oraz zapelnienie czasu wolnego.","bullets":["Wplywa na rozwoj osobowosci, wspomaga i przyspiesza rehabilitacje","Podnosi samopoczucie, sprawnosc i wydolnosc fizyczna oraz przystosowanie spoleczne","Pozwala przezwyciezyc leki i kompleksy, zapobiega wtornym zmianom po zabiegach","Aktywnosc powinna byc: bezpieczna (dostosowana obciazeniowo), zaadaptowana (uwzgledniajaca ograniczenia) i efektywna (rozwijajaca mozliwosci)"]},{"heading":"Czynniki przy programowaniu i metodyka","body":"Programujac aktywnosc nalezy pamietac m.in. o: funkcjach ruchowych i czuciowych, ukladzie sercowo-naczyniowym, termoregulacji, ukladzie oddechowym i wydalniczo-moczowym, autonomicznej dysrefleksji, spastycznosci, stosowanych lekach, osteoporozie oraz koordynacji.","bullets":["Wzbudzanie motywacji i entuzjazmu poprzez stymulacje zdolnosci, zainteresowan i ambicji","Indywidualne traktowanie kazdego cwiczacego i znajomosc jego problemow","Metody nauczania: slowne, kinestetyczne (angazowanie aktywnosci miesniowej, kojarzenie wzrokowo-ruchowe) i wzrokowe (pokaz bezposredni lub multimedialny)"]}],"questions":[{"type":"abcd","q":"Ile stopni niepelnosprawnosci ustala sie w Polsce?","options":["Cztery stopnie","Dwa: ciezki i lekki","Trzy: znaczny, umiarkowany i lekki","Piec stopni"],"correct":2,"explain":"Ustala sie trzy stopnie niepelnosprawnosci: znaczny, umiarkowany i lekki."},{"type":"abcd","q":"Jakie trzy cechy powinna miec aktywnosc turystyczna programowana dla osob z niepelnosprawnoscia?","options":["Bezpieczna, zaadaptowana i efektywna","Tania, krotka i masowa","Spontaniczna, indywidualna i ryzykowna","Sezonowa, lokalna i komercyjna"],"correct":0,"explain":"Aktywnosc powinna byc bezpieczna (dostosowana obciazeniowo), zaadaptowana (uwzgledniajaca ograniczenia uczestnikow) i efektywna (rozwijajaca ich mozliwosci)."},{"type":"tf","q":"Uczestnictwo osob z niepelnosprawnoscia w turystyce wspomaga i przyspiesza proces rehabilitacji.","correct":true,"explain":"Wsrod efektow uczestnictwa wymienia sie wspomaganie i przyspieszanie procesu rehabilitacji oraz podnoszenie sprawnosci i przystosowania spolecznego."},{"type":"flash","front":"Jakie metody nauczania wyroznia sie w pracy z osobami z niepelnosprawnoscia w turystyce?","back":"Metody slowne, kinestetyczne (angazowanie aktywnosci miesniowej, np. kojarzenie wzrokowo-ruchowe) oraz wzrokowe (pokaz bezposredni lub posredni za pomoca srodkow multimedialnych)."}]},{"id":"turystyka-przygodowa-dzieci","track":"przygodowa","category":"outdoor","number":24,"title":"Turystyka przygodowa dzieci","summary":"Organizacja wypoczynku dzieci i młodzieży, obowiązki kadry oraz cele i formy turystyki przygodowej.","wiki":[{"heading":"Podstawa prawna","body":"Organizację wypoczynku dla dzieci i młodzieży określają przepisy ustawy z dnia 7 września 1991 r. o systemie oświaty oraz Rozporządzenie Ministra Edukacji Narodowej z dnia 30 czerwca 2016 r. w sprawie wypoczynku dzieci i młodzieży.","bullets":["termin złożenia zgłoszenia wypoczynku oraz przekazania karty wypoczynku","liczba uczestników w grupie pod opieką jednego wychowawcy","obowiązki kierownika i wychowawcy wypoczynku, w tym prowadzenie dziennika zajęć","program kursów na kierownika albo wychowawcę wypoczynku, wzór karty kwalifikacyjnej i zaświadczenia"]},{"heading":"Limity liczebności grup i terminy zgłoszeń","bullets":["liczba uczestników pod opieką jednego wychowawcy nie może przekraczać 20 osób","dla grupy z dziećmi do 10. roku życia (lub grupy mieszanej z takimi dziećmi) limit wynosi 15 osób","dopuszcza się udział nie więcej niż 2 uczestników niepełnosprawnych lub przewlekle chorych w grupie jednego wychowawcy","zgłoszenie wypoczynku składa się nie później niż na 21 dni przed terminem rozpoczęcia, a dla półkolonii lub wypoczynku za granicą — nie później niż na 14 dni"]},{"heading":"Obowiązki kierownika i wychowawcy","body":"Kierownik kieruje wypoczynkiem, opracowuje plan pracy i rozkład dnia, przydziela zadania kadrze i kontroluje ich wykonanie, zapewnia opiekę od przejęcia dzieci od rodziców do przekazania ich z powrotem oraz nadzoruje bezpieczne i higieniczne warunki. Wychowawca zapoznaje się z kartami kwalifikacyjnymi uczestników, informuje kierownika o ich specjalnych potrzebach, prowadzi dziennik zajęć, opracowuje plan pracy grupy i realizuje program zgodnie z rozkładem dnia."},{"heading":"Cele i formy turystyki przygodowej dzieci","body":"Realizowane cele dzieli się na poznawczo-kształtujące, wychowawcze oraz rekreacyjno-zdrowotne (m.in. wypoczynkowe, restytucyjne, zabawowe, kondycyjne).","bullets":["wycieczki: lekcje (spacery), programowo-dydaktyczne, krajobrazowe, turystyczno-krajoznawcze","turystyka kwalifikowana: piesza, rowerowa, żeglarska, narciarska, motorowa, kajakowa","imprezy turystyki kwalifikowanej: rajd, spływ, rejs, zlot, złaz, biwak, kolonie, imprezy na orientację, obozy wędrowne i stałe","szkoły: zielona, biała/zimowa, ekologiczna"]}],"questions":[{"type":"abcd","q":"Ilu uczestników może maksymalnie pozostawać pod opieką jednego wychowawcy w grupie mieszanej z dziećmi do 10. roku życia?","options":["10 osób","25 osób","20 osób","15 osób"],"correct":3,"explain":"Standardowy limit to 20 osób, ale dla grup z dziećmi do 10. roku życia oraz grup mieszanych z takimi dziećmi limit wynosi 15 osób."},{"type":"tf","q":"Do obowiązków wychowawcy wypoczynku należy prowadzenie dziennika zajęć realizowanych podczas wypoczynku.","correct":true,"explain":"Rozporządzenie nakłada na wychowawcę obowiązek prowadzenia dziennika zajęć, którego wzór określa załącznik nr 5."},{"type":"flash","front":"Jakie akty prawne regulują organizację wypoczynku dzieci i młodzieży?","back":"Ustawa z 7 września 1991 r. o systemie oświaty oraz Rozporządzenie MEN z 30 czerwca 2016 r. w sprawie wypoczynku dzieci i młodzieży."},{"type":"flash","front":"Wymień trzy grupy celów turystyki przygodowej dzieci i młodzieży.","back":"Cele poznawczo-kształtujące, wychowawcze oraz rekreacyjno-zdrowotne."}]},{"id":"typologia-form-aktywnosci-terenowej","track":"przygodowa","category":"outdoor","number":25,"title":"Typologia form aktywności terenowej — twarde i miękkie formy","summary":"Podział aktywności terenowej według poziomu ryzyka na formy miękkie i twarde oraz inne typologie.","wiki":[{"heading":"Podział według poziomu ryzyka","body":"Na podstawie poziomu ryzyka wyróżniono formy twarde i miękkie aktywności terenowej. Formy miękkie uprawiają osoby zainteresowane przeżyciem przygody o niewielkim stopniu ryzyka. Formy twarde charakteryzują się wysokim poziomem ryzyka — np. ryzykiem poważnych obrażeń ciała, a nawet śmierci. Odczucie ryzyka jest jednak pojęciem subiektywnym."},{"heading":"Formy miękkie i twarde","bullets":["miękkie: backpacking, birdwatching, camping, kajakarstwo, wędkarstwo, trekking, bieg na orientację, safari, nurkowanie","twarde: speleologia, wspinaczka skałkowa, wspinaczka lodowa, trekking w niebezpiecznym terenie, spadochroniarstwo, paralotniarstwo"]},{"heading":"Inne typologie","bullets":["według skali: formy małej skali (elementy ekoturystyki), średniej skali (elementy sportowe), dużej skali (cechy turystyki masowej)","według przestrzeni realizacji: w powietrzu (loty balonem), na wodzie (windsurfing), na lądzie (wyprawy rowerowe)"]}],"questions":[{"type":"abcd","q":"Która z wymienionych aktywności należy do form twardych aktywności terenowej?","options":["Birdwatching","Camping","Wspinaczka lodowa","Wędkarstwo"],"correct":2,"explain":"Wspinaczka lodowa charakteryzuje się wysokim poziomem ryzyka, więc zaliczana jest do form twardych; pozostałe to formy miękkie."},{"type":"tf","q":"Odczucie ryzyka w aktywności terenowej jest pojęciem obiektywnym, jednakowym dla wszystkich uczestników.","correct":false,"explain":"Odczucie ryzyka jest pojęciem subiektywnym i różni się w zależności od uczestnika."},{"type":"flash","front":"Według jakiego kryterium dzieli się aktywności terenowe na twarde i miękkie?","back":"Według poziomu ryzyka — formy miękkie mają niewielki stopień ryzyka, twarde wysoki (zagrożenie poważnymi obrażeniami, a nawet śmiercią)."}]},{"id":"wyprawy-trampingowe-zasady-organizacji","track":"przygodowa","category":"outdoor","number":26,"title":"Wyprawy trampingowe — zasady organizacji","summary":"Zasady przygotowania i prowadzenia wyprawy trampingowej: informacje, kontakty lokalne, program i rola pilota.","wiki":[{"heading":"Baza informacji i kontakty lokalne","body":"Podstawą organizacji wypraw trampingowych jest zgromadzenie dużej bazy informacji o miejscu podróży — zarówno o atrakcjach turystycznych, jak i o warunkach panujących w przestrzeni (bezpieczeństwo, pogoda, opłaty). Organizator musi nawiązać kontakty z lokalnymi przedsiębiorcami, aby zorganizować nocleg, transport lub inne usługi."},{"heading":"Program i informacje praktyczne","body":"Program wycieczki powinien być elastyczny i dopasowany do możliwości grupy, która się zgłosi; należy zaznaczyć wymagany poziom sprawności fizycznej i zastrzec sobie prawo do zmian w sytuacjach nieprzewidzianych. Przygotowuje się informacje praktyczne o charakterze wyprawy, przelotach, zakwaterowaniu, transporcie, klimacie, wyżywieniu, ubezpieczeniu, przepisach rezygnacji i kosztach (w tym dodatkowych). Analizuje się dystans i przewyższenia trasy, by oszacować czas potrzebny na pokonanie szlaku, oraz weryfikuje zagrożenia i np. wymagane szczepionki."},{"heading":"Specyfika trampingu i rola pilota","body":"W trampingu dąży się do ograniczenia kosztów — korzysta się z noclegów o niższym standardzie, a wyprawy projektuje dla mniejszych grup. Ważny jest aspekt kulturowy: prawdziwy kontakt uczestników ze społecznością i miejscem. Najważniejszym ogniwem jest rola pilota wyprawy — musi być elastyczny i sprawny w kontaktach międzyludzkich, jest pośrednikiem między turystami, biurem a lokalną społecznością. Tramping wymaga otwartości na dialog międzykulturowy oraz znoszenia trudów podróży, a grupa często wspólnie decyduje o organizacji wyżywienia i mniej istotnych punktów programu."}],"questions":[{"type":"abcd","q":"Co jest podstawą organizacji wyprawy trampingowej?","options":["Wykupienie noclegów o najwyższym standardzie","Ograniczenie kontaktu z lokalną społecznością","Zaplanowanie sztywnego, niezmiennego programu","Zgromadzenie dużej bazy informacji o miejscu podróży"],"correct":3,"explain":"Podstawą jest zgromadzenie dużej bazy informacji o miejscu — o atrakcjach oraz o warunkach (bezpieczeństwo, pogoda, opłaty)."},{"type":"tf","q":"W trampingu dąży się do ograniczenia kosztów, dlatego korzysta się z noclegów o niższym standardzie.","correct":true,"explain":"Tramping nastawiony jest na ograniczenie kosztów — stąd tańsze noclegi i mniejsze grupy."},{"type":"flash","front":"Jaka jest rola pilota w wyprawie trampingowej?","back":"Pilot to najważniejsze ogniwo wyprawy — elastyczny pośrednik między turystami, biurem a lokalną społecznością, dobrze odnajdujący się w kontaktach międzyludzkich."}]},{"id":"wyprawy-trekkingowe-przygotowanie-sprzet","track":"przygodowa","category":"outdoor","number":27,"title":"Wyprawy trekkingowe — przygotowanie, zasady organizacji, sprzęt","summary":"Przygotowanie fizyczne i psychiczne do trekkingu, zasady organizacji wyprawy oraz niezbędny sprzęt.","wiki":[{"heading":"Przygotowanie do trekkingu","body":"Najlepiej zacząć od zdobycia wiedzy merytorycznej o miejscu docelowym (inaczej przygotujemy się na trekking po Saharze, a inaczej na Kilimandżaro). Konieczne jest przygotowanie fizyczne i psychiczne organizmu. W początkowych fazach prowadzi się trening kondycyjny (bieganie wytrzymałościowe, marszobiegi, interwały), zaleca się podstawowe badania (morfologia krwi, badanie moczu, EKG serca), a także ćwiczenia siłowe na duże partie mięśniowe (plecy, brzuch, nogi), ćwiczenia oddechowe i rozciągające. Ważna jest odpowiednia dieta (białko, tłuszcze, węglowodany, witaminy i minerały) oraz równowaga wodno-elektrolitowa. Zdrowie psychiczne buduje się przez stawianie sobie celów i rozwój cech wolicjonalnych."},{"heading":"Zasady organizacji","bullets":["analiza dystansu i przewyższenia — oszacowanie czasu potrzebnego na pokonanie szlaku","powiadomienie osoby bliskiej o celu wyprawy i planowanych ścieżkach","dostosowanie ekwipunku do rodzaju wyprawy (inny zimą, inny latem) — dobór obuwia, plecaka, odzieży","weryfikacja zagrożeń na trasie i poza nią oraz wymaganych szczepionek","dostosowanie kijów trekkingowych do wysokości ciała","dwukrotne sprawdzenie prognoz pogody (na tydzień przed i potwierdzenie dzień przed wylotem)","uwzględnienie kondycji, wieku i poziomu zaawansowania uczestników"]},{"heading":"Niezbędny sprzęt","bullets":["wodoodporny plecak ze stelażem o dużej pojemności; kurtka i spodnie z membraną; odzież termiczna szybkoschnąca","bukłak z wodą (z filtrem lub tabletkami uzdatniającymi), termos, karimata, śpiwór dobrany do miejsca","okulary przeciwsłoneczne, kremy z filtrem, latarka zwykła i czołowa, nóż wielofunkcyjny, ciepłe nakrycie głowy","składane, regulowane kije trekkingowe, mapa i kompas, apteczka, lornetka","buty za kostkę z membraną o sztywnej podeszwie (rozchodzone przed wyjazdem), skarpetki trekkingowe","batony energetyczne i żele, namiot, worki na śmieci, ręcznik szybkoschnący"]}],"questions":[{"type":"abcd","q":"Które z poniższych badań zaleca się wykonać przed trekkingiem, aby wykluczyć przeciwwskazania ze strony układu krążenia?","options":["Tylko pomiar wzrostu i wagi","EKG serca","Badanie wzroku","Test sprawności fizycznej Coopera"],"correct":1,"explain":"Zaleca się podstawowe badania: morfologię krwi, badanie moczu oraz EKG serca, by upewnić się, że nie ma przeciwwskazań związanych z niewydolnością układu krążenia."},{"type":"tf","q":"Nowe buty trekkingowe najlepiej założyć po raz pierwszy dopiero na szlaku, bez wcześniejszego rozchodzenia.","correct":false,"explain":"Buty za kostkę należy rozchodzić przed wyjazdem — zakładanie nowych dopiero na szlaku grozi otarciami i kontuzjami."},{"type":"flash","front":"Dlaczego prognozę pogody przed trekkingiem sprawdza się dwukrotnie?","back":"Sprawdza się ją na tydzień poprzedzający i na tydzień planowanego wyjścia, a następnie potwierdza dzień przed wylotem — to dwukrotna weryfikacja zwiększająca bezpieczeństwo."}]},{"id":"zagospodarowanie-kajaki-zeglarstwo-nurkowanie","track":"przygodowa","category":"outdoor","number":28,"title":"Zagospodarowanie turystyczne dla turystyki kajakowej, żeglarskiej, nurkowania","summary":"Wymagania infrastrukturalne akwenów wodnych dla kajakarstwa, żeglarstwa i nurkowania oraz zasady planowania przestrzennego.","wiki":[{"heading":"Kajakarstwo","body":"Dla wszystkich typów kluczowa jest dostępność akwenów wodnych i odpowiednie zaplecze. Warunki dla kajakarstwa zmieniają się co sezon, a brak infrastruktury może zniechęcić turystów — ważne, by szlaki zachowały naturalność.","bullets":["dostępność i oznakowanie szlaków wodnych dla bezpieczeństwa","miejsca wodowania i wyciągania kajaków","biwaki i pola namiotowe przy trasach wraz z informacją o nich","wypożyczalnie sprzętu i parkingi; spławność rzeki (odpowiednia głębokość i szerokość)","przykłady: Krutynia, Czarna Hańcza, Dordogne we Francji, Abel Tasman National Park w Nowej Zelandii"]},{"heading":"Żeglarstwo","body":"Wymagania infrastrukturalne dla żeglarstwa są bardzo wysokie i kosztowne.","bullets":["porty i przystanie żeglarskie, serwis techniczny i tankowanie","miejsca do cumowania i slipy; szkoły żeglarskie i kapitanaty portów oraz wypożyczalnie sprzętu","punkty gastronomiczne (rejsy trwają kilka dni) oraz informacje pogodowe","przykłady: Wielkie Jeziora Mazurskie, Cyklady (Santorini, Mykonos), Brytyjskie Wyspy Dziewicze na Karaibach"]},{"heading":"Nurkowanie i planowanie przestrzenne","body":"Nurkowanie wymaga specyficznej infrastruktury. Planując przestrzennie dla środowiska naturalnego, należy unikać konfliktów użytkowania przestrzeni, utrzymywać zgodność z planami zagospodarowania i dążyć do zrównoważonego rozwoju. Wyzwaniami pozostają kwestie ekonomiczne, sezonowość, zagrożenia środowiskowe oraz balans między komercjalizacją a ochroną.","bullets":["bazy nurkowe z wypożyczalniami sprzętu; dostęp do łodzi nurkowych z odpowiednią burtą","zaplecze ratunkowe i dekompresyjne; punkty szkoleniowe i certyfikacyjne (PADI, CMAS)","przykłady: Morze Czerwone (Sharm El Sheikh), Wyspy Kanaryjskie (Lanzarote, Teneryfa), Blue Hole na Malcie"]}],"questions":[{"type":"abcd","q":"Które organizacje wymieniono jako wystawiające certyfikaty w nurkowaniu?","options":["IATA i UNWTO","PADI i CMAS","PZŻ i ISO","FIFA i UEFA"],"correct":1,"explain":"W zagospodarowaniu dla nurkowania wymieniono punkty szkoleniowe i certyfikacyjne PADI oraz CMAS."},{"type":"tf","q":"Wymagania infrastrukturalne dla żeglarstwa są minimalne i tanie.","correct":false,"explain":"Przeciwnie — żeglarstwo wymaga portów, slipów, serwisu, szkół, kapitanatów i gastronomii, więc infrastruktura jest bardzo wysoka i kosztowna."},{"type":"flash","front":"Co decyduje o spławności rzeki dla kajakarstwa?","back":"Odpowiednia głębokość i szerokość rzeki — tak, aby dało się nią płynąć."}]},{"id":"zagospodarowanie-turystyka-rowerowa","track":"przygodowa","category":"outdoor","number":29,"title":"Zagospodarowanie turystyczne dla turystyki rowerowej","summary":"Infrastruktura turystyki rowerowej, różnica między ścieżką a szlakiem oraz jej rola w zrównoważonym rozwoju.","wiki":[{"heading":"Potrzebna infrastruktura","bullets":["miejsca postoju rowerów (bezpieczne pozostawienie roweru) oraz wypożyczalnie dostarczające jednolity sprzęt grupom","miejsca obsługi technicznej: serwisy, sklepy z narzędziami, punkty na szlakach (np. do dopompowania kół)","miejsca odpoczynku z właściwym oznakowaniem oraz oznakowane szlaki rowerowe z tabliczkami edukacyjnymi","bazy noclegowe i gastronomiczne przy dłuższych wyprawach","informacje o pogodzie i atrakcjach regionu, ścieżki i wydzielone pasy dla rowerów oraz oświetlenie szlaków na zmrok"]},{"heading":"Ścieżka a szlak; MTB i downhill","body":"Nie każda ścieżka rowerowa to szlak rowerowy i nie każdy szlak to ścieżka — ścieżka to droga przeznaczona dla komunikacji. W przypadku jazdy MTB oraz downhill potrzebne są dodatkowo miejsca wypożyczenia sprzętu, specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe. Przykłady zagospodarowania: Nadwarciański Szlak Rowerowy w Polsce, Cape Epic w RPA, Mai Chau w Wietnamie, Alpe-Adria (Włochy, Austria)."},{"heading":"Rola w zrównoważonym rozwoju","body":"Turystyka rowerowa sprzyja zrównoważonemu rozwojowi — ogranicza negatywny wpływ na środowisko, a tablice przy szlakach podnoszą świadomość ekologiczną i umożliwiają współpracę z lokalnymi społecznościami. Dobrze zaprojektowana infrastruktura podnosi bezpieczeństwo i komfort podróży, promuje walory przestrzeni, zachęca do aktywności fizycznej oraz zwiększa ochronę środowiska."}],"questions":[{"type":"abcd","q":"Co jest potrzebne w turystyce rowerowej obejmującej jazdę MTB oraz downhill, czego zwykle nie wymaga zwykła turystyka rowerowa?","options":["Tylko oznakowane miejsca odpoczynku","Wyłącznie bazy gastronomiczne","Specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe","Jedynie informacje o pogodzie"],"correct":2,"explain":"Dla MTB i downhill potrzebne są dodatkowo miejsca wypożyczenia sprzętu, specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe."},{"type":"tf","q":"Każda ścieżka rowerowa jest jednocześnie szlakiem rowerowym.","correct":false,"explain":"Nie każda ścieżka rowerowa to szlak rowerowy i odwrotnie — ścieżka to droga przeznaczona dla komunikacji."},{"type":"flash","front":"W jaki sposób turystyka rowerowa sprzyja zrównoważonemu rozwojowi?","back":"Ogranicza negatywny wpływ na środowisko, tablice przy szlakach podnoszą świadomość ekologiczną, a sama turystyka umożliwia współpracę z lokalnymi społecznościami."}]},{"id":"fotografia-przygodowa-zasady-techniki","track":"przygodowa","category":"outdoor","number":30,"title":"Zasady i techniki fotografii przygodowej","summary":"Czym jest fotografia przygodowa oraz jej kluczowe zasady kompozycji, ustawień aparatu i techniki wykonania.","wiki":[{"heading":"Czym jest fotografia przygodowa","body":"Fotografia przygodowa skupia się na zdjęciach plenerowych — oszałamiających krajobrazach i zapierających dech sytuacjach — oraz na uchwyceniu sportów ekstremalnych (narciarstwo, wspinaczka górska, kajakarstwo). Kluczowe elementy to dobra kompozycja, świadome użycie światła, wybór odpowiednich ustawień aparatu oraz praktyka i cierpliwość."},{"heading":"Zasady dobrej fotografii","bullets":["zasada trójpodziału — podział kadru na trzy części i umieszczenie elementów na liniach podziału","linie wiodące — prowadzenie wzroku widza ku głównemu obiektowi","ramy — kadrowanie obiektu naturalnymi elementami; zrównoważenie kompozycji","światło naturalne (wschód i zachód słońca) oraz dbałość o kontrast i cień dla głębi i emocji","tryb manualny i kontrola ekspozycji, dobór ISO (unikanie szumu), czasu naświetlania i przysłony (głębia ostrości)"]},{"heading":"Techniki fotografii przygodowej","bullets":["panoramowanie — ruch aparatem do uchwycenia ruchu i dynamiki","długie naświetlanie — efekt rozmycia i zamrażania światła (np. w nocy)","HDR — uchwycenie większego zakresu tonalnego i szczegółów","zamrażanie ruchu — krótki czas naświetlania lub lampa błyskowa","malowanie światłem — kreatywne, artystyczne efekty nocne"]}],"questions":[{"type":"abcd","q":"Na czym polega zasada trójpodziału w fotografii przygodowej?","options":["Na ustawieniu aparatu na trzy różne wartości ISO","Na podziale kadru na trzy równe części i umieszczeniu głównych elementów na liniach podziału","Na wykonaniu trzech zdjęć tego samego ujęcia","Na użyciu trzech źródeł światła jednocześnie"],"correct":1,"explain":"Zasada trójpodziału polega na podziale kadru na trzy równe części (poziomo i pionowo) i umieszczeniu głównych elementów na liniach przecięcia, co daje dynamiczniejszą kompozycję."},{"type":"tf","q":"Technika HDR służy do uchwycenia większego zakresu tonalnego i szczegółów w zdjęciach.","correct":true,"explain":"HDR (High Dynamic Range) pozwala uchwycić szerszy zakres tonalny i więcej szczegółów."},{"type":"flash","front":"Jak ustawienie przysłony wpływa na głębię ostrości?","back":"Szersza przysłona daje mniejszą głębię ostrości, a mniejsza przysłona — większą głębię ostrości."}]},{"id":"rek-wskaznik-antropometryczny","track":"rekreacja","category":"rekreacja-spec","number":1,"title":"Wskaźniki antropometryczne i ich zastosowanie","summary":"Wskaźnik antropometryczny to stosunek dwóch lub więcej pomiarów ciała, który pozwala ocenić jego proporcje, stan odżywienia lub ryzyko chorób.","wiki":[{"heading":"Czym jest wskaźnik antropometryczny","body":"Wskaźnik antropometryczny to stosunek dwóch lub więcej pomiarów ciała, które pozwalają ocenić proporcje ciała, stan odżywienia lub ryzyko chorób. Zasadą tworzenia wskaźników jest ustosunkowanie pomiaru o mniejszej liczbowo wartości do cechy o wartości większej."},{"heading":"Wysokość ciała w ergonomii","body":"Wysokość ciała to cecha wykorzystywana w ergonomii. Właściwości budowy ciała człowieka warunkują kształtowanie struktury przestrzennej miejsca pracy oraz jej elementów składowych: rozmiarów siedzisk i urządzeń pracowniczych oraz optymalnego rozmieszczenia tych elementów względem siebie i względem użytkownika. Pomiary antropometryczne opisują sylwetkę wyprostowaną (antropometria klasyczna: statyczna i dynamiczna) oraz naturalną, jaką przyjmuje człowiek podczas wykonywanej czynności (antropometria ergonomiczna)."},{"heading":"BMI (Indeks Masy Ciała)","body":"BMI (Body Mass Index) to popularny wskaźnik, który pomaga ocenić proporcje masy ciała do wzrostu i jest stosunkowo łatwy w obliczeniach. Uzyskany wynik porównuje się z tabelą i kwalifikuje do jednej z czterech kategorii: niedowaga, waga prawidłowa, nadwaga lub otyłość.","bullets":["ocena masy ciała","rozpoznanie otyłości","pomoc dla specjalistów w planowaniu diety i treningów"]},{"heading":"Ograniczenia BMI","body":"Przy BMI należy pamiętać, że nie rozróżnia on masy mięśniowej od masy tłuszczowej. Przez to wynik BMI osoby ćwiczącej profesjonalnie, na przykład kulturysty, może wskazywać otyłość, choć w rzeczywistości nią nie jest."}],"questions":[{"type":"abcd","q":"Do ilu kategorii kwalifikuje się wynik BMI?","options":["Do trzech","Do pięciu","Do dwóch","Do czterech"],"correct":3,"explain":"Wynik BMI kwalifikuje się do jednej z czterech kategorii: niedowaga, waga prawidłowa, nadwaga lub otyłość."},{"type":"tf","q":"BMI rozróżnia masę mięśniową od masy tłuszczowej.","correct":false,"explain":"BMI nie rozróżnia masy mięśniowej od tłuszczowej, dlatego u kulturysty może błędnie wskazywać otyłość."},{"type":"tf","q":"Zasadą tworzenia wskaźników antropometrycznych jest ustosunkowanie pomiaru o mniejszej wartości liczbowej do cechy o wartości większej.","correct":true,"explain":"To właśnie ta zasada leży u podstaw konstruowania wskaźników antropometrycznych."},{"type":"flash","front":"Czym jest wskaźnik antropometryczny?","back":"To stosunek dwóch lub więcej pomiarów ciała, pozwalający ocenić proporcje ciała, stan odżywienia lub ryzyko chorób."}]},{"id":"rek-nordic-walking-wszechstronnosc","track":"rekreacja","category":"rekreacja-spec","number":2,"title":"Wszechstronność nordic walking","summary":"Nordic walking jest wszechstronną formą aktywności, ponieważ angażuje niemal wszystkie mięśnie ciała, poprawia wydolność oraz wzmacnia stawy i kręgosłup.","wiki":[{"heading":"Dlaczego nordic walking jest wszechstronny","body":"Nordic walking jest wszechstronną formą aktywności ruchowej, ponieważ angażuje niemal wszystkie mięśnie ciała, poprawia wydolność, wzmacnia stawy i kręgosłup, a także pozytywnie wpływa na samopoczucie. To kompleksowa forma aktywności, która przynosi liczne korzyści zdrowotne i może być uprawiana przez każdego, niezależnie od wieku czy poziomu sprawności."},{"heading":"Główne korzyści","bullets":["aktywacja mięśni — angażuje aż do 90% mięśni ciała, w tym rąk, barków, nóg i tułowia, znacznie więcej niż zwykły spacer","poprawa wydolności tlenowej, pracy serca i układu krążenia oraz spalanie kalorii","wzmocnienie stawów i kości — kijki odciążają stawy kolanowe i biodrowe, wzmacniając kości i zapobiegając osteoporozie","poprawa koordynacji i równowagi dzięki skoordynowanemu ruchowi rąk i nóg","redukcja stresu — ruch na świeżym powietrzu sprzyja produkcji endorfin"]},{"heading":"Dostępność i rehabilitacja","body":"Nordic walking jest odpowiedni dla osób w każdym wieku i o różnym poziomie sprawności, a jedyny potrzebny sprzęt to kije i wygodne buty. Może być również pomocny w procesie rehabilitacji po urazach lub operacjach, ponieważ odciąża stawy i pozwala na stopniowy powrót do aktywności fizycznej."}],"questions":[{"type":"abcd","q":"Jaki odsetek mięśni ciała angażuje nordic walking?","options":["Aż do 90%","Około 50%","Aż do 70%","Około 30%"],"correct":0,"explain":"Nordic walking angażuje aż do 90% mięśni ciała, znacznie więcej niż zwykły spacer."},{"type":"tf","q":"Chodzenie z kijkami obciąża stawy kolanowe i biodrowe bardziej niż zwykły spacer.","correct":false,"explain":"Przeciwnie — kijki odciążają stawy kolanowe i biodrowe, jednocześnie wzmacniając kości."},{"type":"tf","q":"Nordic walking może być pomocny w procesie rehabilitacji po urazach lub operacjach.","correct":true,"explain":"Odciąża stawy i pozwala na stopniowy powrót do aktywności fizycznej, dlatego bywa wykorzystywany w rehabilitacji."},{"type":"flash","front":"Jaki sprzęt jest potrzebny do uprawiania nordic walking?","back":"Jedynie kije do nordic walking oraz wygodne buty."}]},{"id":"rek-sport-zjawisko-spoleczne","track":"rekreacja","category":"rekreacja-spec","number":3,"title":"Sport jako zjawisko społeczne","summary":"Sport jest złożonym fenomenem kulturowo-społecznym, który od ponad 2000 lat towarzyszy relacjom społecznym i spełnia wiele funkcji.","wiki":[{"heading":"Sport w świetle ustawy o sporcie","body":"Zgodnie z ustawą z dnia 25 czerwca 2010 r. o sporcie, sportem są wszelkie formy aktywności fizycznej, które przez uczestnictwo doraźne lub zorganizowane wpływają na wypracowanie lub poprawienie kondycji fizycznej i psychicznej, rozwój stosunków społecznych lub osiągnięcie wyników sportowych na wszelkich poziomach. Za sport uważa się również współzawodnictwo oparte na aktywności intelektualnej, którego celem jest osiągnięcie wyniku sportowego."},{"heading":"Sport a kultura fizyczna","body":"Sport wraz z wychowaniem fizycznym i rehabilitacją ruchową składa się na kulturę fizyczną, czyli ogół zachowań przebiegających według przyjętych w danym środowisku reguł i norm, mających na celu dbałość o zdrowie człowieka, poprawę jego postawy i prawidłowy rozwój psychofizyczny. Sport to z założenia pokojowe współzawodnictwo prowadzone zgodnie z zasadami fair play, rozwijające cechy osobowości, takie jak wytrwałość, silna wola, zdyscyplinowanie oraz poczucie solidarności i koleżeństwa."},{"heading":"Funkcje i znaczenie społeczne","bullets":["spełnia wiele funkcji: wychowawczą, integracyjną, zdrowotną, rozrywkową, edukacyjną i terapeutyczną","jest ważnym czynnikiem integrującym różne środowiska społeczne o zasięgu lokalnym, regionalnym i międzynarodowym","przyczynił się do rozwoju budownictwa sportowego oraz przemysłowej produkcji sprzętu","od ponad 2000 lat towarzyszy relacjom społecznym i kulturowym, stając się ich nieodłączną częścią"]},{"heading":"Sport jako przedmiot badań","body":"Sport nie jest jedynie aktywnością fizyczną, lecz złożonym fenomenem kulturowo-społecznym. Analizowany jest przez wiele nauk społecznych i humanistycznych: socjologię, filozofię, psychologię, pedagogikę, historię, politologię, a nawet prawo i ekonomię. Filozofia sportu analizuje jego sens, wartości i bytowość (ontologia), a socjologia bada jego wpływ na strukturę społeczną, role społeczne i tożsamość jednostek."}],"questions":[{"type":"abcd","q":"Które elementy razem ze sportem składają się na kulturę fizyczną?","options":["Turystyka i rekreacja","Wychowanie fizyczne i rehabilitacja ruchowa","Edukacja i rozrywka","Polityka i ekonomia"],"correct":1,"explain":"Sport wraz z wychowaniem fizycznym i rehabilitacją ruchową składa się na kulturę fizyczną."},{"type":"tf","q":"Zgodnie z ustawą o sporcie za sport uważa się również współzawodnictwo oparte na aktywności intelektualnej.","correct":true,"explain":"Ustawa uznaje za sport współzawodnictwo intelektualne, którego celem jest osiągnięcie wyniku sportowego."},{"type":"tf","q":"Sport towarzyszy relacjom społecznym i kulturowym dopiero od około 200 lat.","correct":false,"explain":"Sport jest trwale wpisany w życie społeczne od ponad 2000 lat, a nie od 200 lat."},{"type":"flash","front":"Jakie nauki analizują zjawisko sportu?","back":"Socjologia, filozofia, psychologia, pedagogika, historia, politologia, a nawet prawo i ekonomia."}]},{"id":"rek-narciarstwo-grupy-wiekowe","track":"rekreacja","category":"rekreacja-spec","number":4,"title":"Nauczanie narciarstwa w różnych grupach wiekowych","summary":"Zadania w nauce narciarstwa stopniuje się według wieku i poziomu uczestników — od zabawowego oswajania ze sprzętem u dzieci po spokojne, asekurowane ćwiczenia seniorów.","wiki":[{"heading":"Dzieci (3–12 lat)","body":"Zajęcia rozpoczynają się oswojeniem ze sprzętem: chodzeniem w butach narciarskich, utrzymaniem równowagi i prostymi ślizgami w pług na płaskim terenie. Nauka odbywa się przez zabawę, z krótkimi seriami ćwiczeń (10–15 min) i częstymi przerwami. Trudność stopniuje się od niemal płaskiego terenu do bardzo łagodnych wzniesień, zawsze z asekuracją. Grupy są małe (4–6 osób), a ze względu na wrażliwość na zimno i słabiej rozwinięte mięśnie konieczne są ciepłe przerwy oraz lekki sprzęt."},{"heading":"Młodzież (13–18 lat)","body":"Nastolatki zaczynają od przypomnienia podstaw, przechodząc do ćwiczeń technicznych: płużnych skrętów, slalomu między pachołkami i muld. Nauka odbywa się na stokach zielonych i łatwych niebieskich, z naciskiem na kontrolę prędkości, samodzielne hamowanie i refleks. Po opanowaniu podstaw wprowadza się elementy współzawodnictwa, np. slalom na czas. Grupy liczą 6–10 osób."},{"heading":"Dorośli (19–60 lat)","body":"Lekcję rozpoczyna omówienie sprzętu i zasad bezpieczeństwa (numery GOPR), a następnie demonstracja podstaw: pozycji, trzymania kijków i wstawania z upadku. Ćwiczenia na śniegu prowadzi się stopniowo — od ześlizgu w pług po jazdę łukiem płużnym — z przerwami na stretching. Grupy są małe (4–6 osób), dobrane według kondycji i poziomu lęku, a metoda demonstracyjna i analityczna pozwala na logiczną rozbiórkę ruchu."},{"heading":"Seniorzy (60+)","body":"Zajęcia zaczynają się od łagodnej rozgrzewki stawów, a następnie spokojnych, powtarzanych ćwiczeń na łagodnym stoku, w tym ćwiczeń równowagi. Każdy ruch wykonuje się wolno, z asekuracją i przerwami na kontrolę pulsu oraz ogrzanie. Grupy są bardzo małe (2–4 osoby) lub zajęcia są indywidualne. Ze względu na wolniejszy czas reakcji i pogorszenie równowagi unika się gwałtownych ruchów i nadmiernej prędkości, a przerwy z ciepłymi napojami są obowiązkowe."}],"questions":[{"type":"abcd","q":"Ilu osób liczą zwykle grupy seniorów (60+) na zajęciach narciarskich?","options":["6–10 osób","4–6 osób","2–4 osoby lub zajęcia indywidualne","10–15 osób"],"correct":2,"explain":"Grupy seniorów są bardzo małe — 2–4 osoby — lub zajęcia prowadzone są indywidualnie."},{"type":"tf","q":"U dzieci naukę narciarstwa prowadzi się głównie przez zabawę, z krótkimi seriami ćwiczeń i częstymi przerwami.","correct":true,"explain":"Dzieci uczą się przez zabawę, w krótkich seriach 10–15 min, z częstymi i ciepłymi przerwami."},{"type":"tf","q":"U seniorów ćwiczenia kładą nacisk na gwałtowne ruchy i jazdę z dużą prędkością.","correct":false,"explain":"U seniorów unika się gwałtownych ruchów i nadmiernej prędkości, stawiając na spokojne, asekurowane ćwiczenia."},{"type":"flash","front":"Na jakich stokach uczy się narciarstwa młodzież (13–18 lat)?","back":"Na stokach zielonych i łatwych niebieskich, z naciskiem na kontrolę prędkości i samodzielne hamowanie."}]},{"id":"rek-gry-miejskie-produkt-turystyczny","track":"rekreacja","category":"rekreacja-spec","number":5,"title":"Gry miejskie jako produkt turystyczny","summary":"Gry miejskie to innowacyjna, aktywna alternatywa dla tradycyjnego zwiedzania z przewodnikiem, łącząca poznawanie miasta z integracją i wykonywaniem zadań.","wiki":[{"heading":"Czym są gry miejskie","body":"Gry miejskie są wykorzystywane w branży turystycznej jako bardziej interesująca alternatywa dla tradycyjnego zwiedzania miasta z przewodnikiem. Zakładają aktywne zwiedzanie miasta, włączając w to integrację uczestników. Posługując się przygotowaną przez organizatora mapą z wyznaczoną trasą, uczestnicy mają za cel zdobycie jak największej liczby punktów za wykonane zadania. Gra może mieć bardzo różną formę, np. strategicznej rozgrywki, zabawy integracyjnej, survivalu czy poszukiwania skarbów."},{"heading":"Przykłady poznańskich gier miejskich","bullets":["gry nawiązujące do wydarzeń historycznych — o początkach Państwa Polskiego („Poznań poza Czasem”)","gry o II wojnie światowej („Łamacze szyfrów”, „Enigma”, „Aresztuj Generała”, „Bitwa o Poznań”)","gra o okresie stanu wojennego („Raport z oblężonego miasta”)","gry związane z bieżącymi wydarzeniami, np. Mistrzostwami Europy w Piłce Nożnej 2012 („POZnań 2012”)"]},{"heading":"Projekt „Zwiedzaj grając – graj zwiedzając”","body":"Poznański zespół gramiejska.pl we współpracy z Poznańską Lokalną Organizacją Turystyczną realizuje projekt „Zwiedzaj grając – graj zwiedzając”. Oferta skierowana jest głównie do turystów, ale także do mieszkańców, by promować różne części miasta. Należą do niej m.in. „Pierwszy stopień poznania” (śladami zabytków Ostrowa Tumskiego i Śródki), „Czas patriotów” (szlakiem miejsc Powstania Wielkopolskiego) oraz „Poznań poza czasem” (w obrębie Traktu Królewsko-Cesarskiego)."},{"heading":"Atuty gier miejskich","body":"Gry miejskie wkraczają w fazę dynamicznego rozwoju jako alternatywa dla zwiedzania z przewodnikiem. Rozwiązywanie zadań dodatkowo motywuje do dokładnego poznawania miejsc. Dodatkowym atutem jest zejście z uczęszczanych ścieżek oraz interakcje z lokalnymi mieszkańcami, co raczej nie jest możliwe przy tradycyjnym przewodniku. Dzięki dobrze zaprojektowanej grze miasto może wzmocnić swój przekaz o historii i współczesności."}],"questions":[{"type":"abcd","q":"Co jest głównym celem uczestników gry miejskiej?","options":["Jak najszybsze ukończenie trasy","Spotkanie z przewodnikiem","Zdobycie jak największej liczby punktów za wykonane zadania","Zwiedzanie wyłącznie głównych zabytków"],"correct":2,"explain":"Uczestnicy, korzystając z mapy z wyznaczoną trasą, dążą do zdobycia jak największej liczby punktów za wykonane zadania."},{"type":"tf","q":"Gry miejskie umożliwiają zejście z uczęszczanych ścieżek oraz interakcje z lokalnymi mieszkańcami.","correct":true,"explain":"To jeden z atutów gier miejskich, trudny do osiągnięcia przy tradycyjnym zwiedzaniu z przewodnikiem."},{"type":"tf","q":"Projekt „Zwiedzaj grając – graj zwiedzając” jest skierowany wyłącznie do mieszkańców Poznania.","correct":false,"explain":"Oferta skierowana jest głównie do turystów, ale także do mieszkańców miasta."},{"type":"flash","front":"Jaką formę mogą przyjmować gry miejskie?","back":"Np. strategicznej rozgrywki, zabawy integracyjnej, survivalu czy poszukiwania skarbów."}]},{"id":"rek-impreza-rekreacyjna-istota-etapy","track":"rekreacja","category":"rekreacja-spec","number":6,"title":"Istota imprezy rekreacyjnej i etapy jej organizacji","summary":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie, a jej przygotowanie przebiega według kolejnych etapów organizacyjnych.","wiki":[{"heading":"Czym jest impreza rekreacyjna","body":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie. Jej organizacja to złożony proces, który wymaga zaangażowania wielu osób, a skuteczna realizacja przyczynia się do pozytywnego doświadczenia uczestników oraz budowania pozytywnego wizerunku organizatora."},{"heading":"Istota imprez rekreacyjnych","bullets":["Rozrywka – poczucie przyjemności odczuwane przez uczestników poprzez udział w wydarzeniu","Relaks – możliwość odpoczynku od ciągłego pełnienia roli w społeczeństwie, czas dla siebie","Integracja społeczna – kontakt z innymi ludźmi o podobnych celach","Aktywność fizyczna – każda dodatkowa ilość ruchu w tygodniu pozytywnie wpływa na organizm","Edukacja – promowanie zdrowego stylu życia i zachęcanie do zdrowych wyborów"]},{"heading":"Etapy organizacji imprezy","bullets":["Pomysł na imprezę – określenie celu i tematu przewodniego wydarzenia","Zdobycie budżetu i pozyskanie sponsorów – kluczowy punkt finansujący przedsięwzięcie","Stworzenie zespołu – podział na grupy oraz podział zadań i odpowiedzialności","Przygotowanie programu i atrakcji – jednocześnie zabezpieczenie medyczne, regulamin oraz promocja i marketing","Koordynacja w dniu imprezy","Podsumowanie imprezy – zebranie opinii, ocena realizacji celów i wnioski na przyszłość"]}],"questions":[{"type":"abcd","q":"W jakim celu organizuje się imprezę rekreacyjną?","options":["Promocji aktywności fizycznej podejmowanej w wolnym czasie","Wyłonienia mistrza w danej dyscyplinie sportu","Wyłącznie pozyskania środków finansowych dla organizatora","Przeprowadzenia badań naukowych nad uczestnikami"],"correct":0,"explain":"Impreza rekreacyjna to wydarzenie organizowane w celu promocji aktywności fizycznej podejmowanej w wolnym czasie."},{"type":"tf","q":"Zdobycie budżetu i pozyskanie sponsorów to ostatni etap organizacji imprezy rekreacyjnej.","correct":false,"explain":"Zdobycie budżetu i pozyskanie sponsorów to jeden z wczesnych etapów; ostatnim etapem jest podsumowanie imprezy."},{"type":"flash","front":"Wymień elementy stanowiące istotę imprez rekreacyjnych.","back":"Rozrywka, relaks, integracja społeczna, aktywność fizyczna oraz edukacja."},{"type":"flash","front":"Co dzieje się na etapie podsumowania imprezy?","back":"Zebranie opinii, ocena realizacji celów oraz wyciągnięcie wniosków na przyszłość."}]},{"id":"rek-walory-poznawcze-narciarstwa-snowboardu","track":"rekreacja","category":"rekreacja-spec","number":7,"title":"Walory poznawcze narciarstwa i snowboardu","summary":"Uprawianie narciarstwa i snowboardu niesie liczne walory poznawcze i turystyczne – od poznawania nowych obszarów po rozwijanie umiejętności i przezwyciężanie własnych słabości.","wiki":[{"heading":"Walory poznawcze i turystyczne","bullets":["Poznawanie nowych obszarów oraz obcowanie z naturą","Nauka lub rozwijanie umiejętności jazdy, koordynacji ruchowej i równowagi","Rozwijanie umiejętności analitycznych i nawigacyjnych – planowanie trasy, ocena warunków, szybkie podejmowanie decyzji podczas zjazdów","Przezwyciężanie słabości – zjazdy z trudnych i stromych stoków w trudnych warunkach","Walory zdrowotne – ruch na świeżym powietrzu w połączeniu z krajobrazem gór wpływa pozytywnie także na zdrowie psychiczne","Integracja z bliskimi i innymi ludźmi","Doświadczanie radości i przyjemności z ruchu"]}],"questions":[{"type":"abcd","q":"Które umiejętności rozwija planowanie trasy i ocena warunków podczas jazdy?","options":["Wyłącznie umiejętności językowe","Umiejętności analityczne i nawigacyjne","Wyłącznie siłę mięśniową","Umiejętności kulinarne"],"correct":1,"explain":"Planowanie trasy i ocena warunków rozwijają umiejętności analityczne i nawigacyjne oraz szybkie podejmowanie decyzji podczas zjazdów."},{"type":"tf","q":"Ruch na świeżym powietrzu w górach pozytywnie wpływa także na zdrowie psychiczne.","correct":true,"explain":"Do walorów zdrowotnych zalicza się ruch na świeżym powietrzu, który w połączeniu z krajobrazem gór wpływa pozytywnie również na zdrowie psychiczne."},{"type":"flash","front":"Na czym polega walor poznawczy \"przezwyciężanie słabości\" w narciarstwie i snowboardzie?","back":"Na podejmowaniu zjazdów z trudnych i bardziej stromych stoków oraz w trudnych warunkach."}]},{"id":"rek-zaleznosci-rekreacja-praca","track":"rekreacja","category":"rekreacja-spec","number":8,"title":"Zależności pomiędzy rekreacją a pracą","summary":"Rekreacja i praca są ze sobą powiązane w sposób wpływający na efektywność i samopoczucie – rekreacja redukuje stres, ale nadmierne skupienie na pracy ogranicza czas na odpoczynek.","wiki":[{"heading":"Wzajemne powiązanie","body":"Rekreacja i praca są ze sobą powiązane w sposób, który może wpływać na efektywność i samopoczucie. Z jednej strony rekreacja pomaga w redukcji stresu i wypalenia zawodowego, co przekłada się na większą wydajność w pracy. Z drugiej strony nadmierne skupienie na pracy może ograniczać czas na aktywności rekreacyjne, co negatywnie wpływa na zdrowie psychiczne i fizyczne."},{"heading":"Zależności między pracą a rekreacją","bullets":["Redukcja stresu i wypalenia zawodowego","Poprawa koncentracji i kreatywności dzięki regeneracji umysłu","Wzrost motywacji i zaangażowania dzięki równowadze praca–życie prywatne","Poprawa zdrowia psychicznego i fizycznego","Budowanie relacji społecznych","Zwiększenie produktywności","Rozwój osobisty i większa satysfakcja z życia","Odskocznia od rutyny i codziennych obowiązków"]}],"questions":[{"type":"abcd","q":"Jaki wpływ na pracę ma redukcja stresu osiągana dzięki rekreacji?","options":["Obniża wydajność w pracy","Nie ma żadnego wpływu na pracę","Przekłada się na większą wydajność w pracy","Powoduje wypalenie zawodowe"],"correct":2,"explain":"Rekreacja pomaga w redukcji stresu i wypalenia zawodowego, co przekłada się na większą wydajność w pracy."},{"type":"tf","q":"Nadmierne skupienie na pracy korzystnie zwiększa ilość czasu przeznaczanego na aktywności rekreacyjne.","correct":false,"explain":"Przeciwnie – nadmierne skupienie na pracy ogranicza czas na aktywności rekreacyjne, co negatywnie wpływa na zdrowie psychiczne i fizyczne."},{"type":"flash","front":"W jaki sposób odpoczynek i aktywność rekreacyjna wpływają na umysł pracownika?","back":"Sprzyjają regeneracji umysłu, co przekłada się na lepszą koncentrację i kreatywność w pracy."},{"type":"flash","front":"Dlaczego rekreacja sprzyja budowaniu relacji społecznych?","back":"Czas wolny spędzany z rodziną i przyjaciółmi oraz udział w zajęciach rekreacyjnych w grupie sprzyja budowaniu i wzmacnianiu relacji, co jest ważne dla dobrostanu."}]},{"id":"rek-zasady-ekonomiczne-w-rekreacji","track":"rekreacja","category":"rekreacja-spec","number":9,"title":"Zasady ekonomiczne w rekreacji","summary":"Ekonomika rekreacji analizuje mechanizmy rządzące wykorzystaniem czasu wolnego i świadczeniem usług rekreacyjnych, czerpiąc z ekonomiki przedsiębiorstw.","wiki":[{"heading":"Ekonomika rekreacji","body":"Ekonomika rekreacji analizuje zasady i mechanizmy rządzące wykorzystaniem czasu wolnego oraz świadczeniem usług rekreacyjnych. Jej podstawy teoretyczne czerpią z ekonomiki przedsiębiorstw."},{"heading":"Zasady ekonomiczne w rekreacji","bullets":["Prawo popytu i podaży – im wyższa cena, tym mniejszy popyt, a większa podaż","Zasada ograniczoności zasobów – zasoby są rzadkie, więc trzeba odpowiadać na pytania: co, jak, ile i dla kogo produkować","Zasada racjonalnego gospodarowania – maksymalizacja efektu przy danych nakładach lub minimalizacja nakładów przy danych efektach","Zasada kosztu alternatywnego – koszt utraconych możliwości wynikający z wyboru jednego dobra zamiast innego","Zasada równowagi – przy pełnym wykorzystaniu zasobów zachodzi równość między podażą dóbr i usług a popytem na nie"]},{"heading":"Przykłady zastosowania","body":"Przykładem prawa popytu i podaży jest klub fitness, który po podniesieniu ceny karnetu uruchamia dodatkowe zajęcia wieczorne. Kosztem alternatywnym płatnych zajęć jogi w sobotę rano jest rezygnacja z bezpłatnego spaceru z rodziną – nie tylko pieniądze, ale i czas. Zasadę równowagi ilustruje gmina ustalająca opłatę za wejście do parku tak, by pokryć koszty utrzymania bez nadwyżki ani deficytu."}],"questions":[{"type":"abcd","q":"Z czego czerpie swoje podstawy teoretyczne ekonomika rekreacji?","options":["Z biologii sportu","Z psychologii społecznej","Z teorii prawa pracy","Z ekonomiki przedsiębiorstw"],"correct":3,"explain":"Podstawy teoretyczne ekonomiki rekreacji czerpią z ekonomiki przedsiębiorstw."},{"type":"tf","q":"Charakterystyczną cechą zasobów jest ich rzadkość, dlatego trzeba nimi umiejętnie gospodarować.","correct":true,"explain":"Zasada ograniczoności zasobów wskazuje, że zasoby są rzadkie i ich ilość jest ograniczona, więc społeczeństwo musi nimi umiejętnie gospodarować."},{"type":"abcd","q":"Czego dotyczy zasada kosztu alternatywnego?","options":["Ilości innego dobra, którego nie można uzyskać wskutek wyboru danego dobra","Łącznej sumy wszystkich kosztów stałych przedsiębiorstwa","Maksymalnej ceny, jaką klient zapłaci za usługę","Liczby pracowników potrzebnych do realizacji usługi"],"correct":0,"explain":"Koszt alternatywny danego dobra to ilość innego dobra, którego nie można uzyskać, ponieważ podjęto decyzję o wyborze tego pierwszego; bywa nazywany kosztem utraconych możliwości."},{"type":"flash","front":"Na czym polega zasada racjonalnego gospodarowania?","back":"Na alokowaniu ograniczonych zasobów tak, by zmaksymalizować efekt przy założonych nakładach lub zminimalizować nakłady przy założonych efektach."}]},{"id":"rek-niska-temperatura-gory-wysilek","track":"rekreacja","category":"rekreacja-spec","number":10,"title":"Znaczenie niskiej temperatury w górach podczas wysiłku","summary":"W warunkach górskich organizm broni temperatury ciała poprzez obwodową wazokonstrykcję i termogenezę, jednak chłód obniża funkcje mięśni, koordynację i sprawność umysłową oraz grozi hipotermią.","wiki":[{"heading":"Reakcje obronne organizmu","body":"Pierwszą reakcją na zimno jest obwodowa wazokonstrykcja – skurcz naczyń w skórze, a przy większym wychłodzeniu także w mięśniach i narządach wewnętrznych. Powoduje to centralizację krążenia, czyli kierowanie przepływu krwi do najważniejszych narządów: mózgu, serca i płuc, kosztem kończyn. Skóra wraz z podskórną tkanką tłuszczową tworzy izolujący \"płaszcz\" ograniczający utratę ciepła."},{"heading":"Termogeneza","body":"Gdy ochłodzenie postępuje, pojawia się termogeneza drżeniowa – mimowolne drżenie mięśni, które nawet 2,5-krotnie podnosi tempo metabolizmu i może zwiększyć spalanie węglowodanów niemal sześciokrotnie. Równocześnie termogeneza bezdrżeniowa, pobudzona wzrostem poziomu noradrenaliny, adrenaliny, glukagonu i trijodotyroniny, przyspiesza metabolizm bez drżeń. Szybkie zużycie glikogenu podczas wielogodzinnego wysiłku może jednak prowadzić do nagłego spadku sił."},{"heading":"Wpływ na mięśnie i koordynację","bullets":["Dyskomfort zaczyna się przy temperaturze skóry poniżej 25 °C","Siła mięśni spada o około 3% na każdy spadek temperatury ciała o 1 °C, a mięśnie stają się sztywne","Chłód wydłuża czas przewodzenia nerwowego – pojawiają się zaburzenia koordynacji i wolniejsze reakcje","Mimo chłodu dochodzi do odwodnienia – przez pocenie, suche powietrze i zwiększoną diurezę"]},{"heading":"Zagrożenia i przeciwdziałanie","body":"Długotrwałe przebywanie w niskiej temperaturze i wilgoci grozi hipotermią (spadek temperatury ciała poniżej 35 °C) oraz odmrożeniami, najczęściej palców rąk i stóp, nosa i małżowin usznych. Zimno obniża też sprawność umysłową: orientację w terenie, pamięć i szybkość decyzji. Aby temu przeciwdziałać, należy stosować odzież wielowarstwową i termoaktywną, dbać o regularne nawadnianie oraz planować tempo i przerwy umożliwiające regenerację."}],"questions":[{"type":"abcd","q":"Na czym polega centralizacja krążenia będąca reakcją organizmu na zimno?","options":["Na kierowaniu przepływu krwi do mózgu, serca i płuc kosztem kończyn","Na rozszerzeniu naczyń krwionośnych w skórze","Na całkowitym zatrzymaniu przepływu krwi do mózgu","Na równomiernym rozprowadzeniu krwi po całym ciele"],"correct":0,"explain":"Na skutek skurczu naczyń krew kierowana jest do najważniejszych narządów – mózgu, serca i płuc – kosztem mniej istotnych części ciała, np. kończyn."},{"type":"tf","q":"Siła mięśni rośnie o około 3% na każdy spadek temperatury ciała o 1 °C.","correct":false,"explain":"Jest odwrotnie – siła mięśni spada o około 3% na każdy spadek temperatury ciała o 1 °C, a mięśnie stają się sztywne i mniej elastyczne."},{"type":"tf","q":"Mimo chłodu w górach może dochodzić do odwodnienia organizmu.","correct":true,"explain":"Intensywne pocenie podczas podejścia, wysuszające powietrze oraz zwiększona diureza prowadzą do odwodnienia mimo niskiej temperatury."},{"type":"flash","front":"Jak należy przeciwdziałać skutkom niskiej temperatury podczas wysiłku w górach?","back":"Stosować odzież wielowarstwową i termoaktywną, dbać o regularne nawadnianie oraz planować tempo i przerwy umożliwiające regenerację i utrzymanie temperatury ciała."}]},{"id":"rek-cwiczenia-nadmierna-masa-ciala","track":"rekreacja","category":"rekreacja-spec","number":11,"title":"Ćwiczenia i aktywność dla osób z nadmierną masą ciała","summary":"Najistotniejsze zasady doboru ćwiczeń oraz zalecane formy aktywności fizycznej dla osób z nadwagą i otyłością, od konsultacji lekarskiej po dobór wysiłku tlenowego.","wiki":[{"heading":"Definicja i ocena","body":"Nadwaga i otyłość to nieprawidłowe lub nadmierne gromadzenie się tłuszczu, które stanowi zagrożenie dla zdrowia i zwiększa ryzyko wielu chorób niezakaźnych (cukrzyca, choroby sercowo-naczyniowe, niektóre nowotwory). Powszechnym wskaźnikiem oceny jest BMI, obrazujący stosunek masy ciała do wzrostu. Według klasyfikacji WHO osoby dorosłe z BMI 30 lub więcej są uznawane za otyłe, a z wynikiem 25 lub więcej — za osoby z nadwagą."},{"heading":"Zasady doboru ćwiczeń","bullets":["przed rozpoczęciem aktywności konieczna jest konsultacja lekarska w celu diagnozy chorób i przeciwwskazań","dobór ćwiczeń indywidualny — na podstawie możliwości, zdrowia, upodobań i stopnia otyłości","ćwiczenia powinny być dla pacjenta przyjemne i niesprawiające trudności, angażujące jak najwięcej grup mięśniowych","zajęcia grupowe motywują do systematyczności i poprawiają aspekt psychiczny i społeczny","w pierwszej kolejności zaleca się ćwiczenia w wodzie oraz jazdę na rowerze, które odciążają stawy kończyn dolnych i kręgosłup","podczas ćwiczeń nie wolno wstrzymywać oddechu — należy oddychać wolno i głęboko"]},{"heading":"Formy i intensywność aktywności","body":"Aktywność dzieli się na codzienną (każda forma ruchu, np. wchodzenie po schodach, unikanie wind, pieszy spacer) oraz planowaną. Według Brownella aktywność planowana powinna uwzględniać rodzaj, intensywność, czas trwania i częstotliwość. Typowe są ćwiczenia ogólnokondycyjne o średniej lub niskiej intensywności, angażujące duże grupy mięśniowe i wykonywane cyklicznie. Tętno docelowe do spalania tkanki tłuszczowej to 60-70% tętna maksymalnego. Zaleca się co najmniej 30 minut ćwiczeń o średniej intensywności dziennie, w miarę możliwości codziennie.","bullets":["metoda walk and talk: możliwość prowadzenia rozmowy podczas wysiłku świadczy o jego tlenowym charakterze","obowiązuje zasada, że jakakolwiek aktywność fizyczna jest lepsza niż żadna"]}],"questions":[{"type":"abcd","q":"Jaki zakres tętna maksymalnego stanowi tętno docelowe do ćwiczeń na spalanie tkanki tłuszczowej?","options":["40-50%","50-60%","60-70%","80-90%"],"correct":2,"explain":"Według źródła tętno docelowe do ćwiczeń na spalanie tkanki tłuszczowej to 60-70% tętna maksymalnego."},{"type":"abcd","q":"Jaką wartość BMI WHO przyjmuje jako granicę otyłości u osób dorosłych?","options":["25 lub więcej","28 lub więcej","30 lub więcej","35 lub więcej"],"correct":2,"explain":"Według klasyfikacji WHO osoby dorosłe z BMI wynoszącym 30 lub więcej są uznawane za otyłe, a z wynikiem 25 lub więcej — za osoby z nadwagą."},{"type":"tf","q":"Osoby z nadwagą i otyłością przed przystąpieniem do aktywności fizycznej powinny udać się na konsultację lekarską.","correct":true,"explain":"Źródło wskazuje, że w pierwszej kolejności należy udać się na konsultację lekarską w celu diagnozy chorób i przeciwwskazań do konkretnych aktywności."},{"type":"flash","front":"Wymień cechy ćwiczeń ogólnokondycyjnych stosowanych w leczeniu otyłości.","back":"Średni lub niski poziom intensywności (zakres docelowego tętna treningowego), efektywne zużycie tlenu przez pracujące mięśnie, angażowanie dużych grup mięśniowych kurczących się naprzemiennie oraz cykliczność i możliwość długotrwałego wysiłku bez przerw."}]},{"id":"rek-planowanie-dzialalnosci-rekreacyjnej","track":"rekreacja","category":"rekreacja-spec","number":12,"title":"Planowanie działalności rekreacyjnej w różnych środowiskach","summary":"Zasady planowania i programowania działalności rekreacyjnej dostosowanej do specyfiki miejsca zamieszkania, ośrodka wczasowego, zakładu pracy i hotelu.","wiki":[{"heading":"Podstawy planowania","body":"W planowaniu i programowaniu działalności rekreacyjnej ważne są: analiza rynku, zapewnienie bogatej oferty usług rekreacyjnych oraz działania marketingowe. Ofertę zawsze dostosowuje się do specyfiki środowiska i grupy odbiorców."},{"heading":"Miejsce zamieszkania i ośrodek wczasowy","bullets":["na osiedlu: wieczorne aktywności dla osób pracujących (8-16) oraz poranne dla kobiet w ciąży, z dziećmi i seniorów","stałe zajęcia ruchowe (fitness, nordic walking, joga) i wydarzenia (pikniki, spartakiady); przykładem jest program Trener Osiedlowy","ośrodek wczasowy: uwzględnia sezonowość (np. nad morzem duże obłożenie latem) oraz przedział wiekowy gości","rodziny potrzebują animacji dla dzieci i basenów, seniorzy spokojniejszych zajęć i opieki medycznej, osoby aktywne — wypożyczalni rowerów i sportów wodnych","krótkie turnusy wymagają intensywnego, atrakcyjnego i elastycznego programu rozrywkowo-sportowego"]},{"heading":"Zakład pracy i hotel","bullets":["zakład pracy: aktywności w czasie przerw lunchowych lub po godzinach pracy (tzw. 9-5 job)","w trakcie pracy warto zadbać o krótkie ćwiczenia rozluźniające i gimnastykę","hotel: sezonowość zależna od funkcjonowania hotelu oraz duża rotacja gości (pobyty 1-2 tygodnie)","oferta hotelowa powinna być bardzo atrakcyjna i nastawiona na „tu i teraz”, np. pakiety wellness z jogą, wstępem na basen lub siłownię"]}],"questions":[{"type":"abcd","q":"Co — według źródła — jest ważne w planowaniu i programowaniu działalności rekreacyjnej?","options":["analiza rynku, bogata oferta usług i działania marketingowe","wyłącznie obniżanie cen biletów","rezygnacja z działań marketingowych","jednolita oferta niezależna od środowiska"],"correct":0,"explain":"Źródło wymienia trzy elementy: analizę rynku, zapewnienie bogatej oferty usług rekreacyjnych oraz działania marketingowe."},{"type":"abcd","q":"Jaki czynnik trzeba szczególnie uwzględnić, planując działalność w ośrodku wczasowym nad morzem?","options":["brak jakiejkolwiek sezonowości","sezonowość — duże obłożenie w sezonie letnim i niemal zerowe poza nim","wyłącznie ofertę dla seniorów","całkowitą rezygnację z animacji dla dzieci"],"correct":1,"explain":"Funkcjonowanie ośrodka zależy od gości — nad polskim morzem oznacza to duże obłożenie latem i niemal zerowe poza sezonem."},{"type":"tf","q":"Oferta rekreacyjna w hotelu powinna być nastawiona na długofalowe budowanie sylwetki do kolejnego lata.","correct":false,"explain":"Przeciwnie — przez dużą rotację gości oferta hotelowa ma być atrakcyjna i nastawiona na „tu i teraz”, a nie na budowanie sylwetki do kolejnego lata."},{"type":"flash","front":"Jak rozplanować aktywności rekreacyjne dla mieszkańców osiedla?","back":"Wieczorne aktywności dla większości osób pracujących w godzinach 8-16 oraz poranne dla kobiet w ciąży, z dziećmi i seniorów; do tego dostęp do terenów rekreacyjnych, stałe zajęcia ruchowe (fitness, nordic walking, joga) i wydarzenia (pikniki, spartakiady)."}]},{"id":"rek-pomiary-antropometryczne","track":"rekreacja","category":"rekreacja-spec","number":13,"title":"Zasady wykonywania pomiarów antropometrycznych","summary":"Najważniejsze zasady prawidłowego wykonywania pomiarów antropometrycznych — od znajomości punktów ciała po dokładność zapisu.","wiki":[{"heading":"Najważniejsze zasady","bullets":["znajomość punktów antropometrycznych ciała","właściwa postawa ciała — w Polsce pomiary wykonuje się po lewej stronie ciała","odpowiedni strój, najlepiej sportowy, przylegający do ciała","dokładność odpowiednia do skali instrumentarium pomiarowego","odpowiednia pora wykonywania pomiarów","dokładność w zapisywaniu pomiarów"]}],"questions":[{"type":"abcd","q":"Po której stronie ciała wykonuje się w Polsce pomiary antropometryczne?","options":["po prawej stronie","po lewej stronie","naprzemiennie po obu stronach","wyłącznie z przodu ciała"],"correct":1,"explain":"Według źródła w Polsce pomiary antropometryczne wykonuje się po lewej stronie ciała przy zachowaniu właściwej postawy."},{"type":"tf","q":"Do pomiarów antropometrycznych zaleca się luźny, nieprzylegający strój, aby nie krępować ruchów.","correct":false,"explain":"Przeciwnie — źródło zaleca odpowiedni strój sportowy, najlepiej przylegający do ciała, oraz dokładność dostosowaną do skali instrumentarium pomiarowego."},{"type":"flash","front":"Wymień najważniejsze zasady wykonywania pomiarów antropometrycznych.","back":"Znajomość punktów antropometrycznych ciała, właściwa postawa (w Polsce po lewej stronie), odpowiedni przylegający strój sportowy, dokładność odpowiednia do skali instrumentarium, odpowiednia pora pomiarów oraz dokładność w zapisywaniu wyników."}]},{"id":"rek-zabawy-gry-ruchowe-seniorzy","track":"rekreacja","category":"rekreacja-spec","number":14,"title":"Rola zabaw i gier ruchowych w sprawności osób starszych","summary":"Funkcje, cele i zasady prowadzenia zabaw oraz gier ruchowych podtrzymujących ogólną sprawność fizyczną osób w wieku starszym.","wiki":[{"heading":"Funkcje zabaw i gier ruchowych","bullets":["kompensacyjna — rekompensuje ograniczenia wynikające z wieku","regeneracyjna — umożliwia aktywny odpoczynek, relaks i odbudowę sił psychicznych","rozrywkowa — dostarcza pozytywnych emocji, ważna wobec rosnącego ryzyka izolacji i smutku","antyinwolucyjna — przeciwdziała procesom starzenia się organizmu","kreacyjna — pozwala na kreatywność i rozwijanie pasji","afiliacyjna — sprzyja tworzeniu więzi i przynależności w grupie seniorów","integracyjna — aktywizuje seniorów z innymi grupami wiekowymi"]},{"heading":"Cele","bullets":["zapobieganie niepełnosprawności i chorobom wieku starczego (serca, narządu ruchu, metabolicznym)","poprawa odporności, koordynacji, czasu reakcji i siły, wzmocnienie mięśni","poprawa umiejętności motorycznych, zdrowia fizycznego i psychicznego oraz pracy mózgu","zabawa i rozrywka"]},{"heading":"Zasady prowadzenia zajęć","bullets":["pod kontrolą lekarską, z uwzględnieniem stanu zdrowia, oraz indywidualizacja zajęć","kameralna atmosfera i stosowanie łatwych przyborów","wprowadzanie ćwiczeń oddechowych w zwiększonym zakresie","mniejsze tempo ćwiczeń (temporalność) oraz urozmaicone, lecz stabilne pozycje wyjściowe","zadania o charakterze praktycznym"]}],"questions":[{"type":"abcd","q":"Która funkcja zabaw i gier ruchowych polega na przeciwdziałaniu procesom starzenia się organizmu?","options":["kompensacyjna","rozrywkowa","afiliacyjna","antyinwolucyjna"],"correct":3,"explain":"Funkcja antyinwolucyjna przeciwdziała procesom starzenia się organizmu, dzięki czemu seniorzy zachowują lepszą kondycję."},{"type":"tf","q":"Zajęcia ruchowe dla seniorów należy prowadzić w jak najszybszym tempie, aby maksymalnie obciążyć organizm.","correct":false,"explain":"Wręcz przeciwnie — źródło zaleca mniejsze tempo ćwiczeń (temporalność, realizacja zadań w wolniejszym tempie) oraz prowadzenie zajęć pod kontrolą lekarską."},{"type":"tf","q":"Funkcja afiliacyjna zabaw i gier ruchowych sprzyja tworzeniu więzi i poczucia przynależności w grupie seniorów.","correct":true,"explain":"Źródło opisuje funkcję afiliacyjną jako sprzyjającą tworzeniu więzi i przynależności wewnątrz grupy seniorów oraz przeciwdziałającą samotności i wykluczeniu."},{"type":"flash","front":"Wymień zasady prowadzenia zajęć ruchowych dla osób starszych.","back":"Kontrola lekarska i uwzględnienie stanu zdrowia, indywidualizacja zajęć, kameralna atmosfera, łatwe przybory, zwiększony zakres ćwiczeń oddechowych, mniejsze tempo (temporalność), urozmaicone, lecz stabilne pozycje wyjściowe oraz zadania o charakterze praktycznym."}]},{"id":"rek-miejska-turystyka-rowerowa","track":"rekreacja","category":"rekreacja-spec","number":15,"title":"Walory miejskiej turystyki rowerowej","summary":"Miejska turystyka rowerowa jako sposób spędzania wolnego czasu i źródło korzyści zdrowotnych, ekonomicznych, społecznych oraz ekologicznych.","wiki":[{"heading":"Czym jest miejska turystyka rowerowa","body":"Miejska turystyka rowerowa to przede wszystkim korzyści zdrowotne i metoda spędzania wolnego czasu. Zakłada podróżowanie rowerem po terenach miejskich w celach rekreacyjnych i turystycznych."},{"heading":"Walory","bullets":["poprawa kondycji i lepsze samopoczucie","profilaktyka zdrowotna","oszczędność kosztów oraz unikanie korków w mieście","kontakt z miastem i odkrywanie go z innej perspektywy","integracja społeczna, np. gdy zabieramy ze sobą bliskich","ochrona środowiska i promocja kultury rowerowej"]}],"questions":[{"type":"abcd","q":"Który z poniższych walorów wprost wynika z poruszania się rowerem zamiast samochodem w mieście?","options":["unikanie korków w mieście i oszczędność kosztów","zwiększenie emisji spalin","wzrost wydatków na paliwo","pogorszenie kondycji fizycznej"],"correct":0,"explain":"Źródło wymienia wśród walorów oszczędność kosztów oraz unikanie korków w mieście, a także ochronę środowiska."},{"type":"tf","q":"Miejska turystyka rowerowa sprzyja integracji społecznej, np. gdy zabieramy ze sobą bliskich.","correct":true,"explain":"Integracja społeczna — np. wspólne wyprawy z bliskimi — jest wymieniona w źródle jako jeden z walorów miejskiej turystyki rowerowej."},{"type":"flash","front":"Wymień walory miejskiej turystyki rowerowej.","back":"Poprawa kondycji, lepsze samopoczucie, profilaktyka zdrowotna, oszczędność kosztów, unikanie korków, kontakt z miastem i odkrywanie go z innej perspektywy, integracja społeczna, ochrona środowiska oraz promocja kultury rowerowej."}]},{"id":"rek-ksztalcenie-motoryczne-okresy-rozwojowe","track":"rekreacja","category":"rekreacja-spec","number":16,"title":"Proces kształcenia motorycznego w rekreacji fizycznej wg okresów rozwojowych","summary":"Kształcenie motoryczne przebiega odmiennie w kolejnych okresach życia człowieka — od burzliwego rozwoju motoryki w niemowlęctwie, przez dwa apogea motoryczności w dzieciństwie, kryzys w okresie pokwitania, aż po regres w starości.","wiki":[{"heading":"Wczesne dzieciństwo","body":"Okres niemowlęctwa cechuje się dużym tempem rozwoju motoryki: unoszenie głowy z tułowiem (ok. 3-4 miesiąca), obracanie się, ruchy chwytne i manipulacyjne, raczkowanie (od 5 do 7 miesiąca), siadanie (6-9 miesiąca) oraz pierwsze kroki (10-12 miesiąca). W okresie poniemowlęcym dziecko swobodnie chodzi, biega, doskonali równowagę, skacze, rzuca i kopie piłkę."},{"heading":"Apogea motoryczności","bullets":["I apogeum motoryczności — ok. 5 roku życia (okres przedszkolny), tzw. złoty okres motoryczności: rozrzutność ruchowa, przewaga procesów pobudzania nad hamowaniem, ruchy płynne, celowe i swobodne.","II apogeum motoryczności — okres młodszy szkolny: u dziewcząt w wieku 10-11 lat, u chłopców w wieku 12-13 lat. Dynamiczny rozwój wszystkich zdolności motorycznych i wyjątkowa łatwość uczenia się nowych, skomplikowanych ruchów (tzw. uczenie się z miejsca)."]},{"heading":"Pokwitanie, młodzieńczość i dorosłość","body":"Okres pokwitania to okres krytyczny w rozwoju motoryczności — pojawia się niezręczność w harmonii, dokładności i rytmie ruchu, szczególnie w ćwiczeniach gimnastycznych na przyrządach (ruchy acykliczne), przy ruchach precyzyjnych, kombinowanych oraz przy uczeniu nowych ruchów. W okresie młodzieńczym u osób nietrenujących występują maksymalne wartości większości zdolności motorycznych (zwłaszcza koordynacyjnych), kształtuje się indywidualny styl motoryczny i rozchodzą się linie rozwojowe kobiety i mężczyzny. Wiek dorosły i dojrzały nie sprzyja już rozwojowi motoryki."},{"heading":"Starość","bullets":["Wczesna starość: 60-75 rok życia; późna starość: powyżej 75 roku życia.","Zanik potrzeby ruchu i neofobia (strach przed uczeniem się nowego ruchu).","Zmniejszenie tempa ruchu, wydłużenie czasu reakcji, sztywność aparatu ruchu.","Sarkopenia — zanik włókien mięśniowych, spadek masy mięśniowej i obniżenie siły.","Obniżenie poziomu koordynacji ruchowej i ograniczenie ruchomości w stawach."]}],"questions":[{"type":"abcd","q":"W którym roku życia przypada I apogeum motoryczności, zwane złotym okresem motoryczności?","options":["Ok. 3 roku życia","Ok. 5 roku życia","Ok. 7 roku życia","Ok. 10 roku życia"],"correct":1,"explain":"I apogeum motoryczności (złoty okres) przypada na ok. 5 rok życia, w okresie przedszkolnym."},{"type":"abcd","q":"W jakim wieku przypada II apogeum motoryczności u chłopców?","options":["10-11 lat","8-9 lat","12-13 lat","14-15 lat"],"correct":2,"explain":"II apogeum motoryczności występuje u dziewcząt w wieku 10-11 lat, a u chłopców w wieku 12-13 lat."},{"type":"tf","q":"Okres pokwitania określa się jako okres krytyczny w rozwoju motoryczności, w którym pojawia się niezręczność ruchowa.","correct":true,"explain":"Pokwitanie to okres krytyczny — występują zakłócenia w harmonii, dokładności i rytmie ruchu, zwłaszcza przy ruchach acyklicznych i precyzyjnych."},{"type":"flash","front":"Wymień charakterystyczne cechy motoryczności w okresie starości.","back":"Zanik potrzeby ruchu, neofobia, zmniejszenie tempa ruchu, wydłużenie czasu reakcji, sztywność aparatu ruchu, sarkopenia (zanik włókien i spadek masy mięśniowej), obniżenie koordynacji oraz ograniczenie ruchomości w stawach."}]},{"id":"rek-recepta-ruchowa-niepelnosprawni","track":"rekreacja","category":"rekreacja-spec","number":17,"title":"Recepta ruchowa — ramowy program zajęć rekreacji dla osób z niepełnosprawnością","summary":"Ramowy program zajęć rekreacji fizycznej dla osób z niepełnosprawnością, zwany receptą ruchową, powinien zawierać konkretne kategorie informacji: od wskazań i przeciwwskazań, przez modyfikacje i techniki adaptacyjne, po dawkowanie wysiłku i metody samokontroli.","wiki":[{"heading":"Czym jest recepta ruchowa","body":"Recepta ruchowa to ramowy program zajęć rekreacji fizycznej przygotowany z myślą o osobach z niepełnosprawnością. Określa, jak bezpiecznie i skutecznie dobrać oraz dawkować aktywność ruchową w zależności od rodzaju dysfunkcji uczestnika."},{"heading":"Kategorie informacji w recepcie ruchowej","bullets":["Szczegółowe wskazania i przeciwwskazania do wykonywania poszczególnych zadań ruchowych.","Modyfikacja sposobu wykonywania zadań ruchowych w zależności od rodzaju występującej dysfunkcji.","Możliwości stosowania różnych technik adaptacyjnych w poszczególnych formach ruchu.","Optymalna częstotliwość i czas trwania zajęć rekreacyjnych.","Informacja o korzyściach płynących z danej formy rekreacji dla usprawniania leczniczego pacjenta.","Metody samokontroli tolerancji wysiłkowej pacjenta (zmęczenie, ból, tętno wysiłkowe itp.)."]}],"questions":[{"type":"abcd","q":"Który z elementów NIE należy do kategorii informacji recepty ruchowej?","options":["Wskazania i przeciwwskazania do zadań ruchowych","Techniki adaptacyjne w formach ruchu","Lista nagród za udział w zajęciach","Metody samokontroli tolerancji wysiłkowej"],"correct":2,"explain":"Recepta ruchowa obejmuje wskazania/przeciwwskazania, modyfikacje, techniki adaptacyjne, dawkowanie, korzyści i samokontrolę — nie zawiera listy nagród."},{"type":"tf","q":"Recepta ruchowa powinna zawierać metody samokontroli tolerancji wysiłkowej pacjenta, takie jak obserwacja zmęczenia, bólu czy tętna wysiłkowego.","correct":true,"explain":"Zgodnie ze źródłem recepta podaje metody samokontroli tolerancji wysiłkowej (zmęczenie, ból, tętno wysiłkowe itp.)."},{"type":"tf","q":"Recepta ruchowa zaleca jednakowy sposób wykonywania zadań ruchowych dla wszystkich, niezależnie od rodzaju dysfunkcji.","correct":false,"explain":"Przeciwnie — recepta wymaga modyfikacji sposobu wykonywania zadań ruchowych w zależności od rodzaju występującej dysfunkcji."},{"type":"flash","front":"Wymień kategorie informacji, które powinna zawierać recepta ruchowa.","back":"Wskazania i przeciwwskazania, modyfikacje zadań zależnie od dysfunkcji, techniki adaptacyjne, optymalna częstotliwość i czas trwania zajęć, informacja o korzyściach leczniczych oraz metody samokontroli tolerancji wysiłkowej."}]},{"id":"rek-piersieniowka-promocja-regionu","track":"rekreacja","category":"rekreacja-spec","number":18,"title":"Pierścieniówka jako polski sport promujący region turystyczny","summary":"Pierścieniówka to polska gra tradycyjna zbliżona do siatkówki, wymyślona w latach 30. XX wieku przez Władysława Robakowskiego. Dzięki obecności na festynach i imprezach integracyjnych stanowi element promujący region turystyczny.","wiki":[{"heading":"Zasady gry","body":"Pierścieniówka to polska gra tradycyjna, w której dwie drużyny (zazwyczaj 4 na 4) rywalizują, oburęcznie przerzucając piłkę przez siatkę z trzema otworami; środkowy otwór jest większy niż boczne. Można w nią grać na polu do siatkówki, potrzebna jest jednak specjalna siatka. Sport ten wymyślił w latach 30. XX wieku nauczyciel gimnastyki Władysław Robakowski."},{"heading":"Dostępność i promocja regionu","body":"Pierścieniówka to dynamiczna gra odpowiednia zarówno dla dzieci i młodzieży, jak i dorosłych, a także dla osób niepełnosprawnych, co udowodniło Stowarzyszenie Sportowo-Rehabilitacyjne START z Poznania. Bywa rozgrywana podczas festynów, imprez integracyjnych i świąt, takich jak Majówka, Dzień Dziecka, Jarmark Świętojański czy Festiwal Integracje w Poznaniu. Od momentu przywrócenia do życia jest coraz częściej pokazywana podczas ważnych imprez sportowych, w tym Światowych Igrzysk Sportów Tradycyjnych."}],"questions":[{"type":"abcd","q":"Kto wymyślił pierścieniówkę w latach 30. XX wieku?","options":["Władysław Robakowski","James Naismith","William G. Morgan","Stowarzyszenie START z Poznania"],"correct":0,"explain":"Pierścieniówkę wymyślił w latach 30. XX wieku nauczyciel gimnastyki Władysław Robakowski."},{"type":"abcd","q":"Ile otworów ma siatka używana w pierścieniówce?","options":["Dwa","Cztery","Trzy","Jeden"],"correct":2,"explain":"Siatka w pierścieniówce ma trzy otwory, przy czym środkowy jest większy niż boczne."},{"type":"tf","q":"Pierścieniówka jest grą, w którą mogą grać także osoby niepełnosprawne, co udowodniło Stowarzyszenie Sportowo-Rehabilitacyjne START z Poznania.","correct":true,"explain":"Źródło wskazuje, że pierścieniówka jest dostępna dla osób niepełnosprawnych, co potwierdziło poznańskie Stowarzyszenie START."},{"type":"flash","front":"Na czym polega gra w pierścieniówkę?","back":"Dwie drużyny (zazwyczaj 4 na 4) oburęcznie przerzucają piłkę przez siatkę z trzema otworami (środkowy większy niż boczne). Grać można na boisku do siatkówki, potrzebna jest jednak specjalna siatka."}]},{"id":"rek-gry-terenowe-miejskie-grupy-wiekowe","track":"rekreacja","category":"rekreacja-spec","number":19,"title":"Gry terenowe i miejskie dla różnych grup wiekowych i ich charakter edukacyjny","summary":"Gry terenowe i miejskie angażują wszystkie grupy wiekowe — od dzieci po seniorów — i pełnią funkcję edukacyjną: uczą korzystania z mapy i kompasu, współpracy, spostrzegawczości oraz poznawania przyrody i lokalnej kultury.","wiki":[{"heading":"Dzieci (6-12 lat)","bullets":["Skarb piratów — mapa z drogą do skarbu i zadaniami po drodze; uczy korzystania z mapy i współpracy.","Spacer po lesie — uzupełnianie zielnika w trakcie spaceru; łączy spacer z poznawaniem przyrody."]},{"heading":"Młodzież (13-18 lat)","bullets":["Skarb piratów z trudniejszymi zadaniami — uczy korzystania z mapy, kompasu i współpracy.","Podchody — podział na grupę „uciekającą” i „goniącą”; uczy poznawania obszaru, kreatywnego myślenia i współpracy."]},{"heading":"Dorośli (18+ lat)","bullets":["Geocaching — poszukiwanie ukrytych skrytek za pomocą telefonu; uczy cierpliwości, spostrzegawczości i poznawania terenu (skrytki zawierają notatki i ciekawostki o miejscu).","Bieg na orientację — bieg z mapą i kompasem do punktów kontrolnych; uczy planowania trasy i wpływa na sprawność fizyczną."]},{"heading":"Seniorzy (60+)","bullets":["Gra miejska — spacer po mieście z mapą i prostymi zadaniami związanymi z lokalną kulturą i przyrodą; aktywizuje ruchowo i umysłowo, trenuje pamięć i orientację oraz integruje uczestników."]}],"questions":[{"type":"abcd","q":"Która gra terenowa jest proponowana w źródle jako odpowiednia dla dorosłych (18+)?","options":["Podchody","Spacer po lesie","Skarb piratów","Geocaching"],"correct":3,"explain":"Dla dorosłych proponuje się geocaching oraz bieg na orientację; podchody i Skarb piratów to propozycje dla młodzieży/dzieci."},{"type":"abcd","q":"Czego głównie uczy gra miejska proponowana dla seniorów?","options":["Aktywizacji ruchowej i umysłowej, treningu pamięci i orientacji oraz integracji","Wyłącznie maksymalnego wysiłku fizycznego","Obsługi specjalistycznego sprzętu wspinaczkowego","Rywalizacji dwóch drużyn na czas"],"correct":0,"explain":"Gra miejska dla seniorów ma na celu aktywizację ruchową i umysłową, trening pamięci i orientacji oraz integrację z innymi uczestnikami."},{"type":"tf","q":"Gra „Skarb piratów” uczy korzystania z mapy i współpracy między uczestnikami.","correct":true,"explain":"Zgodnie ze źródłem Skarb piratów uczy korzystania z mapy oraz współpracy (u młodzieży dodatkowo kompasu)."},{"type":"flash","front":"Podaj przykład gry terenowej dla dzieci (6-12 lat) i wskaż jej walory edukacyjne.","back":"Spacer po lesie z uzupełnianiem zielnika — łączy spacer z poznawaniem przyrody. Alternatywnie Skarb piratów, który uczy korzystania z mapy i współpracy."}]},{"id":"rek-snooker-bilard-roznice","track":"rekreacja","category":"rekreacja-spec","number":20,"title":"Snooker i bilard — charakterystyka i różnice","summary":"Bilard i snooker to gry stołowe polegające na uderzaniu bil kijem i wbijaniu ich do otworów. Snooker wywodzi się z tradycyjnego bilarda, lecz różni się liczbą i wielkością bil, rozmiarem stołu, terminologią oraz bardziej zaawansowaną punktacją.","wiki":[{"heading":"Bilard","body":"Bilard to gra stołowa polegająca na uderzaniu bil za pomocą kija i wbijaniu ich do łuz. Używa się 16 bil — białej i 15 kolorowych. Może być grany pomiędzy dwoma graczami lub drużynami. Bile są ustawione w trójkąt, przy czym bile kolorowe i połówkowe są wymieszane."},{"heading":"Snooker","body":"Snooker to gra bilardowa wywodząca się od tradycyjnego bilarda. Grana jest na większym stole o tym samym kształcie, pomiędzy dwoma zawodnikami lub drużynami. Używa się 22 bil (15 czerwonych, 6 kolorowych i 1 biała). Bile czerwone są rozstawione w trójkąt, a kolorowe ustawione w określonych punktach na stole."},{"heading":"Najważniejsze różnice","bullets":["Liczba bil: w snookerze 22 (15 czerwonych, 6 kolorowych, 1 biała), w bilardzie 16 (15 kolorowych, 1 biała).","Wielkość bil: w snookerze są mniejsze; w snookerze nie ma numerków.","Terminologia: w snookerze „kieszenie”, w bilardzie „łuzy”.","Kij: w snookerze cieńszy; stół w snookerze większy (3,6 m wobec 2,8 m w bilardzie).","Punktacja: w snookerze bardziej zaawansowana — bile mają wartość od 2 do 7 pkt, w bilardzie po jednym punkcie (oprócz czarnej, która kończy rozgrywkę)."]}],"questions":[{"type":"abcd","q":"Ilu bil używa się w snookerze?","options":["16 bil","22 bile","15 bil","21 bil"],"correct":1,"explain":"W snookerze używa się 22 bil: 15 czerwonych, 6 kolorowych i 1 białej. W bilardzie jest ich 16."},{"type":"abcd","q":"Jak nazywa się otwory, do których wbija się bile, w terminologii bilardowej?","options":["Kieszenie","Bramki","Łuzy","Otwory"],"correct":2,"explain":"W bilardzie używa się terminu „łuzy”, natomiast w snookerze mówi się o „kieszeniach”."},{"type":"tf","q":"W snookerze stół jest większy niż w bilardzie, a kij cieńszy.","correct":true,"explain":"Zgodnie ze źródłem stół snookerowy jest większy (3,6 m wobec 2,8 m), a kij w snookerze jest cieńszy."},{"type":"tf","q":"W snookerze każda bila warta jest tyle samo punktów, podobnie jak w prostej punktacji bilardowej.","correct":false,"explain":"Przeciwnie — punktacja w snookerze jest bardziej zaawansowana: bile mają wartość od 2 do 7 punktów, podczas gdy w bilardzie liczone są po jednym punkcie."}]},{"id":"rek-pomiar-aktywnosci-i-sprawnosci-fizycznej","track":"rekreacja","category":"rekreacja-spec","number":21,"title":"Metody pomiaru aktywności i sprawności fizycznej w różnych grupach wiekowych","summary":"Aktywność fizyczną mierzy się metodami obiektywnymi i subiektywnymi, a sprawność fizyczną zestawami testów dobranymi do wieku, takimi jak HBSC, IPAQ, Eurofit czy Senior fitness test.","wiki":[{"heading":"Aktywność a sprawność fizyczna","body":"Aktywność fizyczna to ruch ciała wykonywany przez mięśnie szkieletowe, stanowiący element zdrowego stylu życia związany z rozwojem, zdrowiem i dobrym samopoczuciem. Jest ona aktywnością ruchową, ale nie każda aktywność ruchowa jest aktywnością fizyczną. Sprawność fizyczna to umiejętność rozwiązywania konkretnych zadań ruchowych oraz zdolność do efektywnego i ekonomicznego wykonywania pracy mięśniowej."},{"heading":"Metody pomiaru aktywności fizycznej","bullets":["obiektywne: bezpośrednie (np. kalorymetria bezpośrednia) i pośrednie (np. metoda podwójnie znakowanej wody, pomiar HR, kalorymetria pośrednia)","subiektywne: badania kwestionariuszowe oraz pisemna relacja","test IPAQ wyraża aktywność w jednostkach MET-min./tydzień, kwalifikując do aktywności niewystarczającej (poniżej 600), dostatecznej (600-1500) lub wysokiej (powyżej 1500)"]},{"heading":"Narzędzia dobrane do grup wiekowych","bullets":["dzieci: HBSC (badanie WHO co 4 lata wśród uczniów w wieku 11, 13 i 15 lat) oraz PAR oceniający wsparcie rodziców","dorośli (16-65 lat): IPAQ (aktywność w pracy, transporcie, rekreacji i obowiązkach domowych z ostatnich 7 dni) oraz Eurobarometr","osoby starsze: ADAPT (dzienniczek aktywności) oraz CHAMPS (samoocena aktywności seniorów)"]},{"heading":"Testy sprawności fizycznej","bullets":["Indeks Sprawności Fizycznej K. Zuchory - ocenia 6 cech motorycznych bez skomplikowanej aparatury","Eurofit - dla dzieci i młodzieży w wieku szkolnym 6-18 lat, bateria 9 prób","Alpha-fit - testy terenowe dla dorosłych Europejczyków w wieku 18-69 lat","Senior fitness test - wielowymiarowa ocena sprawności osób powyżej 60 r.ż."]}],"questions":[{"type":"abcd","q":"Które badanie aktywności fizycznej koordynowane przez WHO przeprowadza się co 4 lata wśród uczniów w wieku 11, 13 i 15 lat?","options":["IPAQ","Eurobarometr","HBSC","CHAMPS"],"correct":2,"explain":"HBSC (Health Behaviour in School-aged Children) to międzynarodowe badanie WHO realizowane co 4 lata wśród uczniów w wieku 11, 13 i 15 lat."},{"type":"abcd","q":"Dla jakiej grupy wiekowej przeznaczony jest Senior fitness test?","options":["Dla osób powyżej 60 r.ż.","Dla dzieci 6-18 lat","Dla dorosłych 18-69 lat","Dla uczniów 11-15 lat"],"correct":0,"explain":"Senior fitness test służy wielowymiarowej ocenie sprawności fizycznej osób w starszym wieku, powyżej 60 r.ż."},{"type":"tf","q":"Test IPAQ wyraża aktywność fizyczną w jednostkach MET-min./tydzień i pozwala zakwalifikować ją do jednej z trzech kategorii.","correct":true,"explain":"IPAQ wyraża aktywność w MET-min./tydzień, dzieląc ją na niewystarczającą (poniżej 600), dostateczną (600-1500) i wysoką (powyżej 1500)."},{"type":"flash","front":"Wymień narzędzia pomiaru aktywności fizycznej przeznaczone dla dorosłych (16-65 lat).","back":"IPAQ - kwestionariusz oceniający aktywność w pracy, transporcie, rekreacji i obowiązkach domowych z ostatnich 7 dni, oraz Eurobarometr - badanie opinii publicznej w krajach UE."}]},{"id":"rek-efekty-treningu-zdrowotnego","track":"rekreacja","category":"rekreacja-spec","number":22,"title":"Pożądane efekty treningu zdrowotnego w trzech płaszczyznach","summary":"Regularny trening zdrowotny przynosi korzyści w płaszczyźnie psychicznej, społecznej i fizycznej, od poprawy nastroju po redukcję ryzyka chorób przewlekłych.","wiki":[{"heading":"Czym jest trening zdrowotny","body":"Trening zdrowotny to trening skupiony na utrzymaniu lub poprawie zdrowia ćwiczącego. Wykonywany regularnie niesie za sobą szereg korzyści fizycznych, psychicznych oraz społecznych."},{"heading":"Płaszczyzna psychiczna","bullets":["poprawa nastroju i redukcja stresu","zwiększenie samooceny i pewności siebie","łagodzenie objawów depresji","zwiększenie motywacji do działania","poprawa funkcji poznawczych: pamięci i koncentracji"]},{"heading":"Płaszczyzna społeczna","bullets":["budowanie relacji i poczucia przynależności poprzez treningi grupowe","poprawa komunikacji i umiejętności interpersonalnych","redukcja poczucia samotności i izolacji, szczególnie istotna dla osób starszych"]},{"heading":"Płaszczyzna fizyczna","bullets":["wzmacnianie układu kostno-mięśniowego","poprawa wydolności krążeniowo-oddechowej","regulacja masy ciała i zapobieganie otyłości","redukcja ryzyka chorób przewlekłych (serca, cukrzycy typu 2, osteoporozy, nadciśnienia, niektórych nowotworów)","poprawa jakości snu"]}],"questions":[{"type":"abcd","q":"Który z poniższych efektów treningu zdrowotnego należy do płaszczyzny społecznej?","options":["Redukcja poczucia samotności i izolacji","Poprawa jakości snu","Wzmacnianie układu kostno-mięśniowego","Łagodzenie objawów depresji"],"correct":0,"explain":"Redukcja poczucia samotności i izolacji to efekt w płaszczyźnie społecznej; jakość snu i układ kostno-mięśniowy są fizyczne, a łagodzenie depresji psychiczne."},{"type":"tf","q":"Poprawa wydolności krążeniowo-oddechowej jest zaliczana do efektów treningu zdrowotnego w płaszczyźnie psychicznej.","correct":false,"explain":"Poprawa wydolności krążeniowo-oddechowej należy do płaszczyzny fizycznej, a nie psychicznej."},{"type":"flash","front":"Wymień przynajmniej trzy pożądane efekty treningu zdrowotnego w płaszczyźnie fizycznej.","back":"Wzmacnianie układu kostno-mięśniowego, poprawa wydolności krążeniowo-oddechowej, regulacja masy ciała, redukcja ryzyka chorób przewlekłych oraz poprawa jakości snu."}]},{"id":"rek-rekreacja-a-rozwiazywanie-konfliktow","track":"rekreacja","category":"rekreacja-spec","number":23,"title":"Wpływ rekreacji na rozwiązywanie konfliktów społecznych i zawodowych","summary":"Dzięki funkcji katartycznej i budowaniu relacji rekreacja sprzyja zdrowej komunikacji oraz radzeniu sobie ze stresem, co ułatwia rozwiązywanie konfliktów.","wiki":[{"heading":"Funkcja katartyczna","body":"Funkcja katartyczna (oczyszczająca) odnosi się do możliwości emocjonalnego odreagowania napięć i stresów poprzez aktywność fizyczną lub inne formy rekreacji. Jest to proces uwalniania negatywnych emocji prowadzący do odprężenia i poprawy samopoczucia, ważny dla zachowania równowagi psychicznej i fizycznej. Pozwala na odprężenie i redukcję stresu (ruch uwalnia endorfiny), uwolnienie emocji oraz katharsis, czyli oczyszczenie następujące po uwolnieniu napięć."},{"heading":"Wpływ na konflikty społeczne","bullets":["poprawa komunikacji poprzez wspólny sport i gry zespołowe","budowanie relacji, zaufania i empatii","redukcja stresu i napięcia towarzyszącego konfliktom","wzrost umiejętności negocjacyjnych dzięki grom zespołowym","tworzenie pozytywnej atmosfery wzajemnego szacunku"]},{"heading":"Wpływ na konflikty zawodowe","bullets":["budowanie zespołu poprzez wyjazdy integracyjne","poprawa komunikacji w zespole","redukcja stresu w pracy","rozwijanie umiejętności rozwiązywania konfliktów wymagających współpracy i negocjacji"]}],"questions":[{"type":"abcd","q":"Jak nazywa się funkcja rekreacji pozwalająca na emocjonalne oczyszczenie i odreagowanie napięć?","options":["Funkcja integracyjna","Funkcja negocjacyjna","Funkcja motywacyjna","Funkcja katartyczna"],"correct":3,"explain":"Funkcja katartyczna (oczyszczająca) pozwala na odreagowanie napięć i stresów oraz uwolnienie negatywnych emocji."},{"type":"tf","q":"Wyjazdy integracyjne i inne formy rekreacji mogą pomóc w budowaniu silnego zespołu, co zapobiega konfliktom zawodowym.","correct":true,"explain":"Budowanie zespołu poprzez wyjazdy integracyjne sprawia, że pracownicy chętniej współpracują, co przeciwdziała konfliktom zawodowym."},{"type":"flash","front":"W jaki sposób rekreacja wpływa na rozwiązywanie konfliktów społecznych?","back":"Poprawia komunikację, buduje relacje oparte na zaufaniu i empatii, redukuje stres, zwiększa umiejętności negocjacyjne i tworzy pozytywną atmosferę wzajemnego szacunku."}]},{"id":"rek-tance-regionalne-a-narodowe","track":"rekreacja","category":"rekreacja-spec","number":24,"title":"Różnice pomiędzy tańcami regionalnymi a narodowymi","summary":"Tańce regionalne związane są z konkretnym, niewielkim obszarem i tradycją lokalną, podczas gdy tańce narodowe reprezentują cały naród; w Polsce jest ich pięć.","wiki":[{"heading":"Definicje","bullets":["tańce regionalne - tańczone w określonym regionie kraju (np. Śląsk, Mazury), jak Hajduk na Żywiecczyźnie czy Wełto na Kaszubach","tańce narodowe - tańczone przez cały naród; w Polsce wyróżnia się 5 tańców narodowych","polskie tańce narodowe: polonez, mazur, krakowiak, kujawiak i oberek"]},{"heading":"Główne różnice","bullets":["strój - tańce regionalne mają charakterystyczne stroje związane z danym regionem","lokalizacja - regionalne na małym obszarze, narodowe reprezentują cały kraj","różnorodność - regionalne cechuje różnorodność ruchów, narodowe ich jednolitość","okoliczności - narodowe tańczono na salonach, regionalne głównie podczas obrzędów","historia - regionalne związane z tradycją lokalną, narodowe z całym narodem","w tańcach regionalnych stosuje się przyśpiewki"]}],"questions":[{"type":"abcd","q":"Ile tańców narodowych wyróżnia się w Polsce?","options":["Trzy","Pięć","Cztery","Siedem"],"correct":1,"explain":"W Polsce wyróżnia się 5 tańców narodowych: polonez, mazur, krakowiak, kujawiak i oberek."},{"type":"tf","q":"Tańce narodowe cechuje różnorodność ruchów, a tańce regionalne ich jednolitość.","correct":false,"explain":"Jest odwrotnie: to tańce regionalne cechuje różnorodność ruchów, a tańce narodowe ich jednolitość, bo wszędzie wyglądają tak samo."},{"type":"flash","front":"Wymień pięć polskich tańców narodowych.","back":"Polonez, mazur, krakowiak, kujawiak i oberek."}]},{"id":"rek-imprezy-rekreacyjne-promocja-zdrowia","track":"rekreacja","category":"rekreacja-spec","number":25,"title":"Rola imprez rekreacyjnych w promocji zdrowego stylu życia","summary":"Imprezy rekreacyjne to widowiska i zawody organizowane dla wypoczynku i rozwoju psychofizycznego, które motywują do aktywności, budują nawyki i sprzyjają profilaktyce zdrowotnej.","wiki":[{"heading":"Czym jest impreza rekreacyjna","body":"Impreza rekreacyjna to widowisko, koncert, zabawa lub zawody sportowe organizowane dla wypoczynku, rozrywki oraz podwyższania umiejętności i zdolności psychofizycznych uczestników. Jest to przedsięwzięcie dla dużej grupy odbiorców, jednorazowe lub cykliczne, w którym podstawowym środkiem działania programowego jest aktywność ruchowa oraz kulturalno-rozrywkowa."},{"heading":"Cele imprez rekreacyjnych","bullets":["popularyzacja rekreacyjnych form ruchowych","zaspokajanie potrzeb różnych środowisk w zakresie wzorów rekreacji ruchowej","rozbudzenie zainteresowań aktywnym wypoczynkiem","tworzenie warunków dla pozytywnie rozumianego współzawodnictwa","umożliwienie oceny sprawności fizycznej uczestników"]},{"heading":"Korzyści dla zdrowego stylu życia","bullets":["motywowanie do aktywności fizycznej i wykształcanie potrzeby ruchu","budowanie nawyków oraz uczenie dyscypliny i systematyczności","promowanie zdrowego odżywiania, snu i radzenia sobie ze stresem","integracja społeczna i budowanie poczucia wspólnoty","zabawa, radość i działanie na rzecz profilaktyki zdrowotnej"]}],"questions":[{"type":"abcd","q":"Co jest podstawowym środkiem działania programowego imprezy rekreacyjnej?","options":["Aktywność ruchowa oraz kulturalno-rozrywkowa","Wyłącznie rywalizacja sportowa wyczynowa","Bierny odpoczynek uczestników","Indywidualna terapia medyczna"],"correct":0,"explain":"W imprezie rekreacyjnej podstawowym środkiem działania programowego jest aktywność ruchowa oraz kulturalno-rozrywkowa."},{"type":"tf","q":"Imprezy rekreacyjne mają działać na rzecz profilaktyki zdrowotnej, zapobiegając chorobom związanym z brakiem ruchu.","correct":true,"explain":"Wśród korzyści wymienia się działanie na rzecz profilaktyki zdrowotnej poprzez zapobieganie chorobom z braku ruchu oraz promowanie zdrowego odżywiania."},{"type":"flash","front":"Wymień przynajmniej trzy cele imprez rekreacyjnych.","back":"Popularyzacja rekreacyjnych form ruchowych, zaspokajanie potrzeb różnych środowisk, rozbudzenie zainteresowań aktywnym wypoczynkiem, tworzenie warunków dla pozytywnego współzawodnictwa oraz umożliwienie oceny sprawności fizycznej."}]},{"id":"rek-zabawy-kreglarskie","track":"rekreacja","category":"rekreacja-spec","number":26,"title":"Zabawy kręglarskie w rekreacji ruchowej","summary":"Zabawy kręglarskie, takie jak Milionówka, Wyrzucany, Czarna kula, Gra rumuńska i Labinet, urozmaicają rekreację ruchową i często wywodzą się z treningu kręglarskiego.","wiki":[{"heading":"Milionówka i Wyrzucany","body":"Milionówka bierze nazwę od maksymalnej liczby punktów możliwych do uzyskania (999 999, czyli prawie milion). Liczba uczestników jest dowolna, a każdy po wylosowaniu kolejności wykonuje sześć rzutów, kolejno po jednym, wpisując wynik do jednej z sześciu rubryk. Wygrywa ten, kto ułoży wynik najbliższy milionowi. W Wyrzucanym liczba graczy jest dowolna; każdy stara się uzyskać rezultat lepszy od poprzednika w kolejce, a wynik gorszego przeciwnika się skreśla. Po ustalonej liczbie skreśleń gracz odpada, a wygrywa ten, kto ma ich najmniej."},{"heading":"Czarna kula i Gra rumuńska","body":"Czarna kula stosowana jest głównie jako trening w grze do uliczek. Grają dwie pięcioosobowe drużyny, każda na jednym torze, a w połowie gry następuje zmiana torów; ustawia się układy trzech kręgli (np. 1, 2, 4 lub 1, 3, 6). Wygrywa drużyna, która straci najwięcej układów „trójek”, a nazwa pochodzi od poznańskiego klubu „Czarna kula”. Gra rumuńska, wylansowana przez kręglarzy rumuńskich na torach klasycznych jako trening do zbieranych, daje na strącenie dziewięciu kręgli maksymalnie sześć rzutów, lecz punkty przyznaje tylko za strącenie „dziewiątki” w najwyżej trzech rzutach; pozostałe rzuty powodują odliczanie."},{"heading":"Labinet","body":"W Labinecie liczba graczy jest nieograniczona, a każdy oddaje kolejno po jednym rzucie. Na początku każdy otrzymuje 50 punktów minusowych i stara się je odrobić, a następnie nadrobić punkty plusowe. Wygrywa zawodnik, który pierwszy osiągnie 50 punktów na plus, czyli łącznie 100 punktów."}],"questions":[{"type":"abcd","q":"Od czego pochodzi nazwa zabawy Milionówka?","options":["Od liczby uczestników biorących udział w grze","Od maksymalnej liczby punktów możliwych do uzyskania (999 999)","Od liczby sześciu rzutów wykonywanych przez gracza","Od nazwy klubu kręglarskiego, w którym powstała"],"correct":1,"explain":"Nazwa pochodzi od maksymalnej liczby punktów (999 999, czyli prawie milion), jaką można zapisać w trakcie zabawy."},{"type":"tf","q":"W zabawie Labinet każdy gracz rozpoczyna od 50 punktów minusowych, a do zwycięstwa musi osiągnąć łącznie 100 punktów.","correct":true,"explain":"Grający startuje z 50 punktami minusowymi, odrabia je i nadrabia plusy; wygrywa pierwszy, kto osiągnie 50 plusów, czyli łącznie 100 punktów."},{"type":"tf","q":"W Czarnej kuli uczestniczą dwie dziesięcioosobowe drużyny grające bez zmiany torów.","correct":false,"explain":"W Czarnej kuli grają dwie pięcioosobowe drużyny, a w połowie gry następuje zmiana torów."},{"type":"flash","front":"Na czym polega Gra rumuńska?","back":"To trening do zbieranych na torach klasycznych: na strącenie dziewięciu kręgli gracz ma maksymalnie sześć rzutów, ale punkty zdobywa tylko za strącenie „dziewiątki” w najwyżej trzech rzutach; pozostałe rzuty powodują odliczanie. Wygrywa zawodnik z najwyższą liczbą punktów."}]},{"id":"rek-zachowania-zdrowotne","track":"rekreacja","category":"rekreacja-spec","number":27,"title":"Zachowania zdrowotne: prozdrowotne i ryzykowne","summary":"Zachowania zdrowotne to działania i nawyki wpływające na zdrowie pozytywnie (prozdrowotne) lub negatywnie (ryzykowne), a o samym zdrowiu najsilniej decyduje styl życia.","wiki":[{"heading":"Pojęcie zdrowia i jego uwarunkowania","body":"Zdrowie to nie tylko brak choroby czy kalectwa, ale stan pełnego dobrostanu fizycznego, umysłowego i społecznego. Obejmuje wymiary: fizyczny, psychiczny, społeczny, umysłowy, duchowy i seksualny. Na zdrowie najmocniej wpływa styl życia (50%), następnie czynniki genetyczne (20%), środowisko fizyczne i społeczne (20%) oraz służba zdrowia (10%). Kluczowe są też zdolność organizmu do utrzymania homeostazy oraz zasady salutogenezy, koncentrującej się na czynnikach sprzyjających zdrowiu."},{"heading":"Zachowania prozdrowotne","bullets":["aktywność fizyczna – regularne uprawianie sportu lub innej aktywności ruchowej","zdrowe odżywianie – posiłki bogate w warzywa, owoce, produkty pełnoziarniste, chude białko i zdrowe tłuszcze","unikanie używek oraz dbanie o higienę osobistą","regularne profilaktyczne wizyty u lekarza","wystarczająca ilość snu (7–8 h)","radzenie sobie ze stresem poprzez techniki relaksacyjne i aktywność fizyczną"]},{"heading":"Zachowania ryzykowne","bullets":["palenie tytoniu i nadużywanie alkoholu","niezdrowe odżywianie – dieta bogata w tłuszcze i cukry","brak aktywności fizycznej oraz stosowanie używek","zaniedbywanie zdrowia – brak wizyt u lekarza, ignorowanie objawów, samoleczenie","nadmierny, długotrwały stres","zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem"]}],"questions":[{"type":"abcd","q":"Który czynnik w największym stopniu wpływa na zdrowie człowieka?","options":["Styl życia (ok. 50%)","Czynniki genetyczne (ok. 20%)","Środowisko fizyczne i społeczne (ok. 20%)","Służba zdrowia (ok. 10%)"],"correct":0,"explain":"Według podanych proporcji styl życia odpowiada za około 50% wpływu na zdrowie, najwięcej spośród wszystkich czynników."},{"type":"tf","q":"Zalecana ilość snu wskazana wśród zachowań prozdrowotnych to 7–8 godzin.","correct":true,"explain":"Wśród zachowań prozdrowotnych wymienia się wystarczającą ilość snu, czyli 7–8 godzin."},{"type":"tf","q":"Salutogeneza koncentruje się głównie na poszukiwaniu czynników chorobotwórczych i przyczyn chorób.","correct":false,"explain":"Salutogeneza koncentruje się na poszukiwaniu czynników sprzyjających zdrowiu i budowaniu zasobów pomagających adaptować się do stresorów."},{"type":"flash","front":"Wymień przykładowe zachowania ryzykowne zagrażające zdrowiu.","back":"Palenie tytoniu, nadużywanie alkoholu, niezdrowe odżywianie (dieta bogata w tłuszcze i cukry), brak aktywności fizycznej, stosowanie używek, zaniedbywanie zdrowia, nadmierny długotrwały stres oraz zbyt długie przesiadywanie z telefonem, komputerem lub telewizorem."}]},{"id":"rek-funkcje-rekreacji-niepelnosprawni","track":"rekreacja","category":"rekreacja-spec","number":28,"title":"Funkcje rekreacji osób z niepełnosprawnością","summary":"Rekreacja ruchowa osób z niepełnosprawnością pełni funkcje: leczniczą, pedagogiczno-psychologiczną, estetyczną, społeczną i ekonomiczną, co ilustrują konkretne formy zajęć.","wiki":[{"heading":"Funkcja lecznicza i pedagogiczno-psychologiczna","body":"Funkcja lecznicza stanowi część programu leczniczego: poprawia ekonomikę wysiłku, obniża wydatek energetyczny przy czynnościach i bywa substytutem środków farmakologicznych bez skutków ubocznych – jak hipoterapia (terapeutyczna jazda konna), w której ruchy konia korygują postawę, równowagę, koordynację i zmniejszają spastyczność mięśni. Funkcja pedagogiczno-psychologiczna kształtuje więzi społeczne i normuje postępowanie w grupie; przykładem są Olimpiady Specjalne, których celem nie jest wyłonienie mistrza, lecz danie możliwości przeżycia własnego startu – każdy startujący jest zwycięzcą."},{"heading":"Funkcja estetyczna i społeczna","body":"Funkcja estetyczna usprawnia ruch i kształtuje jego estetykę, maskując dysfunkcję ruchową oraz zaspokajając potrzebę piękna i harmonii; przykładem są zajęcia taneczne dla osób na wózkach inwalidzkich. Funkcja społeczna daje możliwość kontaktu z innymi ludźmi i tworzy pozytywne postawy społeczne wobec osób z niepełnosprawnością; ilustruje ją hortiterapia – prace w ogrodzie dające korzyści fizyczne oraz społeczne, takie jak otwartość na kontakt, współdziałanie i akceptacja społeczna."},{"heading":"Funkcja ekonomiczna","body":"Funkcja ekonomiczna zwiększa potencjał aktywności poprzez ogólne usprawnienie fizyczne oraz ekonomikę usprawnienia ruchowego. Przykładem jest udział osób z niepełnosprawnością w programach aktywizacji zawodowej obejmujących zajęcia rekreacyjne, co poprawia kondycję fizyczną, a tym samym zwiększa zdolność do podjęcia pracy i samodzielnego funkcjonowania w społeczeństwie."}],"questions":[{"type":"abcd","q":"Która funkcja rekreacji osób z niepełnosprawnością jest ilustrowana przykładem hipoterapii?","options":["Funkcja społeczna","Funkcja estetyczna","Funkcja lecznicza","Funkcja ekonomiczna"],"correct":2,"explain":"Hipoterapia to przykład funkcji leczniczej – ruchy konia korygują postawę, równowagę i koordynację oraz zmniejszają spastyczność mięśni."},{"type":"tf","q":"Celem Olimpiad Specjalnych jest wyłonienie mistrza uzyskującego najlepsze wyniki w danej konkurencji.","correct":false,"explain":"Celem Olimpiad Specjalnych nie jest wyłonienie mistrza, lecz danie możliwości przeżycia własnego startu – każdy startujący jest zwycięzcą."},{"type":"tf","q":"Hortiterapia, czyli prace w ogrodzie, jest przykładem społecznej funkcji rekreacji.","correct":true,"explain":"Hortiterapia ilustruje funkcję społeczną – oprócz korzyści fizycznych daje otwartość na kontakt, współdziałanie i akceptację społeczną."},{"type":"flash","front":"Wymień podstawowe funkcje rekreacji osób z niepełnosprawnością.","back":"Lecznicza, pedagogiczno-psychologiczna, estetyczna, społeczna oraz ekonomiczna."}]},{"id":"rek-zabawy-gry-zdolnosci-motoryczne","track":"rekreacja","category":"rekreacja-spec","number":29,"title":"Zabawy i gry kształtujące zdolności motoryczne","summary":"Różne rodzaje zabaw i gier ruchowych – ze śpiewem, orientacyjno-porządkowe, na czworakach, bieżne, rzutne, skoczne, kopne i słowne – kształtują wybrane zdolności motoryczne człowieka.","wiki":[{"heading":"Zabawy ze śpiewem oraz orientacyjno-porządkowe","body":"Zabawy ze śpiewem interesują dzieci w wieku 3–8 lat i osoby starsze; harmonizują ruch z rytmem i tempem muzyki, wywołują uśmiech i mają walor integracyjny (np. „Nitka”), wspierając poczucie rytmu, równowagi i orientację w przestrzeni. Gry orientacyjno-porządkowe stosuje się w grupach dzieci młodszych; uczą skupienia uwagi, słuchania poleceń, zasad fair play i porozumiewania się znakami, kształtując szybką i celową reakcję, spostrzegawczość oraz orientację (np. „Złośliwy wąż”)."},{"heading":"Zabawy na czworakach, bieżne i rzutne","body":"Zabawy na czworakach (np. „Pieski na spacer – pieski do domu”) stosuje się głównie u dzieci przedszkolnych i wczesnoszkolnych, bo sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa, wzmacniają aparat kostno-stawowo-więzadłowy i siłę. Zabawy bieżne (np. „Lawina”) kształtują szybkość i wytrzymałość, a często też zręczność, i mogą być stosowane od wczesnej młodości do wieku podeszłego. Zabawy rzutne (np. „Zaganianie piłki świnki”) wymagają wstępnej nauki i rozwijają siłę, szybkość, koordynację oraz zręczność manualną."},{"heading":"Zabawy skoczne, kopne i słowne","body":"Zabawy skoczne opierają się na podskokach, skokach, wyskokach, przeskokach i doskokach (np. „Skoki konika”); rozwijają zwinność, szybkość i koordynację oraz wzmacniają stawy kończyn dolnych, lecz nie powinny być wykonywane przez osoby starsze. Zabawy kopne (np. „Piłkarska sztafeta wahadłowa”) interesują głównie chłopców i mężczyzn, kształtują zręczność, siłę i szybkość oraz angażują cały organizm poza kończynami górnymi. Zabawy słowne rozwijają kulturę słowa mówionego, angażują intelekt i można je łączyć z innymi grami ruchowymi."}],"questions":[{"type":"abcd","q":"Dlaczego zabawy i gry na czworakach stosuje się głównie u dzieci przedszkolnych i wczesnoszkolnych?","options":["Ponieważ rozwijają przede wszystkim wytrzymałość biegową","Ponieważ kształtują kulturę słowa mówionego","Ponieważ harmonizują ruch z rytmem muzyki","Ponieważ sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa"],"correct":3,"explain":"Zabawy na czworakach sprzyjają kształtowaniu fizjologicznych krzywizn kręgosłupa i prawidłowej postawy ciała oraz wzmacniają aparat kostno-stawowo-więzadłowy."},{"type":"abcd","q":"Które zdolności motoryczne kształtują przede wszystkim zabawy i gry bieżne?","options":["Szybkość i wytrzymałość, a często też zręczność","Wyłącznie siłę kończyn górnych","Tylko poczucie rytmu","Wyłącznie precyzję ruchów rzutu"],"correct":0,"explain":"Zabawy i gry bieżne sprzyjają kształtowaniu szybkości i wytrzymałości, ale często też zręczności, w zależności od rodzaju zadania."},{"type":"tf","q":"Zabawy i gry skoczne są zalecane szczególnie dla osób w wieku starszym.","correct":false,"explain":"Zabawy skoczne wzmacniają sprawność głównie dzieci i młodzieży i nie powinny być wykonywane przez osoby w wieku starszym."},{"type":"flash","front":"Wymień rodzaje zabaw i gier ruchowych kształtujących zdolności motoryczne.","back":"Zabawy ze śpiewem, orientacyjno-porządkowe, na czworakach, bieżne, rzutne, skoczne, kopne oraz słowne."}]},{"id":"rek-folklor-kaszuby","track":"rekreacja","category":"rekreacja-spec","number":30,"title":"Folklor i region folklorystyczny – Kaszuby","summary":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców i opowieści kultury ludowej danej społeczności, a jednym z bogatych regionów folklorystycznych w Polsce są Kaszuby.","wiki":[{"heading":"Pojęcie folkloru","body":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców, opowieści i innych przejawów kultury ludowej charakterystycznych dla danej społeczności lub regionu. Jednym z bogatych regionów folklorystycznych w Polsce są Kaszuby, położone na Pomorzu."},{"heading":"Folklor Kaszub","bullets":["język kaszubski – odrębny język słowiański używany przez Kaszubów","stroje ludowe – bogata ornamentyka i kolorystyka z charakterystycznymi haftami; niebieski związany z morzem, a także czerwony, żółty i czarny","tańce i muzyka – m.in. taniec Wełtok (podobny do trojaka) oraz instrumenty ludowe, jak diabelskie skrzypce i burczybas (rodzaj bębna)","legendy i podania – opowieści o morskich potworach i tajemniczych postaciach","obrzędy i zwyczaje – związane z cyklem życia (chrzciny, wesela) i kalendarzem (sobótka, dożynki)","sztuka ludowa i kuchnia – rzeźba w drewnie, haft, ceramika oraz potrawy z ryb, ziemniaków i kapusty"]}],"questions":[{"type":"abcd","q":"Który element najlepiej oddaje definicję folkloru?","options":["Wyłącznie współczesna muzyka rozrywkowa danego kraju","Ogół tradycji, wierzeń, obyczajów, pieśni, tańców i opowieści kultury ludowej","Zbiór przepisów prawnych regulujących życie społeczności","Zestaw dyscyplin sportowych uprawianych w danym regionie"],"correct":1,"explain":"Folklor to ogół tradycji, wierzeń, obyczajów, pieśni, tańców, opowieści i innych przejawów kultury ludowej charakterystycznych dla danej społeczności lub regionu."},{"type":"tf","q":"Język kaszubski jest odrębnym językiem słowiańskim używanym przez Kaszubów.","correct":true,"explain":"W folklorze Kaszub wskazuje się język kaszubski jako odrębny język słowiański używany przez Kaszubów."},{"type":"tf","q":"Charakterystyczny dla kaszubskich strojów ludowych kolor niebieski jest związany z górami.","correct":false,"explain":"W kaszubskich strojach kolor niebieski związany jest z morzem; występują też czerwony, żółty i czarny."},{"type":"flash","front":"Podaj charakterystyczne elementy folkloru kaszubskiego.","back":"Język kaszubski, stroje ludowe o bogatej ornamentyce, tańce i muzyka (taniec Wełtok, instrumenty: diabelskie skrzypce i burczybas), legendy i podania, obrzędy i zwyczaje, sztuka ludowa oraz kuchnia oparta na rybach, ziemniakach i kapuście."}]},{"id":"model-zachowan-rynkowych-konsumentow","track":"wszyscy","category":"marketing","number":20,"title":"Model zachowań rynkowych konsumentów i ich uwarunkowania","summary":"Konsument jako uczestnik rynku, modele jego zachowań (ekonomiczny, psychologiczny, socjologiczny, behawioralny), proces podejmowania decyzji oraz uwarunkowania makro- i mikroekonomiczne.","wiki":[{"body":"Konsument to uczestnik rynku, finalny odbiorca i użytkownik dobra lub usługi, który zaspokaja swoje potrzeby poprzez spożycie nabywanych dóbr i usług. Jego zachowania rynkowe opisuje się modelami i analizuje w kontekście uwarunkowań makro- i mikroekonomicznych."},{"heading":"Mikro- i makroekonomia","bullets":["Mikroekonomia — bada pojedyncze jednostki gospodarujące (przedsiębiorstwa, gospodarstwa domowe) i ich decyzje dotyczące produkcji oraz wymiany.","Makroekonomia — bada wielkości zagregowane w skali całej gospodarki: podaż, popyt, zatrudnienie, inwestycje, dochód narodowy."]},{"heading":"Modele zachowań rynkowych konsumenta","bullets":["Ekonomiczny — konsument działa racjonalnie i wybiera produkt o największej wartości przy najniższym koszcie.","Psychologiczny — decyzje wynikają z emocji, motywacji, osobowości i percepcji.","Socjologiczny — na wybory wpływają grupy społeczne, kultura i trendy.","Behawioralny — decyzje są wynikiem doświadczeń, nawyków i bodźców marketingowych."]},{"heading":"Proces podejmowania decyzji","bullets":["Rozpoznanie potrzeby — uświadomienie sobie braku lub potrzeby (np. potrzeba odpoczynku).","Poszukiwanie informacji — ze źródeł wewnętrznych (doświadczenia) i zewnętrznych (opinie, reklamy, recenzje).","Ocena alternatyw — porównanie opcji wg ceny, jakości, opinii, dostępności.","Decyzja zakupowa — wybór i zakup konkretnego produktu/usługi.","Zachowanie po zakupie — ocena zadowolenia, rekomendacja lub rezygnacja z ponownego zakupu."]},{"heading":"Uwarunkowania","bullets":["Makroekonomiczne — dochód narodowy, inflacja, rynek pracy, trendy społeczne, ograniczenia w podróżowaniu.","Mikroekonomiczne — dochód i fundusz swobodnej decyzji klienta, preferencje, styl życia, stan zdrowia, marketing i reklama, czynniki demograficzne."]}],"questions":[{"type":"abcd","q":"Który model zachowań zakłada, że konsument działa racjonalnie i wybiera produkt o największej wartości przy najniższym koszcie?","options":["Psychologiczny","Socjologiczny","Ekonomiczny","Behawioralny"],"correct":2,"explain":"Model ekonomiczny zakłada racjonalny wybór — najwyższa wartość przy najniższym koszcie."},{"type":"abcd","q":"Na którym etapie procesu decyzyjnego konsument porównuje opcje według ceny, jakości i opinii?","options":["Rozpoznanie potrzeby","Ocena alternatyw","Poszukiwanie informacji","Zachowanie po zakupie"],"correct":1,"explain":"Ocena alternatyw to porównanie różnych opcji wg kryteriów takich jak cena, jakość, opinie i dostępność."},{"type":"tf","q":"Inflacja i dochód narodowy to mikroekonomiczne uwarunkowania zachowań konsumenta.","correct":false,"explain":"Inflacja i dochód narodowy to wielkości zagregowane — uwarunkowania makroekonomiczne, nie mikroekonomiczne."},{"type":"flash","front":"Czym różni się mikroekonomia od makroekonomii?","back":"Mikroekonomia bada pojedyncze jednostki gospodarujące i ich decyzje; makroekonomia — wielkości zagregowane (podaż, popyt, dochód narodowy) w skali całej gospodarki."}]},{"id":"mobbing-osobowosc-autorytarna","track":"wszyscy","category":"zarzadzanie","number":27,"title":"Mobbing i jego związek z osobowością autorytarną","summary":"Mobbing jako systematyczne, długotrwałe nękanie w miejscu pracy, jego typowe akty oraz powiązanie z cechami osobowości autorytarnej.","wiki":[{"body":"Mobbing to systematyczne, długotrwałe nękanie lub zastraszanie danej osoby w miejscu pracy przez przełożonego, współpracowników lub grupę pracowników. Jego celem jest poniżenie, izolowanie, a czasem wypchnięcie ofiary z organizacji. Charakteryzuje się powtarzalnością aktów agresji psychicznej."},{"heading":"Typowe akty mobbingu","bullets":["Upokarzanie lub szykanowanie pracownika.","Publiczne lub prywatne zawstydzanie.","Izolowanie od zespołu i kluczowych informacji.","Podważanie kompetencji i wartości zawodowej.","Zadawanie zbyt trudnych lub niewykonalnych zadań.","Odmowa wsparcia lub zasobów niezbędnych do pracy."]},{"heading":"Związek z osobowością autorytarną","bullets":["Potrzeba kontroli — silna potrzeba panowania nad otoczeniem prowadzi do nadmiernego nadzoru i krytyki.","Lęk i manipulacja — używane jako narzędzia sprawowania władzy.","Brak empatii — mniejsza wrażliwość na potrzeby i uczucia ofiar.","Wyolbrzymione poczucie własnej wartości — przekonanie o prawie do kontroli nad innymi.","Brak akceptacji słabszych — tolerowanie lub ignorowanie mobbingu wobec osób postrzeganych jako słabe."]}],"questions":[{"type":"abcd","q":"Czym jest mobbing?","options":["Jednorazowym konfliktem między dwoma pracownikami","Systematycznym, długotrwałym nękaniem osoby w miejscu pracy","Formą oceny okresowej pracownika","Premią uznaniową za wyniki"],"correct":1,"explain":"Mobbing to systematyczne, długotrwałe nękanie lub zastraszanie w miejscu pracy — kluczowa jest powtarzalność, nie jednorazowość."},{"type":"abcd","q":"Która cecha osobowości autorytarnej szczególnie sprzyja stosowaniu mobbingu?","options":["Wysoka empatia","Skłonność do kompromisu","Silna potrzeba kontroli nad otoczeniem","Otwartość na krytykę"],"correct":2,"explain":"Silna potrzeba kontroli prowadzi do nadmiernego nadzorowania i krytykowania podwładnych, co sprzyja mobbingowi."},{"type":"tf","q":"Izolowanie pracownika od zespołu i kluczowych informacji jest jednym z typowych aktów mobbingu.","correct":true,"explain":"Izolowanie od zespołu i informacji to jeden z powtarzających się aktów agresji psychicznej składających się na mobbing."},{"type":"flash","front":"Jaki jest cel mobbingu wobec ofiary?","back":"Poniżenie, izolowanie, a czasem wypchnięcie ofiary z organizacji — poprzez powtarzające się akty agresji psychicznej."}]},{"id":"uwarunkowania-rozwoju-turystyki","track":"wszyscy","category":"turystyka","number":55,"title":"Uwarunkowania rozwoju turystyki","summary":"Najważniejsze grupy uwarunkowań rozwoju turystyki: ekonomiczne, społeczne, polityczne, kulturowe i przyrodnicze.","wiki":[{"body":"Rozwój turystyki zależy od wielu współgrających ze sobą uwarunkowań. Najczęściej grupuje się je w pięć kategorii: ekonomiczne, społeczne, polityczne, kulturowe i przyrodnicze."},{"heading":"Ekonomiczne","bullets":["Ceny usług turystycznych i kursy walut.","Poziom dochodów — wzrost dochodów zwiększa skłonność do podróżowania.","Rozwój infrastruktury turystycznej."]},{"heading":"Społeczne","bullets":["Ilość czasu wolnego.","Urbanizacja i zmiany demograficzne (starzenie się społeczeństwa).","Moda, trendy oraz poziom wykształcenia."]},{"heading":"Polityczne","bullets":["Stabilność polityczna kraju i bezpieczeństwo turystów.","Polityka państwa wobec turystyki i stosunki międzynarodowe.","Polityka wizowa — zaostrzona ogranicza ruch turystyczny."]},{"heading":"Kulturowe","bullets":["Dziedzictwo kulturowe (zabytki, muzea, tradycje).","Dostępność kultury (festiwale, wydarzenia).","Poziom tolerancji i otwartości oraz bariery językowe."]},{"heading":"Przyrodnicze","bullets":["Walory przyrodnicze — krajobraz, parki narodowe, unikalne ekosystemy.","Klimat danego regionu.","Ochrona środowiska oraz zagrożenia naturalne (trzęsienia ziemi, tsunami)."]}],"questions":[{"type":"abcd","q":"Kursy walut, poziom dochodów i ceny usług to uwarunkowania rozwoju turystyki o charakterze:","options":["Społecznym","Politycznym","Ekonomicznym","Przyrodniczym"],"correct":2,"explain":"Ceny usług, kursy walut i poziom dochodów to typowe uwarunkowania ekonomiczne rozwoju turystyki."},{"type":"abcd","q":"Które z poniższych jest uwarunkowaniem przyrodniczym rozwoju turystyki?","options":["Polityka wizowa","Klimat i walory krajobrazowe","Poziom wykształcenia","Dziedzictwo kulturowe"],"correct":1,"explain":"Klimat, walory krajobrazowe i ekosystemy to uwarunkowania przyrodnicze; polityka wizowa jest polityczna, a dziedzictwo — kulturowe."},{"type":"tf","q":"Stabilność polityczna kraju i polityka wizowa to polityczne uwarunkowania rozwoju turystyki.","correct":true,"explain":"Stabilność polityczna, bezpieczeństwo turystów i polityka wizowa należą do uwarunkowań politycznych."},{"type":"flash","front":"Wymień pięć grup uwarunkowań rozwoju turystyki.","back":"Ekonomiczne, społeczne, polityczne, kulturowe i przyrodnicze."}]}]$awfjson$::jsonb)
  as x(id text, track text, category text, number int, title text, summary text, wiki jsonb, questions jsonb)
on conflict (id) do update set
